('379e7ebc-80bd-455a-8a92-fe2bb716d826', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.59,"extraversion":0.44,"agreeableness":0.72,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.38,"narcissism":0.38,"psychopathy":0.25},"prospect_theory":{"lambda":3.01,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.5,"liquidation_anxiety":0.58,"max_leverage_comfort":0.32,"deleveraging_style":"adaptive"},"summary":"Index-fund holdout, steady in style: defaults to trust and gives the benefit of the doubt too freely; gets bored of the proven method exactly when it starts working. Waits for a permission that never quite arrives. When the downside gets concrete adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.52},{"slug":"sunk-cost","strength":0.55},{"slug":"endowment","strength":0.54},{"slug":"bandwagon","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.66,"conscientiousness":0.59,"extraversion":0.44,"agreeableness":0.72,"neuroticism":0.61}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Index-fund holdout, steady in style: defaults to trust and gives the benefit of the doubt too freely; gets bored of the proven method exactly when it starts working. Waits for a permission that never quite arrives. When the downside gets concrete adopts a conviction mainly because the room already has.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('713255b6-307d-4eb1-8954-0a210c7a8006', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.26,"extraversion":0.66,"agreeableness":0.25,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.66,"narcissism":0.64,"psychopathy":0.59},"prospect_theory":{"lambda":1.24,"alpha":0.79,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.53,"max_leverage_comfort":0.5,"deleveraging_style":"adaptive"},"summary":"A steady onchain copy-trader who needs repeated reassurance that a decision was the right one. Prefers a fast wrong answer to a slow right one. Reframes every problem as an excuse to learn a new system. When the number turns red sees malicious intent and exploit risk in every standard smart contract update; when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.73},{"slug":"airdrop-entitlement","strength":0.7},{"slug":"recency","strength":0.65},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","decision-making"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.72,"conscientiousness":0.26,"extraversion":0.66,"agreeableness":0.25,"neuroticism":0.79}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','decision-making']::text[], 'A steady onchain copy-trader who needs repeated reassurance that a decision was the right one. Prefers a fast wrong answer to a slow right one. Reframes every problem as an excuse to learn a new system. When the number turns red sees malicious intent and exploit risk in every standard smart contract update; when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d5072c15-c766-4d4c-ace7-d7b851acdcc2', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.44,"extraversion":0.59,"agreeableness":0.58,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.43,"narcissism":0.38,"psychopathy":0.33},"prospect_theory":{"lambda":1.76,"alpha":0.77,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.58,"max_leverage_comfort":0.33,"deleveraging_style":"adaptive"},"summary":"Futures spreader whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Reads outside the field for ideas the field itself would reject. When the walls close in, feels a loss twice as sharply as an equivalent gain and plans accordingly; checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.6},{"slug":"loss-aversion","strength":0.63},{"slug":"recency","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","cognition"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.44,"extraversion":0.59,"agreeableness":0.58,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','cognition']::text[], 'Futures spreader whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Reads outside the field for ideas the field itself would reject. When the walls close in, feels a loss twice as sharply as an equivalent gain and plans accordingly; checks the P&L blotter forty times before lunch.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7d3d06d3-d2f5-4f9a-82a3-cdac9e9bf4ef', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.41,"extraversion":0.6,"agreeableness":0.66,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.36,"narcissism":0.35,"psychopathy":0.32},"prospect_theory":{"lambda":3.37,"alpha":0.82,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.4,"liquidation_anxiety":0.8,"max_leverage_comfort":0.17,"deleveraging_style":"panic"},"summary":"Delays checking the number it most needs to check. A steady commodities speculator: carries yesterday''s stress into today''s unrelated decision, measures decisions by who they might upset. Finds one more piece of information to gather before acting, and in the routine of it names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.67},{"slug":"recency","strength":0.59},{"slug":"loss-aversion","strength":0.62},{"slug":"fomo","strength":0.59}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.61,"conscientiousness":0.41,"extraversion":0.6,"agreeableness":0.66,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Delays checking the number it most needs to check. A steady commodities speculator: carries yesterday''s stress into today''s unrelated decision, measures decisions by who they might upset. Finds one more piece of information to gather before acting, and in the routine of it names every strategy after the trade that almost worked.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('cc7b2192-0d63-4f86-875d-4c5b51bc1918', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.41,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.52,"narcissism":0.39,"psychopathy":0.44},"prospect_theory":{"lambda":3.43,"alpha":0.76,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.77,"max_leverage_comfort":0.15,"deleveraging_style":"panic"},"summary":"A steady pairs trader who reads a single setback as evidence of collapse. Buries hard calls under a pile of preparatory busywork. Once the exit narrows to one door exits winning positions at the first minor delay or quiet period from devs; when the pressure is off, holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.69},{"slug":"ostrich-effect","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.7},{"slug":"airdrop-entitlement","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.41,"neuroticism":0.81}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'A steady pairs trader who reads a single setback as evidence of collapse. Buries hard calls under a pile of preparatory busywork. Once the exit narrows to one door exits winning positions at the first minor delay or quiet period from devs; when the pressure is off, holds a bag from 2021 out of pure spite.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5eb1cf07-98a3-40d3-b4f7-ee3a8c200f1a', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.27,"extraversion":0.88,"agreeableness":0.34,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.55,"narcissism":0.77,"psychopathy":0.54},"prospect_theory":{"lambda":0.88,"alpha":0.85,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.21,"liquidation_anxiety":0.5,"max_leverage_comfort":0.56,"deleveraging_style":"adaptive"},"summary":"A pronounced crypto day-trader who recharges by being around people, not away from them. Trusts momentum over preparation. Says the blunt thing and enjoys the flinch. When the walls close in jumps into whatever everyone else already seems to be winning at; day to day, confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.61},{"slug":"herd-behavior","strength":0.73},{"slug":"dunning-kruger","strength":0.75},{"slug":"fomo","strength":0.82}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.69,"conscientiousness":0.27,"extraversion":0.88,"agreeableness":0.34,"neuroticism":0.73}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'A pronounced crypto day-trader who recharges by being around people, not away from them. Trusts momentum over preparation. Says the blunt thing and enjoys the flinch. When the walls close in jumps into whatever everyone else already seems to be winning at; day to day, confuses a bull market for a trading edge.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('661a2e00-62e0-4f24-a134-f7d82334d5a0', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.32,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.58,"narcissism":0.72,"psychopathy":0.56},"prospect_theory":{"lambda":1.05,"alpha":0.77,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.23,"liquidation_anxiety":0.56,"max_leverage_comfort":0.57,"deleveraging_style":"adaptive"},"summary":"Delta-neutral market maker, steady in style: dominates the room then wonders why others stayed quiet; treats established procedure as a first draft to be rewritten. Commits on impulse and lives loudly with the consequences. Once things get tense jumps into whatever everyone else already seems to be winning at.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"fomo","strength":0.73},{"slug":"recency","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.8,"conscientiousness":0.29,"extraversion":0.81,"agreeableness":0.32,"neuroticism":0.79}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Delta-neutral market maker, steady in style: dominates the room then wonders why others stayed quiet; treats established procedure as a first draft to be rewritten. Commits on impulse and lives loudly with the consequences. Once things get tense jumps into whatever everyone else already seems to be winning at.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('75c07d73-e26a-4422-b8bf-37c54177ef59', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.33,"extraversion":0.45,"agreeableness":0.49,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.42,"narcissism":0.22,"psychopathy":0.36},"prospect_theory":{"lambda":3.65,"alpha":0.79,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.91,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Buries hard calls under a pile of preparatory busywork. This liquidation-bot operator notices the one thing that could go wrong before the nine that could go right and improvises past every deadline and calls it flexibility. When someone is watching the outcome looks away from bad news in the hope it resolves unwitnessed — day to day, exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ISTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.63},{"slug":"diamond-hands-identity","strength":0.67},{"slug":"ostrich-effect","strength":0.79}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","cognition"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.49,"conscientiousness":0.33,"extraversion":0.45,"agreeableness":0.49,"neuroticism":0.89}'::jsonb, 'ISTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','cognition']::text[], 'Buries hard calls under a pile of preparatory busywork. This liquidation-bot operator notices the one thing that could go wrong before the nine that could go right and improvises past every deadline and calls it flexibility. When someone is watching the outcome looks away from bad news in the hope it resolves unwitnessed — day to day, exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('66cb53a4-ec61-410f-9eae-2d29f634f416', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.51,"extraversion":0.6,"agreeableness":0.5,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.44,"narcissism":0.43,"psychopathy":0.26},"prospect_theory":{"lambda":1.44,"alpha":0.84,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.48,"max_leverage_comfort":0.44,"deleveraging_style":"adaptive"},"summary":"A measured penny-stock gambler who carries yesterday''s stress into today''s unrelated decision. Decides on a gut read in seconds and reverse-engineers the reasons later. The instant the deadline moves up cannot watch a rally from the sidelines for long; when no one is watching, backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.6},{"slug":"recency","strength":0.49},{"slug":"availability","strength":0.47}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","anxious","ipip-neo"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.56,"conscientiousness":0.51,"extraversion":0.6,"agreeableness":0.5,"neuroticism":0.62}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','anxious','ipip-neo']::text[], 'A measured penny-stock gambler who carries yesterday''s stress into today''s unrelated decision. Decides on a gut read in seconds and reverse-engineers the reasons later. The instant the deadline moves up cannot watch a rally from the sidelines for long; when no one is watching, backtests for months but front-runs the model on impulse.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('0ffc9db0-a86b-44ce-8bc0-3327c8889cba', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.32,"extraversion":0.68,"agreeableness":0.7,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.41,"narcissism":0.55,"psychopathy":0.38},"prospect_theory":{"lambda":3,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.7,"max_leverage_comfort":0.47,"deleveraging_style":"adaptive"},"summary":"Discretionary swing trader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right. Rehearses catastrophes in vivid detail before they happen. The instant the deadline moves up, discounts the older pattern in favor of whatever just happened; refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"dunning-kruger","strength":0.67},{"slug":"recency","strength":0.76},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","temperament"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.86,"conscientiousness":0.32,"extraversion":0.68,"agreeableness":0.7,"neuroticism":0.71}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','temperament']::text[], 'Discretionary swing trader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right. Rehearses catastrophes in vivid detail before they happen. The instant the deadline moves up, discounts the older pattern in favor of whatever just happened; refreshes the order book compulsively during lunch.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7f0f5c95-9576-4858-9a38-965c6cdcb29e', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.32,"extraversion":0.66,"agreeableness":0.66,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.37,"narcissism":0.53,"psychopathy":0.38},"prospect_theory":{"lambda":2.95,"alpha":0.78,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.58,"max_leverage_comfort":0.36,"deleveraging_style":"adaptive"},"summary":"When the downside gets concrete, mistakes a little fluency for real mastery. Otherwise, a steady DeFi yield farmer who reframes every problem as an excuse to learn a new system and fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own, and once the urgency drains out sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"recency","strength":0.62},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","decision-making"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.75,"conscientiousness":0.32,"extraversion":0.66,"agreeableness":0.66,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','decision-making']::text[], 'When the downside gets concrete, mistakes a little fluency for real mastery. Otherwise, a steady DeFi yield farmer who reframes every problem as an excuse to learn a new system and fills silence reflexively, even when nobody asked it to. Trusts the group''s confidence more than its own, and once the urgency drains out sizes every position at exactly 2% risk.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('665f807f-ba19-4b83-b58f-49fc85e11f03', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.56,"extraversion":0.5,"agreeableness":0.7,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.38,"narcissism":0.39,"psychopathy":0.29},"prospect_theory":{"lambda":3,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.5,"liquidation_anxiety":0.55,"max_leverage_comfort":0.26,"deleveraging_style":"adaptive"},"summary":"Second-guesses its own read the moment someone senior disagrees. A steady futures spreader: reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and as a rule trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.58},{"slug":"endowment","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.52,"conscientiousness":0.56,"extraversion":0.5,"agreeableness":0.7,"neuroticism":0.58}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Second-guesses its own read the moment someone senior disagrees. A steady futures spreader: reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and as a rule trusts the chart more than the fundamentals and won''t say why.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a220981b-8d27-45e2-9f68-35d21cb4874d', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.32,"extraversion":0.49,"agreeableness":0.61,"neuroticism":0.92},"dark_triad":{"machiavellianism":0.38,"narcissism":0.23,"psychopathy":0.33},"prospect_theory":{"lambda":3.68,"alpha":0.79,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.91,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"The instant the deadline moves up, refuses to take profits because holding has become core to their community identity. Otherwise, a pronounced penny-stock gambler who needs repeated reassurance that a decision was the right one and is reliably surprised by deadlines that were never hidden. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.76},{"slug":"disposition-effect","strength":0.72},{"slug":"loss-aversion","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.48,"conscientiousness":0.32,"extraversion":0.49,"agreeableness":0.61,"neuroticism":0.92}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'The instant the deadline moves up, refuses to take profits because holding has become core to their community identity. Otherwise, a pronounced penny-stock gambler who needs repeated reassurance that a decision was the right one and is reliably surprised by deadlines that were never hidden. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('c2cd686e-d610-45ff-8b26-2f52d9255b5c', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.2,"extraversion":0.7,"agreeableness":0.24,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.64,"narcissism":0.64,"psychopathy":0.64},"prospect_theory":{"lambda":1.03,"alpha":0.79,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.53,"max_leverage_comfort":0.4,"deleveraging_style":"adaptive"},"summary":"Treats every unannounced multisig transaction as an imminent exit scam. A pronounced dividend-yield chaser: reads a single setback as evidence of collapse, treats a quiet room as a problem to be solved. Trusts momentum over preparation, and once the urgency drains out exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.71},{"slug":"ostrich-effect","strength":0.7},{"slug":"airdrop-entitlement","strength":0.69},{"slug":"rug-trauma-overcorrection","strength":0.8}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","ipip-neo"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.62,"conscientiousness":0.2,"extraversion":0.7,"agreeableness":0.24,"neuroticism":0.84}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','ipip-neo']::text[], 'Treats every unannounced multisig transaction as an imminent exit scam. A pronounced dividend-yield chaser: reads a single setback as evidence of collapse, treats a quiet room as a problem to be solved. Trusts momentum over preparation, and once the urgency drains out exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6c9482d8-ab11-40c0-ab34-73f188d5dafc', 1, '{"big_five":{"openness":0.43,"conscientiousness":0.76,"extraversion":0.51,"agreeableness":0.56,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.48,"narcissism":0.38,"psychopathy":0.38},"prospect_theory":{"lambda":2.49,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.69,"liquidation_anxiety":0.33,"max_leverage_comfort":0.33,"deleveraging_style":"disciplined"},"summary":"Retail momentum chaser, steady in style: treats a missed deadline as a personal failure regardless of cause. Keeps deliberating past the point where more information would change anything. In a pinch refuses to exit positions until price returns to the previous cycle peak.","decision_style":"deliberative","mbti_label":"ESFJ","suggested_biases":[{"slug":"anchoring","strength":0.56},{"slug":"optimism","strength":0.48},{"slug":"hindsight","strength":0.59},{"slug":"ath-anchoring","strength":0.62}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","cognition"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.43,"conscientiousness":0.76,"extraversion":0.51,"agreeableness":0.56,"neuroticism":0.39}'::jsonb, 'ESFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','cognition']::text[], 'Retail momentum chaser, steady in style: treats a missed deadline as a personal failure regardless of cause. Keeps deliberating past the point where more information would change anything. In a pinch refuses to exit positions until price returns to the previous cycle peak.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('8da56ca4-c86e-43bb-abc6-a9b655d7bcdd', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.84,"extraversion":0.54,"agreeableness":0.58,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.52,"narcissism":0.41,"psychopathy":0.39},"prospect_theory":{"lambda":2.47,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.33,"max_leverage_comfort":0.41,"deleveraging_style":"disciplined"},"summary":"Volatility arbitrageur, pronounced in style: builds in buffer time and then fills the buffer with more work; sleeps fine the night before the big call. Treats a rushed decision as a defect regardless of outcome. When cornered treats past peak valuation as guaranteed future recovery.","decision_style":"deliberative","mbti_label":"ENFJ","suggested_biases":[{"slug":"overconfidence","strength":0.58},{"slug":"anchoring","strength":0.57},{"slug":"optimism","strength":0.54},{"slug":"ath-anchoring","strength":0.6}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","decision-making"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.52,"conscientiousness":0.84,"extraversion":0.54,"agreeableness":0.58,"neuroticism":0.35}'::jsonb, 'ENFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','decision-making']::text[], 'Volatility arbitrageur, pronounced in style: builds in buffer time and then fills the buffer with more work; sleeps fine the night before the big call. Treats a rushed decision as a defect regardless of outcome. When cornered treats past peak valuation as guaranteed future recovery.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('31ede06a-05dd-4dc4-a0a1-73d2d5b80647', 1, '{"big_five":{"openness":0.38,"conscientiousness":0.78,"extraversion":0.48,"agreeableness":0.62,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.5,"narcissism":0.42,"psychopathy":0.29},"prospect_theory":{"lambda":2.57,"alpha":0.91,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.72,"liquidation_anxiety":0.34,"max_leverage_comfort":0.38,"deleveraging_style":"disciplined"},"summary":"When there is no clean exit, measures every later offer against the opening one, not against fair value. Otherwise, a steady airdrop farmer who builds in buffer time and then fills the buffer with more work and measures decisions by who they might upset. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"status-quo","strength":0.58},{"slug":"anchoring","strength":0.62},{"slug":"authority-bias","strength":0.58},{"slug":"hindsight","strength":0.54}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","behavioral"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.38,"conscientiousness":0.78,"extraversion":0.48,"agreeableness":0.62,"neuroticism":0.43}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','behavioral']::text[], 'When there is no clean exit, measures every later offer against the opening one, not against fair value. Otherwise, a steady airdrop farmer who builds in buffer time and then fills the buffer with more work and measures decisions by who they might upset. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5a997494-cd21-4a05-b1d8-538d95a5cd24', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.31,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.39,"narcissism":0.47,"psychopathy":0.32},"prospect_theory":{"lambda":2.88,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.58,"max_leverage_comfort":0.49,"deleveraging_style":"adaptive"},"summary":"A steady commodities speculator who gets bored of the proven method exactly when it starts working. Seeks a second, third, and fourth opinion before committing to anything. Does the interesting 80% and abandons the tedious 20%. The instant it becomes irreversible discounts the older pattern in favor of whatever just happened; on an ordinary week, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"dunning-kruger","strength":0.56},{"slug":"sunk-cost","strength":0.58},{"slug":"ostrich-effect","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","decision-making"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.79,"conscientiousness":0.31,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','decision-making']::text[], 'A steady commodities speculator who gets bored of the proven method exactly when it starts working. Seeks a second, third, and fourth opinion before committing to anything. Does the interesting 80% and abandons the tedious 20%. The instant it becomes irreversible discounts the older pattern in favor of whatever just happened; on an ordinary week, keeps three monitors for a portfolio that fits on one screen.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d6631726-dcec-4b8c-9629-42eef42181d9', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.5,"extraversion":0.72,"agreeableness":0.58,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.43,"narcissism":0.44,"psychopathy":0.25},"prospect_theory":{"lambda":3.57,"alpha":0.8,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.82,"max_leverage_comfort":0.09,"deleveraging_style":"panic"},"summary":"Quant researcher whose defining move is that they hedges every commitment against an imagined worst case. Lets the deadline make the decision by default. Recharges by being around people, not away from them. Once the exit narrows to one door, cannot watch a rally from the sidelines for long; checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"availability","strength":0.66},{"slug":"diamond-hands-identity","strength":0.63},{"slug":"loss-aversion","strength":0.58}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.5,"extraversion":0.72,"agreeableness":0.58,"neuroticism":0.8}'::jsonb, 'ENFJ', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Quant researcher whose defining move is that they hedges every commitment against an imagined worst case. Lets the deadline make the decision by default. Recharges by being around people, not away from them. Once the exit narrows to one door, cannot watch a rally from the sidelines for long; checks the P&L blotter forty times before lunch.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('1a1a1abc-8ba2-473f-b2fd-44b8a9be844b', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.36,"extraversion":0.75,"agreeableness":0.7,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":3.02,"alpha":0.92,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.29,"liquidation_anxiety":0.47,"max_leverage_comfort":0.59,"deleveraging_style":"adaptive"},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady algorithmic market-maker: collects half-finished manifestos and unconventional methods, is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own, and left to their own devices trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"dunning-kruger","strength":0.59},{"slug":"fomo","strength":0.62},{"slug":"bandwagon","strength":0.63}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","ipip-neo"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.82,"conscientiousness":0.36,"extraversion":0.75,"agreeableness":0.7,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','ipip-neo']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady algorithmic market-maker: collects half-finished manifestos and unconventional methods, is reliably surprised by deadlines that were never hidden. Trusts the group''s confidence more than its own, and left to their own devices trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('2bfbc569-7895-4f46-8e82-d616e3562294', 1, '{"big_five":{"openness":0.4,"conscientiousness":0.32,"extraversion":0.48,"agreeableness":0.61,"neuroticism":0.96},"dark_triad":{"machiavellianism":0.41,"narcissism":0.2,"psychopathy":0.36},"prospect_theory":{"lambda":3.66,"alpha":0.69,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.45,"liquidation_anxiety":0.95,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Refuses to take profits because holding has become core to their community identity. A pronounced options seller: spirals on ambiguity and mistakes the spiral for diligence, starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and across an ordinary week confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.82},{"slug":"disposition-effect","strength":0.73},{"slug":"ostrich-effect","strength":0.78}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.4,"conscientiousness":0.32,"extraversion":0.48,"agreeableness":0.61,"neuroticism":0.96}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'Refuses to take profits because holding has become core to their community identity. A pronounced options seller: spirals on ambiguity and mistakes the spiral for diligence, starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and across an ordinary week confuses a bull market for a trading edge.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('379537aa-2819-4e5d-aa03-1bf28b9c00bd', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.45,"extraversion":0.58,"agreeableness":0.65,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.4,"narcissism":0.5,"psychopathy":0.31},"prospect_theory":{"lambda":1.52,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.38,"max_leverage_comfort":0.56,"deleveraging_style":"adaptive"},"summary":"Prop-desk scalper whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Lets pattern-matching from past cases stand in for fresh analysis. Measures decisions by who they might upset. The instant the deadline moves up, discounts the older pattern in favor of whatever just happened; sets stop-losses then cancels them at the open.","decision_style":"intuitive","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"herd-behavior","strength":0.59}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","open-minded","cognition"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.72,"conscientiousness":0.45,"extraversion":0.58,"agreeableness":0.65,"neuroticism":0.54}'::jsonb, 'ENFP', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','open-minded','cognition']::text[], 'Prop-desk scalper whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Lets pattern-matching from past cases stand in for fresh analysis. Measures decisions by who they might upset. The instant the deadline moves up, discounts the older pattern in favor of whatever just happened; sets stop-losses then cancels them at the open.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('71e495ba-3880-448e-9e0f-2920ae09ae52', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.33,"extraversion":0.79,"agreeableness":0.71,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":1.57,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.38,"max_leverage_comfort":0.62,"deleveraging_style":"adaptive"},"summary":"A steady quant researcher who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. Under pressure finds it hard to hold a contrarian position once the room disagrees; as a rule, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.67}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.78,"conscientiousness":0.33,"extraversion":0.79,"agreeableness":0.71,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition']::text[], 'A steady quant researcher who treats a quiet room as a problem to be solved. Circles back to ask what someone else would do even after deciding. Would rather invent a worse tool than use someone else''s good one. Under pressure finds it hard to hold a contrarian position once the room disagrees; as a rule, screenshots the winners and never the losers.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('1a5f8615-9ad0-4add-8002-47b90e0f2ae8', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.38,"extraversion":0.38,"agreeableness":0.63,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.35,"narcissism":0.28,"psychopathy":0.37},"prospect_theory":{"lambda":3.97,"alpha":0.76,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.95,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Macro allocator, pronounced in style: carries yesterday''s stress into today''s unrelated decision; leaves loose ends and trusts future-self to handle them. Prefers a slow loss to a fast, ownable mistake. As soon as real money or reputation is on the line delays checking the number it most needs to check.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.71},{"slug":"loss-aversion","strength":0.65},{"slug":"diamond-hands-identity","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","behavioral"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.49,"conscientiousness":0.38,"extraversion":0.38,"agreeableness":0.63,"neuroticism":0.89}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','behavioral']::text[], 'Macro allocator, pronounced in style: carries yesterday''s stress into today''s unrelated decision; leaves loose ends and trusts future-self to handle them. Prefers a slow loss to a fast, ownable mistake. As soon as real money or reputation is on the line delays checking the number it most needs to check.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7d768997-7a5c-446f-b8c9-a0df19f494f1', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.34,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.56,"narcissism":0.82,"psychopathy":0.51},"prospect_theory":{"lambda":1.03,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.32,"max_leverage_comfort":0.71,"deleveraging_style":"adaptive"},"summary":"Once things get tense, cannot see the gap in its own knowledge from inside the gap. Otherwise, a pronounced quant researcher who fills silence reflexively, even when nobody asked it to and negotiates every relationship a little, even the close ones. Commits before the doubt has time to organize itself, and when the pressure is off apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"recency","strength":0.69},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.85,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.34,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Once things get tense, cannot see the gap in its own knowledge from inside the gap. Otherwise, a pronounced quant researcher who fills silence reflexively, even when nobody asked it to and negotiates every relationship a little, even the close ones. Commits before the doubt has time to organize itself, and when the pressure is off apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e76baa13-3a4d-4c8a-8b77-bd3be7e15a46', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.4,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.38,"narcissism":0.48,"psychopathy":0.35},"prospect_theory":{"lambda":3.48,"alpha":0.81,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.71,"max_leverage_comfort":0.17,"deleveraging_style":"panic"},"summary":"Retail momentum chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the walls close in, looks away from bad news in the hope it resolves unwitnessed; rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.6},{"slug":"fomo","strength":0.59},{"slug":"dunning-kruger","strength":0.54},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.4,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.7}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Retail momentum chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the walls close in, looks away from bad news in the hope it resolves unwitnessed; rotates the whole book into whatever is pumping this hour.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5f221114-6f70-4d0a-8836-6cb23b584b23', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.42,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.34},"prospect_theory":{"lambda":2.98,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.46,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"In a pinch, extrapolates the last data point into a permanent trend. Otherwise, a pronounced algorithmic market-maker who gets bored of the proven method exactly when it starts working and takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"recency","strength":0.65},{"slug":"dunning-kruger","strength":0.56},{"slug":"bandwagon","strength":0.64}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","decision-making"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.87,"conscientiousness":0.42,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','decision-making']::text[], 'In a pinch, extrapolates the last data point into a permanent trend. Otherwise, a pronounced algorithmic market-maker who gets bored of the proven method exactly when it starts working and takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority, and in the unglamorous middle of things sizes every position at exactly 2% risk.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c