('6c73c3d9-d30f-492c-a94a-8d42ad21b650', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.55,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":3,"alpha":0.81,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.58,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"MEV searcher whose defining move is that they would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. Draws energy from the crowd and wilts when working alone. Once things get tense, mistakes a little fluency for real mastery; exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.61},{"slug":"dunning-kruger","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","risk"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.9,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.55,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','risk']::text[], 'MEV searcher whose defining move is that they would rather invent a worse tool than use someone else''s good one. Trusts the group''s confidence more than its own. Draws energy from the crowd and wilts when working alone. Once things get tense, mistakes a little fluency for real mastery; exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
