('efa6ca8f-3ebc-4ff4-8595-98e5cb5c6271', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.31,"extraversion":0.64,"agreeableness":0.4,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.5,"narcissism":0.46,"psychopathy":0.41},"prospect_theory":{"lambda":1.22,"alpha":0.77,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.53,"max_leverage_comfort":0.42,"deleveraging_style":"adaptive"},"summary":"Treats hesitation as the bigger risk. This discretionary swing trader rehearses catastrophes in vivid detail before they happen and does the interesting 80% and abandons the tedious 20%. When someone is watching the outcome exits winning positions at the first minor delay or quiet period from devs — on an ordinary week, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.67},{"slug":"rug-trauma-overcorrection","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","risk"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.31,"extraversion":0.64,"agreeableness":0.4,"neuroticism":0.77}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','risk']::text[], 'Treats hesitation as the bigger risk. This discretionary swing trader rehearses catastrophes in vivid detail before they happen and does the interesting 80% and abandons the tedious 20%. When someone is watching the outcome exits winning positions at the first minor delay or quiet period from devs — on an ordinary week, backtests for months but front-runs the model on impulse.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
