('a4227e8f-2593-4067-a0f0-39c8e7c96650', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.34,"extraversion":0.6,"agreeableness":0.57,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.37,"narcissism":0.32,"psychopathy":0.38},"prospect_theory":{"lambda":3.76,"alpha":0.74,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.77,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Would rather not know yet, even when knowing sooner would help. A steady volatility arbitrageur: needs repeated reassurance that a decision was the right one, leaves loose ends and trusts future-self to handle them. Finds one more piece of information to gather before acting, and as a rule sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.68},{"slug":"ostrich-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.5,"conscientiousness":0.34,"extraversion":0.6,"agreeableness":0.57,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Would rather not know yet, even when knowing sooner would help. A steady volatility arbitrageur: needs repeated reassurance that a decision was the right one, leaves loose ends and trusts future-self to handle them. Finds one more piece of information to gather before acting, and as a rule sets stop-losses then cancels them at the open.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
