('a1088430-5312-4700-b0b8-275326169300', 1, '{"big_five":{"openness":0.38,"conscientiousness":0.32,"extraversion":0.51,"agreeableness":0.63,"neuroticism":0.83},"dark_triad":{"machiavellianism":0.36,"narcissism":0.25,"psychopathy":0.35},"prospect_theory":{"lambda":3.69,"alpha":0.78,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.8,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"The moment it stops being hypothetical, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction. Otherwise, a steady zero-DTE options gambler who spirals on ambiguity and mistakes the spiral for diligence and leaves loose ends and trusts future-self to handle them. Keeps every door open long after most of them should be closed, and in the small things sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.71},{"slug":"loss-aversion","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.38,"conscientiousness":0.32,"extraversion":0.51,"agreeableness":0.63,"neuroticism":0.83}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'The moment it stops being hypothetical, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction. Otherwise, a steady zero-DTE options gambler who spirals on ambiguity and mistakes the spiral for diligence and leaves loose ends and trusts future-self to handle them. Keeps every door open long after most of them should be closed, and in the small things sizes every position at exactly 2% risk.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
