('0616a8b7-d7ad-40ff-8c75-0b546ffcd78f', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.33,"extraversion":0.43,"agreeableness":0.47,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.45,"narcissism":0.25,"psychopathy":0.37},"prospect_theory":{"lambda":3.78,"alpha":0.72,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.45,"liquidation_anxiety":0.91,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"When the safe option quietly expires, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a pronounced meme-coin rotator who carries yesterday''s stress into today''s unrelated decision and starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and once the urgency drains out backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"INTP","suggested_biases":[{"slug":"loss-aversion","strength":0.7},{"slug":"gas-sunk-cost","strength":0.65},{"slug":"disposition-effect","strength":0.63},{"slug":"ostrich-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","cognition"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.55,"conscientiousness":0.33,"extraversion":0.43,"agreeableness":0.47,"neuroticism":0.86}'::jsonb, 'INTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','cognition']::text[], 'When the safe option quietly expires, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a pronounced meme-coin rotator who carries yesterday''s stress into today''s unrelated decision and starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and once the urgency drains out backtests for months but front-runs the model on impulse.', 0.98, 'approved', '092841db-d88c-438b-ab16-50