('426d95ad-ce25-4406-a349-a8e20382d229', 1, '{"big_five":{"openness":0.37,"conscientiousness":0.73,"extraversion":0.46,"agreeableness":0.66,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.46,"narcissism":0.35,"psychopathy":0.24},"prospect_theory":{"lambda":3.09,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.61,"liquidation_anxiety":0.46,"max_leverage_comfort":0.3,"deleveraging_style":"disciplined"},"summary":"Once the exit narrows to one door, lets the first number on the table quietly set the whole range. Otherwise, a steady value investor who maintains flawless records nobody asked for and takes on other people''s problems as if they were their own. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and when the pressure is off calls a 90% drawdown a long-term hold.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"anchoring","strength":0.64},{"slug":"hindsight","strength":0.54}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","cognition"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.37,"conscientiousness":0.73,"extraversion":0.46,"agreeableness":0.66,"neuroticism":0.52}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','cognition']::text[], 'Once the exit narrows to one door, lets the first number on the table quietly set the whole range. Otherwise, a steady value investor who maintains flawless records nobody asked for and takes on other people''s problems as if they were their own. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and when the pressure is off calls a 90% drawdown a long-term hold.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('33cab8ce-d8df-4cf1-a3dc-0e0714f317d3', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.31,"extraversion":0.76,"agreeableness":0.24,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.66,"narcissism":0.71,"psychopathy":0.61},"prospect_theory":{"lambda":1.1,"alpha":0.78,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.51,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Expects retroactive token rewards for routine protocol usage and reacts with outrage when excluded. A steady delta-neutral market maker: narrates the plan to whoever is nearby before committing to it, reads a single setback as evidence of collapse. Treats hesitation as the bigger risk, and when the pressure is off talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"rug-trauma-overcorrection","strength":0.73},{"slug":"airdrop-entitlement","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","outgoing","temperament"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.71,"conscientiousness":0.31,"extraversion":0.76,"agreeableness":0.24,"neuroticism":0.76}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','outgoing','temperament']::text[], 'Expects retroactive token rewards for routine protocol usage and reacts with outrage when excluded. A steady delta-neutral market maker: narrates the plan to whoever is nearby before committing to it, reads a single setback as evidence of collapse. Treats hesitation as the bigger risk, and when the pressure is off talks in win rate and never mentions size.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
