('0e8bd3d2-519d-40da-94b8-abc68764644f', 1, '{"big_five":{"openness":0.44,"conscientiousness":0.32,"extraversion":0.47,"agreeableness":0.66,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.41,"narcissism":0.25,"psychopathy":0.35},"prospect_theory":{"lambda":3.83,"alpha":0.77,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.43,"liquidation_anxiety":0.89,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"A pronounced meme-coin rotator who reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting. Apologizes first in disputes regardless of fault. The moment it stops being hypothetical delays checking the number it most needs to check; in the unglamorous middle of things, rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.73},{"slug":"gas-sunk-cost","strength":0.67},{"slug":"disposition-effect","strength":0.64},{"slug":"diamond-hands-identity","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","cognition"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.44,"conscientiousness":0.32,"extraversion":0.47,"agreeableness":0.66,"neuroticism":0.84}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','cognition']::text[], 'A pronounced meme-coin rotator who reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting. Apologizes first in disputes regardless of fault. The moment it stops being hypothetical delays checking the number it most needs to check; in the unglamorous middle of things, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('22094b21-c204-4aa0-a210-86cc7c618f86', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.54,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.4,"narcissism":0.61,"psychopathy":0.27},"prospect_theory":{"lambda":0.98,"alpha":0.85,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.44,"max_leverage_comfort":0.66,"deleveraging_style":"adaptive"},"summary":"A steady quant researcher who draws energy from the crowd and wilts when working alone. Prefers a fast wrong answer to a slow right one. Collects half-finished manifestos and unconventional methods. When the safe option quietly expires cannot watch a rally from the sidelines for long; when the pressure is off, exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.56},{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.6},{"slug":"bandwagon","strength":0.61}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.79,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.54,"neuroticism":0.66}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'A steady quant researcher who draws energy from the crowd and wilts when working alone. Prefers a fast wrong answer to a slow right one. Collects half-finished manifestos and unconventional methods. When the safe option quietly expires cannot watch a rally from the sidelines for long; when the pressure is off, exits winners at the first green candle.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b2324b9c-6d04-49e8-9a40-9b695a616f91', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.64,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.39,"narcissism":0.63,"psychopathy":0.32},"prospect_theory":{"lambda":1.25,"alpha":0.8,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.54,"max_leverage_comfort":0.53,"deleveraging_style":"adaptive"},"summary":"Bonding-curve sniper whose defining move is that they thinks out loud and recruits an audience for every decision. Decides in the time it takes to say the decision out loud. Measures decisions by who they might upset. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"fomo","strength":0.7},{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.64,"neuroticism":0.73}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Bonding-curve sniper whose defining move is that they thinks out loud and recruits an audience for every decision. Decides in the time it takes to say the decision out loud. Measures decisions by who they might upset. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; refreshes the order book compulsively during lunch.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('133441a6-da6e-4725-b60e-523bb461ef2f', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.25,"extraversion":0.4,"agreeableness":0.65,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.38,"narcissism":0.21,"psychopathy":0.39},"prospect_theory":{"lambda":3.64,"alpha":0.73,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.83,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Zero-DTE options gambler, pronounced in style: hedges every commitment against an imagined worst case; reads other people''s discomfort before they voice it. Keeps every door open long after most of them should be closed. Under pressure wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.68},{"slug":"loss-aversion","strength":0.66},{"slug":"diamond-hands-identity","strength":0.73},{"slug":"ostrich-effect","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.42,"conscientiousness":0.25,"extraversion":0.4,"agreeableness":0.65,"neuroticism":0.86}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'Zero-DTE options gambler, pronounced in style: hedges every commitment against an imagined worst case; reads other people''s discomfort before they voice it. Keeps every door open long after most of them should be closed. Under pressure wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('027ff59c-ba13-4590-b771-1fcbd2719692', 1, '{"big_five":{"openness":0.34,"conscientiousness":0.7,"extraversion":0.28,"agreeableness":0.67,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.49,"narcissism":0.38,"psychopathy":0.38},"prospect_theory":{"lambda":2.93,"alpha":0.95,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.56,"liquidation_anxiety":0.45,"max_leverage_comfort":0.29,"deleveraging_style":"disciplined"},"summary":"The moment risk appears, prices every token against its all-time high, viewing current levels as an automatic discount. Otherwise, a steady index-fund holdout who guards their energy and rations social exposure and treats setbacks as data rather than verdicts. Treats a rushed decision as a defect regardless of outcome, and in the unglamorous middle of things backtests for months but front-runs the model on impulse.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.61},{"slug":"authority-bias","strength":0.6},{"slug":"anchoring","strength":0.54}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","reserved","cognition"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.34,"conscientiousness":0.7,"extraversion":0.28,"agreeableness":0.67,"neuroticism":0.38}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','reserved','cognition']::text[], 'The moment risk appears, prices every token against its all-time high, viewing current levels as an automatic discount. Otherwise, a steady index-fund holdout who guards their energy and rations social exposure and treats setbacks as data rather than verdicts. Treats a rushed decision as a defect regardless of outcome, and in the unglamorous middle of things backtests for months but front-runs the model on impulse.', 0.92, 'approved', '092841db-d88c-438