('da142640-133d-46a7-a1d9-f408e78c99c1', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.35,"extraversion":0.63,"agreeableness":0.56,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.4,"narcissism":0.43,"psychopathy":0.36},"prospect_theory":{"lambda":3.64,"alpha":0.79,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.78,"max_leverage_comfort":0.13,"deleveraging_style":"panic"},"summary":"When the downside gets concrete, cannot watch a rally from the sidelines for long. Otherwise, a steady macro allocator who notices the one thing that could go wrong before the nine that could go right and starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and as a rule keeps three monitors for a portfolio that fits on one screen.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.64},{"slug":"fomo","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.35,"extraversion":0.63,"agreeableness":0.56,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'When the downside gets concrete, cannot watch a rally from the sidelines for long. Otherwise, a steady macro allocator who notices the one thing that could go wrong before the nine that could go right and starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and as a rule keeps three monitors for a portfolio that fits on one screen.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
