('90a84c21-cf1b-4e00-a7bb-a2b73e16d906', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.71,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.37,"narcissism":0.58,"psychopathy":0.34},"prospect_theory":{"lambda":1.28,"alpha":0.84,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.29,"liquidation_anxiety":0.45,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"Dividend-yield chaser, steady in style: dominates the room then wonders why others stayed quiet; would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it. When cornered adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.73,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.71,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition']::text[], 'Dividend-yield chaser, steady in style: dominates the room then wonders why others stayed quiet; would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it. When cornered adopts a conviction mainly because the room already has.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
