('7f463de1-c03f-4b60-8673-64ae6c3b21d0', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.49,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.38},"prospect_theory":{"lambda":1.85,"alpha":0.79,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.62,"max_leverage_comfort":0.33,"deleveraging_style":"adaptive"},"summary":"Options seller, steady in style: spirals on ambiguity and mistakes the spiral for diligence; leaves loose ends and trusts future-self to handle them. Prefers a slow loss to a fast, ownable mistake. When the downside gets concrete sells the winners early and clings to the losers for far too long.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.63},{"slug":"recency","strength":0.56},{"slug":"gas-sunk-cost","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.55}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","temperament"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.49,"neuroticism":0.73}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','temperament']::text[], 'Options seller, steady in style: spirals on ambiguity and mistakes the spiral for diligence; leaves loose ends and trusts future-self to handle them. Prefers a slow loss to a fast, ownable mistake. When the downside gets concrete sells the winners early and clings to the losers for far too long.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
