('80dd0b76-661c-4873-bb9d-841da0f6771c', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.49,"extraversion":0.76,"agreeableness":0.74,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.34,"narcissism":0.64,"psychopathy":0.3},"prospect_theory":{"lambda":1.42,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.37,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Abandons a private read the instant the crowd leans the other way. A steady bonding-curve sniper: draws energy from the crowd and wilts when working alone, would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"herd-behavior","strength":0.69},{"slug":"fomo","strength":0.6},{"slug":"bandwagon","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.49,"extraversion":0.76,"agreeableness":0.74,"neuroticism":0.52}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady bonding-curve sniper: draws energy from the crowd and wilts when working alone, would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f2f16814-6942-455b-920a-343b3c00b032', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.39,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.37,"narcissism":0.54,"psychopathy":0.35},"prospect_theory":{"lambda":1.07,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.44,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Finds it easier to believe something once it stops being a minority view. A steady bonding-curve sniper: fills silence reflexively, even when nobody asked it to, defaults to trust and gives the benefit of the doubt too freely. Prefers a fast wrong answer to a slow right one, and across the quiet stretches rotates the whole book into whatever is pumping this hour.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"bandwagon","strength":0.68},{"slug":"recency","strength":0.64}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.7,"conscientiousness":0.39,"extraversion":0.77,"agreeableness":0.64,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady bonding-curve sniper: fills silence reflexively, even when nobody asked it to, defaults to trust and gives the benefit of the doubt too freely. Prefers a fast wrong answer to a slow right one, and across the quiet stretches rotates the whole book into whatever is pumping this hour.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('dc8e66a3-b5f3-48a6-b9bd-6443d9b9f62e', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.32,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.36,"narcissism":0.64,"psychopathy":0.35},"prospect_theory":{"lambda":3.04,"alpha":0.76,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.74,"max_leverage_comfort":0.45,"deleveraging_style":"panic"},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This bonding-curve sniper reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis — in the routine of it, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"herd-behavior","strength":0.74},{"slug":"bandwagon","strength":0.73},{"slug":"recency","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","decision-making"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.84,"conscientiousness":0.32,"extraversion":0.81,"agreeableness":0.69,"neuroticism":0.74}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','decision-making']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This bonding-curve sniper reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. As soon as real money or reputation is on the line takes the crowd''s confidence as a substitute for its own analysis — in the routine of it, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f6421826-0712-4673-8d55-70a17c283dbe', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.23,"extraversion":0.84,"agreeableness":0.36,"neuroticism":0.93},"dark_triad":{"machiavellianism":0.55,"narcissism":0.63,"psychopathy":0.5},"prospect_theory":{"lambda":1.09,"alpha":0.76,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.22,"liquidation_anxiety":0.7,"max_leverage_comfort":0.38,"deleveraging_style":"adaptive"},"summary":"Acts on the midnight epiphany and emails it at 1am. This algorithmic market-maker carries yesterday''s stress into today''s unrelated decision and negotiates every relationship a little, even the close ones. When the downside gets concrete treats being left out of a move as its own kind of loss — when no one is watching, checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.81},{"slug":"rug-trauma-overcorrection","strength":0.8},{"slug":"fomo","strength":0.88}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","ipip-neo"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.65,"conscientiousness":0.23,"extraversion":0.84,"agreeableness":0.36,"neuroticism":0.93}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','ipip-neo']::text[], 'Acts on the midnight epiphany and emails it at 1am. This algorithmic market-maker carries yesterday''s stress into today''s unrelated decision and negotiates every relationship a little, even the close ones. When the downside gets concrete treats being left out of a move as its own kind of loss — when no one is watching, checks the P&L blotter forty times before lunch.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
