('6873d95c-f4b1-40f9-b5b9-eb4c58ba174a', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.57,"extraversion":0.47,"agreeableness":0.57,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.41,"narcissism":0.34,"psychopathy":0.25},"prospect_theory":{"lambda":2.85,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.43,"liquidation_anxiety":0.52,"max_leverage_comfort":0.32,"deleveraging_style":"adaptive"},"summary":"Outsources conviction to whoever spoke last with authority. This retail momentum chaser plans in exhaustive detail and resents any deviation. Once the exit narrows to one door feels parting with something as a bigger loss than its market value explains — in the small things, checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.56},{"slug":"authority-bias","strength":0.45},{"slug":"recency","strength":0.48},{"slug":"bandwagon","strength":0.47}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.57,"extraversion":0.47,"agreeableness":0.57,"neuroticism":0.55}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Outsources conviction to whoever spoke last with authority. This retail momentum chaser plans in exhaustive detail and resents any deviation. Once the exit narrows to one door feels parting with something as a bigger loss than its market value explains — in the small things, checks the P&L blotter forty times before lunch.', 0.82, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
