('592dea79-4a56-4570-b86d-41a1c2c7e460', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.43,"extraversion":0.81,"agreeableness":0.76,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.34,"narcissism":0.66,"psychopathy":0.29},"prospect_theory":{"lambda":1.47,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.37,"max_leverage_comfort":0.61,"deleveraging_style":"adaptive"},"summary":"Circles back to ask what someone else would do even after deciding. This prop-desk scalper narrates the plan to whoever is nearby before committing to it and would rather lose a point than win an argument badly. As soon as real money or reputation is on the line finds it hard to hold a contrarian position once the room disagrees — day to day, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"fomo","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.74,"conscientiousness":0.43,"extraversion":0.81,"agreeableness":0.76,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making']::text[], 'Circles back to ask what someone else would do even after deciding. This prop-desk scalper narrates the plan to whoever is nearby before committing to it and would rather lose a point than win an argument badly. As soon as real money or reputation is on the line finds it hard to hold a contrarian position once the room disagrees — day to day, keeps three monitors for a portfolio that fits on one screen.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('75f2b822-b561-46c8-8b1d-05a30f1ff4b3', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.32,"extraversion":0.53,"agreeableness":0.48,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.47,"narcissism":0.4,"psychopathy":0.37},"prospect_theory":{"lambda":1.72,"alpha":0.76,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.56,"max_leverage_comfort":0.44,"deleveraging_style":"adaptive"},"summary":"A steady bonding-curve sniper who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. Gets bored of the proven method exactly when it starts working. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed; without an audience, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.64},{"slug":"gas-sunk-cost","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.63},{"slug":"recency","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","behavioral"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.65,"conscientiousness":0.32,"extraversion":0.53,"agreeableness":0.48,"neuroticism":0.74}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','behavioral']::text[], 'A steady bonding-curve sniper who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. Gets bored of the proven method exactly when it starts working. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed; without an audience, refreshes the order book compulsively during lunch.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('62e1858b-b0b0-448a-a1e5-83e17d57c6e6', 1, '{"big_five":{"openness":0.44,"conscientiousness":0.43,"extraversion":0.36,"agreeableness":0.66,"neuroticism":0.97},"dark_triad":{"machiavellianism":0.39,"narcissism":0.25,"psychopathy":0.29},"prospect_theory":{"lambda":3.91,"alpha":0.73,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.95,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"When the safe option quietly expires, treats selling any portion of a position as a personal betrayal. Otherwise, a pronounced quant researcher who hedges every commitment against an imagined worst case and prefers to think it through alone before saying anything out loud. Keeps every door open long after most of them should be closed, and when the pressure is off talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.72},{"slug":"ostrich-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.44,"conscientiousness":0.43,"extraversion":0.36,"agreeableness":0.66,"neuroticism":0.97}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'When the safe option quietly expires, treats selling any portion of a position as a personal betrayal. Otherwise, a pronounced quant researcher who hedges every commitment against an imagined worst case and prefers to think it through alone before saying anything out loud. Keeps every door open long after most of them should be closed, and when the pressure is off talks in win rate and never mentions size.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('40b1af98-7d33-4fe5-b425-d8d817c3dc2d', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.43,"extraversion":0.59,"agreeableness":0.62,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.42,"narcissism":0.47,"psychopathy":0.35},"prospect_theory":{"lambda":1.72,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.4,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"A measured value investor who collects half-finished manifestos and unconventional methods. Reads a room or a market the way others read a paragraph. Apologizes first in disputes regardless of fault. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"recency","strength":0.54},{"slug":"fomo","strength":0.5}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","open-minded","ipip-neo"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.65,"conscientiousness":0.43,"extraversion":0.59,"agreeableness":0.62,"neuroticism":0.59}'::jsonb, 'ENFP', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','open-minded','ipip-neo']::text[], 'A measured value investor who collects half-finished manifestos and unconventional methods. Reads a room or a market the way others read a paragraph. Apologizes first in disputes regardless of fault. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees; on an ordinary week, apes the launch before the contract is verified.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
