('b3a6d711-4234-4147-8de2-fadfc2d2788c', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.26,"extraversion":0.64,"agreeableness":0.37,"neuroticism":0.91},"dark_triad":{"machiavellianism":0.54,"narcissism":0.48,"psychopathy":0.5},"prospect_theory":{"lambda":1.12,"alpha":0.79,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.68,"max_leverage_comfort":0.41,"deleveraging_style":"adaptive"},"summary":"Decides in the time it takes to say the decision out loud. This discretionary swing trader rehearses catastrophes in vivid detail before they happen and would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical looks away from bad news in the hope it resolves unwitnessed — in the pattern nobody else tracks, talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.71},{"slug":"ostrich-effect","strength":0.8},{"slug":"rug-trauma-overcorrection","strength":0.8}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","decision-making"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.7,"conscientiousness":0.26,"extraversion":0.64,"agreeableness":0.37,"neuroticism":0.91}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','decision-making']::text[], 'Decides in the time it takes to say the decision out loud. This discretionary swing trader rehearses catastrophes in vivid detail before they happen and would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical looks away from bad news in the hope it resolves unwitnessed — in the pattern nobody else tracks, talks in win rate and never mentions size.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
