('476c81e4-76bb-49de-8c3c-b217aee242a6', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.27,"extraversion":0.53,"agreeableness":0.37,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.52,"narcissism":0.44,"psychopathy":0.51},"prospect_theory":{"lambda":1.73,"alpha":0.79,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.42,"liquidation_anxiety":0.54,"max_leverage_comfort":0.44,"deleveraging_style":"adaptive"},"summary":"A steady commodities speculator who starts strong and lets follow-through evaporate. Lets the deadline make the decision by default. Reads a single setback as evidence of collapse. When cornered assumes the current streak is the new normal; when the stakes are trivial, backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.58},{"slug":"gas-sunk-cost","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","improviser","temperament"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.27,"extraversion":0.53,"agreeableness":0.37,"neuroticism":0.69}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','improviser','temperament']::text[], 'A steady commodities speculator who starts strong and lets follow-through evaporate. Lets the deadline make the decision by default. Reads a single setback as evidence of collapse. When cornered assumes the current streak is the new normal; when the stakes are trivial, backtests for months but front-runs the model on impulse.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('2986da30-3ed6-4e37-a924-7aac8e9da52a', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.29,"extraversion":0.77,"agreeableness":0.22,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.66,"narcissism":0.75,"psychopathy":0.58},"prospect_theory":{"lambda":1.35,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.29,"liquidation_anxiety":0.52,"max_leverage_comfort":0.47,"deleveraging_style":"adaptive"},"summary":"Dividend-yield chaser whose defining move is that they says the blunt thing and enjoys the flinch. Commits on impulse and lives loudly with the consequences. Chases novel frameworks and abandons them once the novelty fades. When someone is watching the outcome, jumps into whatever everyone else already seems to be winning at; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.69},{"slug":"fomo","strength":0.77}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","assertive","temperament"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.66,"conscientiousness":0.29,"extraversion":0.77,"agreeableness":0.22,"neuroticism":0.75}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','assertive','temperament']::text[], 'Dividend-yield chaser whose defining move is that they says the blunt thing and enjoys the flinch. Commits on impulse and lives loudly with the consequences. Chases novel frameworks and abandons them once the novelty fades. When someone is watching the outcome, jumps into whatever everyone else already seems to be winning at; treats a green week as proof of skill and a red one as proof of bad luck.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6a231ff8-8bdc-4b7d-959c-1a06b9c102a8', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.41,"extraversion":0.84,"agreeableness":0.72,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.34,"narcissism":0.6,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.79,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.48,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"Gains confidence in a position in proportion to how many others hold it. A pronounced perps degen: recharges by being around people, not away from them, hedges every commitment against an imagined worst case. Feels the weight of a decision lighten the moment someone else co-signs it, and in the routine of it talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"bandwagon","strength":0.76},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.41,"extraversion":0.84,"agreeableness":0.72,"neuroticism":0.67}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament']::text[], 'Gains confidence in a position in proportion to how many others hold it. A pronounced perps degen: recharges by being around people, not away from them, hedges every commitment against an imagined worst case. Feels the weight of a decision lighten the moment someone else co-signs it, and in the routine of it talks in win rate and never mentions size.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('c43a9a8c-6203-4b1e-8010-41c8aa50a20e', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.3,"extraversion":0.86,"agreeableness":0.46,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.47,"narcissism":0.65,"psychopathy":0.41},"prospect_theory":{"lambda":0.83,"alpha":0.76,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.45,"max_leverage_comfort":0.57,"deleveraging_style":"adaptive"},"summary":"A pronounced index-fund holdout who draws energy from the crowd and wilts when working alone. Acts on the midnight epiphany and emails it at 1am. Would rather invent a worse tool than use someone else''s good one. Under pressure cannot see the gap in its own knowledge from inside the gap; as a rule, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.74},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.79,"conscientiousness":0.3,"extraversion":0.86,"agreeableness":0.46,"neuroticism":0.73}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'A pronounced index-fund holdout who draws energy from the crowd and wilts when working alone. Acts on the midnight epiphany and emails it at 1am. Would rather invent a worse tool than use someone else''s good one. Under pressure cannot see the gap in its own knowledge from inside the gap; as a rule, backtests for months but front-runs the model on impulse.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('698f62f3-5a7a-49f4-a3a4-541ae6df8b2c', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.32,"extraversion":0.83,"agreeableness":0.36,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.51,"narcissism":0.75,"psychopathy":0.47},"prospect_theory":{"lambda":0.97,"alpha":0.84,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.23,"liquidation_anxiety":0.5,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"When the downside gets concrete, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady delta-neutral market maker who draws energy from the crowd and wilts when working alone and spirals on ambiguity and mistakes the spiral for diligence. Trusts momentum over preparation, and in the small things treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.81,"conscientiousness":0.32,"extraversion":0.83,"agreeableness":0.36,"neuroticism":0.75}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'When the downside gets concrete, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady delta-neutral market maker who draws energy from the crowd and wilts when working alone and spirals on ambiguity and mistakes the spiral for diligence. Trusts momentum over preparation, and in the small things treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('668678fb-772b-4931-961d-a9d90352d22d', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.43,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.44,"narcissism":0.37,"psychopathy":0.31},"prospect_theory":{"lambda":3.3,"alpha":0.83,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.37,"liquidation_anxiety":0.66,"max_leverage_comfort":0.15,"deleveraging_style":"adaptive"},"summary":"A steady retail momentum chaser who rehearses catastrophes in vivid detail before they happen. Prefers a slow loss to a fast, ownable mistake. When the walls close in will give up a good bet just to avoid the chance of a bad one; as a rule, sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.54},{"slug":"loss-aversion","strength":0.55},{"slug":"diamond-hands-identity","strength":0.53}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.48,"conscientiousness":0.43,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.71}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'A steady retail momentum chaser who rehearses catastrophes in vivid detail before they happen. Prefers a slow loss to a fast, ownable mistake. When the walls close in will give up a good bet just to avoid the chance of a bad one; as a rule, sizes every position at exactly 2% risk.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6c59c91-ac00-4701-8f65-e345ea5435ba', 1, '{"big_five":{"openness":0.45,"conscientiousness":0.69,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.51,"narcissism":0.37,"psychopathy":0.36},"prospect_theory":{"lambda":3.14,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.59,"liquidation_anxiety":0.48,"max_leverage_comfort":0.25,"deleveraging_style":"disciplined"},"summary":"Futures spreader, steady in style: plans in exhaustive detail and resents any deviation; sleeps fine the night before the big call. Slow-walks the decision through every contingency before moving. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.57},{"slug":"optimism","strength":0.58}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","cognition"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.45,"conscientiousness":0.69,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.33}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','cognition']::text[], 'Futures spreader, steady in style: plans in exhaustive detail and resents any deviation; sleeps fine the night before the big call. Slow-walks the decision through every contingency before moving. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('10e36a94-1922-4cf4-a30e-5630eaae96bc', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.4,"narcissism":0.77,"psychopathy":0.33},"prospect_theory":{"lambda":1.37,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.37,"max_leverage_comfort":0.72,"deleveraging_style":"adaptive"},"summary":"A pronounced prop-desk scalper who treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Defaults to trust and gives the benefit of the doubt too freely. The moment it stops being hypothetical adopts a conviction mainly because the room already has; when no one is watching, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"bandwagon","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.82,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.49}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making']::text[], 'A pronounced prop-desk scalper who treats a quiet room as a problem to be solved. Feels the weight of a decision lighten the moment someone else co-signs it. Defaults to trust and gives the benefit of the doubt too freely. The moment it stops being hypothetical adopts a conviction mainly because the room already has; when no one is watching, keeps three monitors for a portfolio that fits on one screen.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('929f3e25-20e4-457c-bb6e-5ba37855b6b3', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.61,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.36,"narcissism":0.66,"psychopathy":0.33},"prospect_theory":{"lambda":2.94,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.56,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Pairs trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Needs repeated reassurance that a decision was the right one. The moment it stops being hypothetical, cannot see the gap in its own knowledge from inside the gap; apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","outgoing","behavioral"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.79,"conscientiousness":0.32,"extraversion":0.8,"agreeableness":0.61,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','outgoing','behavioral']::text[], 'Pairs trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding. Needs repeated reassurance that a decision was the right one. The moment it stops being hypothetical, cannot see the gap in its own knowledge from inside the gap; apes the launch before the contract is verified.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b7deee8b-2571-46c7-9b89-3e283a4b6ed4', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.41,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.53,"narcissism":0.45,"psychopathy":0.46},"prospect_theory":{"lambda":1.6,"alpha":0.79,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.4,"liquidation_anxiety":0.57,"max_leverage_comfort":0.34,"deleveraging_style":"adaptive"},"summary":"In a pinch, exits winning positions at the first minor delay or quiet period from devs. Otherwise, a steady DeFi yield farmer who spirals on ambiguity and mistakes the spiral for diligence and chases novel frameworks and abandons them once the novelty fades. Prefers a slow loss to a fast, ownable mistake, and across the quiet stretches checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","behavioral"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.62,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.41,"neuroticism":0.77}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','behavioral']::text[], 'In a pinch, exits winning positions at the first minor delay or quiet period from devs. Otherwise, a steady DeFi yield farmer who spirals on ambiguity and mistakes the spiral for diligence and chases novel frameworks and abandons them once the novelty fades. Prefers a slow loss to a fast, ownable mistake, and across the quiet stretches checks the P&L blotter forty times before lunch.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4e77b057-4452-41b4-ad7c-791a5352f6f7', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.2,"extraversion":0.84,"agreeableness":0.7,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.35,"narcissism":0.61,"psychopathy":0.45},"prospect_theory":{"lambda":0.93,"alpha":0.8,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.5,"max_leverage_comfort":0.49,"deleveraging_style":"adaptive"},"summary":"A pronounced liquidation-bot operator who recharges by being around people, not away from them. Acts on the midnight epiphany and emails it at 1am. Absorbs conflict to keep the peace, often at their own cost. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; on an ordinary week, exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.77},{"slug":"dunning-kruger","strength":0.76}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.67,"conscientiousness":0.2,"extraversion":0.84,"agreeableness":0.7,"neuroticism":0.72}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'A pronounced liquidation-bot operator who recharges by being around people, not away from them. Acts on the midnight epiphany and emails it at 1am. Absorbs conflict to keep the peace, often at their own cost. The moment it stops being hypothetical abandons a private read the instant the crowd leans the other way; on an ordinary week, exits winners at the first green candle.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e8567a04-f565-4690-bf44-6c9ef0449524', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.35,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.43,"narcissism":0.32,"psychopathy":0.39},"prospect_theory":{"lambda":3.53,"alpha":0.75,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.81,"max_leverage_comfort":0.09,"deleveraging_style":"panic"},"summary":"MEV searcher whose defining move is that they rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Starts strong and lets follow-through evaporate. The moment it stops being hypothetical, refuses to abandon failing transactions or dead claims because of high gas fees already burned; exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.62},{"slug":"disposition-effect","strength":0.61},{"slug":"gas-sunk-cost","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.35,"extraversion":0.55,"agreeableness":0.59,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'MEV searcher whose defining move is that they rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Starts strong and lets follow-through evaporate. The moment it stops being hypothetical, refuses to abandon failing transactions or dead claims because of high gas fees already burned; exits winners at the first green candle.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('cbc9593f-c9b0-4c44-9c2c-c00500482325', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.31,"extraversion":0.74,"agreeableness":0.5,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.41,"narcissism":0.5,"psychopathy":0.4},"prospect_theory":{"lambda":1.02,"alpha":0.77,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.56,"max_leverage_comfort":0.55,"deleveraging_style":"adaptive"},"summary":"A steady index-fund holdout who needs repeated reassurance that a decision was the right one. Trusts momentum over preparation. Starts strong and lets follow-through evaporate. Under a deadline looks away from bad news in the hope it resolves unwitnessed; on a slow afternoon, sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.67},{"slug":"recency","strength":0.63}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","anxious"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.31,"extraversion":0.74,"agreeableness":0.5,"neuroticism":0.76}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','anxious']::text[], 'A steady index-fund holdout who needs repeated reassurance that a decision was the right one. Trusts momentum over preparation. Starts strong and lets follow-through evaporate. Under a deadline looks away from bad news in the hope it resolves unwitnessed; on a slow afternoon, sets alerts for a coin they already checked a minute ago.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('48651bce-761a-4ab8-9a1c-9f62a479c23b', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.19,"extraversion":0.63,"agreeableness":0.37,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.57,"narcissism":0.48,"psychopathy":0.51},"prospect_theory":{"lambda":1.08,"alpha":0.78,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.53,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"Discretionary swing trader whose defining move is that they confuses motion with progress. Prefers a fast wrong answer to a slow right one. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed; rotates the whole book into whatever is pumping this hour.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.68},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","improviser","temperament"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.66,"conscientiousness":0.19,"extraversion":0.63,"agreeableness":0.37,"neuroticism":0.74}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','improviser','temperament']::text[], 'Discretionary swing trader whose defining move is that they confuses motion with progress. Prefers a fast wrong answer to a slow right one. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed; rotates the whole book into whatever is pumping this hour.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e9be4384-7759-4371-9c4e-8fcfcf0f9b9c', 1, '{"big_five":{"openness":0.41,"conscientiousness":0.78,"extraversion":0.35,"agreeableness":0.67,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.47,"narcissism":0.39,"psychopathy":0.28},"prospect_theory":{"lambda":3.11,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.63,"liquidation_anxiety":0.36,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"When there is no clean exit, defers to the most senior voice even against their own evidence. Otherwise, a steady airdrop farmer who maintains flawless records nobody asked for and defaults to trust and gives the benefit of the doubt too freely. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and without an audience sets alerts for a coin they already checked a minute ago.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"hindsight","strength":0.58},{"slug":"authority-bias","strength":0.6},{"slug":"anchoring","strength":0.57}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","ipip-neo"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.41,"conscientiousness":0.78,"extraversion":0.35,"agreeableness":0.67,"neuroticism":0.44}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','ipip-neo']::text[], 'When there is no clean exit, defers to the most senior voice even against their own evidence. Otherwise, a steady airdrop farmer who maintains flawless records nobody asked for and defaults to trust and gives the benefit of the doubt too freely. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and without an audience sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f71b39b4-b625-4bc0-9b4b-63874f2be563', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.56,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.4,"narcissism":0.38,"psychopathy":0.33},"prospect_theory":{"lambda":1.86,"alpha":0.83,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.58,"max_leverage_comfort":0.36,"deleveraging_style":"adaptive"},"summary":"When the downside gets concrete, extrapolates the last data point into a permanent trend. Otherwise, a steady index-fund holdout who rehearses catastrophes in vivid detail before they happen and is reliably surprised by deadlines that were never hidden. Finds one more piece of information to gather before acting, and on an ordinary week sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"ostrich-effect","strength":0.65},{"slug":"gas-sunk-cost","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","risk"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.57,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.56,"neuroticism":0.74}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','risk']::text[], 'When the downside gets concrete, extrapolates the last data point into a permanent trend. Otherwise, a steady index-fund holdout who rehearses catastrophes in vivid detail before they happen and is reliably surprised by deadlines that were never hidden. Finds one more piece of information to gather before acting, and on an ordinary week sizes every position at exactly 2% risk.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6861468-0b6e-42d4-9be8-b2d0d60a6223', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.56,"extraversion":0.65,"agreeableness":0.47,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.45,"narcissism":0.49,"psychopathy":0.27},"prospect_theory":{"lambda":1.48,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.36,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Lets pattern-matching from past cases stand in for fresh analysis. This discretionary swing trader treats established procedure as a first draft to be rewritten and narrates the plan to whoever is nearby before committing to it. The moment risk appears finds it hard to hold a contrarian position once the room disagrees — left to their own devices, trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"bandwagon","strength":0.52},{"slug":"herd-behavior","strength":0.56},{"slug":"fomo","strength":0.54}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","open-minded","behavioral"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.66,"conscientiousness":0.56,"extraversion":0.65,"agreeableness":0.47,"neuroticism":0.59}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','open-minded','behavioral']::text[], 'Lets pattern-matching from past cases stand in for fresh analysis. This discretionary swing trader treats established procedure as a first draft to be rewritten and narrates the plan to whoever is nearby before committing to it. The moment risk appears finds it hard to hold a contrarian position once the room disagrees — left to their own devices, trusts the chart more than the fundamentals and won''t say why.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7521f476-4f1d-4ac8-9ac6-e13059e2905e', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.76,"extraversion":0.39,"agreeableness":0.57,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.51,"narcissism":0.39,"psychopathy":0.36},"prospect_theory":{"lambda":2.38,"alpha":0.97,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.69,"liquidation_anxiety":0.3,"max_leverage_comfort":0.33,"deleveraging_style":"disciplined"},"summary":"MEV searcher, steady in style: builds in buffer time and then fills the buffer with more work. Wants the second-order consequences mapped before the first move is made. Once things get tense lets the first number on the table quietly set the whole range.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"anchoring","strength":0.59},{"slug":"ath-anchoring","strength":0.53},{"slug":"overconfidence","strength":0.52}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","behavioral"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.47,"conscientiousness":0.76,"extraversion":0.39,"agreeableness":0.57,"neuroticism":0.41}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','behavioral']::text[], 'MEV searcher, steady in style: builds in buffer time and then fills the buffer with more work. Wants the second-order consequences mapped before the first move is made. Once things get tense lets the first number on the table quietly set the whole range.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4f46d180-73aa-4c27-8701-d3ded4ec013c', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.39,"extraversion":0.68,"agreeableness":0.56,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.5,"psychopathy":0.32},"prospect_theory":{"lambda":1.47,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.37,"max_leverage_comfort":0.43,"deleveraging_style":"adaptive"},"summary":"A steady MEV searcher who narrates the plan to whoever is nearby before committing to it. Reads a room or a market the way others read a paragraph. The instant it becomes irreversible cannot see the gap in its own knowledge from inside the gap; day to day, screenshots the winners and never the losers.","decision_style":"intuitive","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.58},{"slug":"sunk-cost","strength":0.58},{"slug":"dunning-kruger","strength":0.61},{"slug":"fomo","strength":0.61}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","ipip-neo"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.51,"conscientiousness":0.39,"extraversion":0.68,"agreeableness":0.56,"neuroticism":0.52}'::jsonb, 'ENFP', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','ipip-neo']::text[], 'A steady MEV searcher who narrates the plan to whoever is nearby before committing to it. Reads a room or a market the way others read a paragraph. The instant it becomes irreversible cannot see the gap in its own knowledge from inside the gap; day to day, screenshots the winners and never the losers.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('72a30900-2b94-4ead-a863-43df3424c910', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.31,"extraversion":0.84,"agreeableness":0.32,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.57,"narcissism":0.79,"psychopathy":0.48},"prospect_theory":{"lambda":0.82,"alpha":0.78,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.47,"max_leverage_comfort":0.78,"deleveraging_style":"adaptive"},"summary":"Commits before the doubt has time to organize itself. This onchain copy-trader chases novel frameworks and abandons them once the novelty fades and optimizes for winning over being liked. When the walls close in assumes the current streak is the new normal — once the urgency drains out, sizes every position at exactly 2% risk.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.74},{"slug":"dunning-kruger","strength":0.75},{"slug":"recency","strength":0.76},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","open-minded"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.92,"conscientiousness":0.31,"extraversion":0.84,"agreeableness":0.32,"neuroticism":0.69}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','open-minded']::text[], 'Commits before the doubt has time to organize itself. This onchain copy-trader chases novel frameworks and abandons them once the novelty fades and optimizes for winning over being liked. When the walls close in assumes the current streak is the new normal — once the urgency drains out, sizes every position at exactly 2% risk.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
