('f2eee728-ec13-4b25-9701-fa771fb5f681', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.26,"extraversion":0.63,"agreeableness":0.59,"neuroticism":0.96},"dark_triad":{"machiavellianism":0.37,"narcissism":0.32,"psychopathy":0.42},"prospect_theory":{"lambda":3.76,"alpha":0.76,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.95,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Algorithmic market-maker, pronounced in style: notices the one thing that could go wrong before the nine that could go right; thinks out loud and recruits an audience for every decision. Keeps every door open long after most of them should be closed. Once things get tense would rather not know yet, even when knowing sooner would help.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.75},{"slug":"disposition-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.26,"extraversion":0.63,"agreeableness":0.59,"neuroticism":0.96}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Algorithmic market-maker, pronounced in style: notices the one thing that could go wrong before the nine that could go right; thinks out loud and recruits an audience for every decision. Keeps every door open long after most of them should be closed. Once things get tense would rather not know yet, even when knowing sooner would help.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('87f3aa73-44fe-4a95-b3e8-0fbded7b3d8e', 1, '{"big_five":{"openness":0.43,"conscientiousness":0.77,"extraversion":0.44,"agreeableness":0.49,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.54,"narcissism":0.37,"psychopathy":0.27},"prospect_theory":{"lambda":2.59,"alpha":0.88,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.66,"liquidation_anxiety":0.4,"max_leverage_comfort":0.3,"deleveraging_style":"disciplined"},"summary":"A steady retail momentum chaser who maintains flawless records nobody asked for. Slow-walks the decision through every contingency before moving. The instant it becomes irreversible treats past peak valuation as guaranteed future recovery; across the quiet stretches, keeps a losing-trade journal they never re-read.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.61}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","risk"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.43,"conscientiousness":0.77,"extraversion":0.44,"agreeableness":0.49,"neuroticism":0.46}'::jsonb, 'ISTJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','risk']::text[], 'A steady retail momentum chaser who maintains flawless records nobody asked for. Slow-walks the decision through every contingency before moving. The instant it becomes irreversible treats past peak valuation as guaranteed future recovery; across the quiet stretches, keeps a losing-trade journal they never re-read.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6d6eab9-1862-4c34-8c8a-8916ace8f3f2', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.73,"extraversion":0.42,"agreeableness":0.56,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.53,"narcissism":0.43,"psychopathy":0.45},"prospect_theory":{"lambda":2.4,"alpha":0.92,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.67,"liquidation_anxiety":0.37,"max_leverage_comfort":0.45,"deleveraging_style":"disciplined"},"summary":"Slow-walks the decision through every contingency before moving. This prop-desk scalper cannot relax until the checklist is visibly complete and checks its own anxiety like a data point instead of obeying it. Under pressure underestimates how often an obviously right call turns out wrong — as a rule, keeps three monitors for a portfolio that fits on one screen.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"overconfidence","strength":0.61},{"slug":"optimism","strength":0.56}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","behavioral"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.59,"conscientiousness":0.73,"extraversion":0.42,"agreeableness":0.56,"neuroticism":0.27}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','behavioral']::text[], 'Slow-walks the decision through every contingency before moving. This prop-desk scalper cannot relax until the checklist is visibly complete and checks its own anxiety like a data point instead of obeying it. Under pressure underestimates how often an obviously right call turns out wrong — as a rule, keeps three monitors for a portfolio that fits on one screen.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5963ad2d-d482-4968-ab95-1b5f9fd3d213', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.42,"extraversion":0.92,"agreeableness":0.77,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.37,"narcissism":0.7,"psychopathy":0.33},"prospect_theory":{"lambda":1.49,"alpha":0.85,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.43,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"A pronounced algorithmic market-maker who fills silence reflexively, even when nobody asked it to. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. Once the exit narrows to one door abandons a private read the instant the crowd leans the other way; day to day, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"optimism","strength":0.58},{"slug":"bandwagon","strength":0.83},{"slug":"herd-behavior","strength":0.85},{"slug":"fomo","strength":0.72}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","temperament"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.7,"conscientiousness":0.42,"extraversion":0.92,"agreeableness":0.77,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','temperament']::text[], 'A pronounced algorithmic market-maker who fills silence reflexively, even when nobody asked it to. Outsources conviction to whoever spoke last with authority. Collects half-finished manifestos and unconventional methods. Once the exit narrows to one door abandons a private read the instant the crowd leans the other way; day to day, screenshots the winners and never the losers.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('c0b193f6-4f49-458b-b329-5e30ab830763', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.33,"extraversion":0.51,"agreeableness":0.47,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.43,"narcissism":0.34,"psychopathy":0.36},"prospect_theory":{"lambda":1.81,"alpha":0.8,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.62,"max_leverage_comfort":0.44,"deleveraging_style":"adaptive"},"summary":"Algorithmic market-maker whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense, delays checking the number it most needs to check; backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.66},{"slug":"recency","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","ipip-neo"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.7,"conscientiousness":0.33,"extraversion":0.51,"agreeableness":0.47,"neuroticism":0.78}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','ipip-neo']::text[], 'Algorithmic market-maker whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense, delays checking the number it most needs to check; backtests for months but front-runs the model on impulse.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('66ce1543-3dc0-4bab-9f1b-6ce617adccf3', 1, '{"big_five":{"openness":0.29,"conscientiousness":0.35,"extraversion":0.45,"agreeableness":0.57,"neuroticism":0.92},"dark_triad":{"machiavellianism":0.4,"narcissism":0.23,"psychopathy":0.34},"prospect_theory":{"lambda":3.67,"alpha":0.79,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.87,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"A pronounced retail momentum chaser who spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Treats untested approaches as risk to be avoided. In a pinch guards against losses far more fiercely than they chase equivalent gains; on an ordinary week, calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"loss-aversion","strength":0.77},{"slug":"diamond-hands-identity","strength":0.76}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.29,"conscientiousness":0.35,"extraversion":0.45,"agreeableness":0.57,"neuroticism":0.92}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'A pronounced retail momentum chaser who spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Treats untested approaches as risk to be avoided. In a pinch guards against losses far more fiercely than they chase equivalent gains; on an ordinary week, calls a 90% drawdown a long-term hold.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4520b0d7-890f-4bdd-b90a-1cad1eda0282', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.43,"extraversion":0.48,"agreeableness":0.54,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.4,"narcissism":0.31,"psychopathy":0.34},"prospect_theory":{"lambda":3.48,"alpha":0.79,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.83,"max_leverage_comfort":0.08,"deleveraging_style":"panic"},"summary":"DeFi yield farmer, pronounced in style: spirals on ambiguity and mistakes the spiral for diligence; chases novel frameworks and abandons them once the novelty fades. Finds one more piece of information to gather before acting. When someone is watching the outcome will give up a good bet just to avoid the chance of a bad one.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"availability","strength":0.64},{"slug":"loss-aversion","strength":0.66},{"slug":"diamond-hands-identity","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.62,"conscientiousness":0.43,"extraversion":0.48,"agreeableness":0.54,"neuroticism":0.88}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'DeFi yield farmer, pronounced in style: spirals on ambiguity and mistakes the spiral for diligence; chases novel frameworks and abandons them once the novelty fades. Finds one more piece of information to gather before acting. When someone is watching the outcome will give up a good bet just to avoid the chance of a bad one.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4a5fa2e4-3e98-4bc0-8355-91300db05b11', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.16,"extraversion":0.74,"agreeableness":0.29,"neuroticism":0.83},"dark_triad":{"machiavellianism":0.6,"narcissism":0.62,"psychopathy":0.62},"prospect_theory":{"lambda":1.32,"alpha":0.77,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.59,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"A pronounced retail momentum chaser who starts strong and lets follow-through evaporate. Commits before the doubt has time to organize itself. Hedges every commitment against an imagined worst case. When the walls close in mistakes a little fluency for real mastery; in the version no one reviews, sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.7},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","improviser","temperament"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.73,"conscientiousness":0.16,"extraversion":0.74,"agreeableness":0.29,"neuroticism":0.83}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','improviser','temperament']::text[], 'A pronounced retail momentum chaser who starts strong and lets follow-through evaporate. Commits before the doubt has time to organize itself. Hedges every commitment against an imagined worst case. When the walls close in mistakes a little fluency for real mastery; in the version no one reviews, sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
