('d08dfe54-e9fa-402b-85d7-dd0e83c9724b', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.38,"extraversion":0.53,"agreeableness":0.58,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.36,"narcissism":0.29,"psychopathy":0.3},"prospect_theory":{"lambda":3.56,"alpha":0.77,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.78,"max_leverage_comfort":0.1,"deleveraging_style":"panic"},"summary":"As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady algorithmic market-maker who hedges every commitment against an imagined worst case and leaves loose ends and trusts future-self to handle them. Buries hard calls under a pile of preparatory busywork, and once the urgency drains out sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.69},{"slug":"gas-sunk-cost","strength":0.6},{"slug":"availability","strength":0.55},{"slug":"disposition-effect","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.53,"conscientiousness":0.38,"extraversion":0.53,"agreeableness":0.58,"neuroticism":0.75}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady algorithmic market-maker who hedges every commitment against an imagined worst case and leaves loose ends and trusts future-self to handle them. Buries hard calls under a pile of preparatory busywork, and once the urgency drains out sizes every position at exactly 2% risk.', 0.89, 'approved', '092841db-d88c-438b