('ad005087-9fee-478b-a925-454ce23e3072', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.35,"extraversion":0.49,"agreeableness":0.53,"neuroticism":0.97},"dark_triad":{"machiavellianism":0.41,"narcissism":0.2,"psychopathy":0.35},"prospect_theory":{"lambda":3.95,"alpha":0.73,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.95,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"A pronounced delta-neutral market maker who carries yesterday''s stress into today''s unrelated decision. Defers the decision until circumstances make it for them. Confuses motion with progress. When someone is watching the outcome weights whatever happened most recently and vividly as if it were typical; when no one is watching, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"availability","strength":0.75},{"slug":"ostrich-effect","strength":0.75},{"slug":"loss-aversion","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","risk"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.42,"conscientiousness":0.35,"extraversion":0.49,"agreeableness":0.53,"neuroticism":0.97}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','risk']::text[], 'A pronounced delta-neutral market maker who carries yesterday''s stress into today''s unrelated decision. Defers the decision until circumstances make it for them. Confuses motion with progress. When someone is watching the outcome weights whatever happened most recently and vividly as if it were typical; when no one is watching, refreshes the order book compulsively during lunch.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
