('e81d5938-134b-4f35-8727-9ff88eade5ea', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.58,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.38,"narcissism":0.62,"psychopathy":0.38},"prospect_theory":{"lambda":1.18,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.5,"max_leverage_comfort":0.56,"deleveraging_style":"adaptive"},"summary":"Futures spreader whose defining move is that they fills silence reflexively, even when nobody asked it to. Commits on impulse and lives loudly with the consequences. Reads outside the field for ideas the field itself would reject. The moment risk appears, jumps into whatever everyone else already seems to be winning at; holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.78},{"slug":"recency","strength":0.65},{"slug":"dunning-kruger","strength":0.66},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.58,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Futures spreader whose defining move is that they fills silence reflexively, even when nobody asked it to. Commits on impulse and lives loudly with the consequences. Reads outside the field for ideas the field itself would reject. The moment risk appears, jumps into whatever everyone else already seems to be winning at; holds a bag from 2021 out of pure spite.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('aad632f6-65d4-40e7-b887-05692c7df9cb', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.47,"extraversion":0.58,"agreeableness":0.53,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.37,"narcissism":0.32,"psychopathy":0.33},"prospect_theory":{"lambda":3.25,"alpha":0.72,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.85,"max_leverage_comfort":0.07,"deleveraging_style":"panic"},"summary":"Once the exit narrows to one door, judges likelihood by how easily an example comes to mind, not by the base rate. Otherwise, a pronounced pairs trader who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed, and across the quiet stretches refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.68},{"slug":"ostrich-effect","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.58,"conscientiousness":0.47,"extraversion":0.58,"agreeableness":0.53,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Once the exit narrows to one door, judges likelihood by how easily an example comes to mind, not by the base rate. Otherwise, a pronounced pairs trader who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed, and across the quiet stretches refreshes the order book compulsively during lunch.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('ed9b881b-fa4d-411f-8fdc-ef87c86bed5e', 1, '{"big_five":{"openness":0.45,"conscientiousness":0.39,"extraversion":0.5,"agreeableness":0.6,"neuroticism":0.93},"dark_triad":{"machiavellianism":0.36,"narcissism":0.25,"psychopathy":0.34},"prospect_theory":{"lambda":3.89,"alpha":0.72,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.45,"liquidation_anxiety":0.89,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Index-fund holdout whose defining move is that they needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. In a pinch, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"loss-aversion","strength":0.75},{"slug":"diamond-hands-identity","strength":0.76},{"slug":"availability","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","decision-making"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.45,"conscientiousness":0.39,"extraversion":0.5,"agreeableness":0.6,"neuroticism":0.93}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','decision-making']::text[], 'Index-fund holdout whose defining move is that they needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. In a pinch, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; apes the launch before the contract is verified.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
