('25c4e607-cc2a-4245-b4ee-2231bd8a3683', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.38,"extraversion":0.5,"agreeableness":0.62,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.35,"narcissism":0.28,"psychopathy":0.31},"prospect_theory":{"lambda":3.36,"alpha":0.82,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.4,"liquidation_anxiety":0.83,"max_leverage_comfort":0.11,"deleveraging_style":"panic"},"summary":"Treats not-choosing as a safe choice right up until it is not. This DeFi yield farmer reads a single setback as evidence of collapse and does the interesting 80% and abandons the tedious 20%. The moment it stops being hypothetical delays checking the number it most needs to check — when no one is watching, apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.64},{"slug":"ostrich-effect","strength":0.72},{"slug":"availability","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.38,"extraversion":0.5,"agreeableness":0.62,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Treats not-choosing as a safe choice right up until it is not. This DeFi yield farmer reads a single setback as evidence of collapse and does the interesting 80% and abandons the tedious 20%. The moment it stops being hypothetical delays checking the number it most needs to check — when no one is watching, apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5b98c2fa-c22b-4cad-8d18-8efa393cf0c9', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.72,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.39,"narcissism":0.68,"psychopathy":0.36},"prospect_theory":{"lambda":1.57,"alpha":0.87,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.22,"liquidation_anxiety":0.36,"max_leverage_comfort":0.57,"deleveraging_style":"adaptive"},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This discretionary swing trader recharges by being around people, not away from them and does the interesting 80% and abandons the tedious 20%. Once things get tense takes the crowd''s confidence as a substitute for its own analysis — when the pressure is off, sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.65,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.72,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This discretionary swing trader recharges by being around people, not away from them and does the interesting 80% and abandons the tedious 20%. Once things get tense takes the crowd''s confidence as a substitute for its own analysis — when the pressure is off, sets stop-losses then cancels them at the open.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('651676ad-820a-4f95-b788-d9a12432ad88', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.34,"extraversion":0.79,"agreeableness":0.54,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.41,"narcissism":0.61,"psychopathy":0.34},"prospect_theory":{"lambda":0.95,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.37,"max_leverage_comfort":0.65,"deleveraging_style":"adaptive"},"summary":"Treats being left out of a move as its own kind of loss. A steady discretionary swing trader: narrates the plan to whoever is nearby before committing to it, spirals on ambiguity and mistakes the spiral for diligence. Commits on impulse and lives loudly with the consequences, and in the pattern nobody else tracks calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"recency","strength":0.65},{"slug":"dunning-kruger","strength":0.63},{"slug":"herd-behavior","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.34,"extraversion":0.79,"agreeableness":0.54,"neuroticism":0.65}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Treats being left out of a move as its own kind of loss. A steady discretionary swing trader: narrates the plan to whoever is nearby before committing to it, spirals on ambiguity and mistakes the spiral for diligence. Commits on impulse and lives loudly with the consequences, and in the pattern nobody else tracks calls a 90% drawdown a long-term hold.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
