('b3c07a97-950a-4bd0-aba0-e36666afa239', 1, '{"big_five":{"openness":0.39,"conscientiousness":0.75,"extraversion":0.41,"agreeableness":0.6,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.48,"narcissism":0.35,"psychopathy":0.37},"prospect_theory":{"lambda":3.09,"alpha":0.94,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.65,"liquidation_anxiety":0.46,"max_leverage_comfort":0.27,"deleveraging_style":"disciplined"},"summary":"Airdrop farmer, steady in style: maintains flawless records nobody asked for; moves on from a mistake faster than the people around them do. Revisits a settled decision if a single new fact appears. The instant it becomes irreversible is more certain than the hit rate justifies.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"hindsight","strength":0.57},{"slug":"overconfidence","strength":0.61},{"slug":"anchoring","strength":0.52},{"slug":"ath-anchoring","strength":0.6}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","risk"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.39,"conscientiousness":0.75,"extraversion":0.41,"agreeableness":0.6,"neuroticism":0.33}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','risk']::text[], 'Airdrop farmer, steady in style: maintains flawless records nobody asked for; moves on from a mistake faster than the people around them do. Revisits a settled decision if a single new fact appears. The instant it becomes irreversible is more certain than the hit rate justifies.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e9147bb0-ecd3-41e0-a624-510789439c11', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.41,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.37,"narcissism":0.35,"psychopathy":0.34},"prospect_theory":{"lambda":3.76,"alpha":0.72,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.91,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Value investor, pronounced in style: notices the one thing that could go wrong before the nine that could go right; apologizes first in disputes regardless of fault. Buries hard calls under a pile of preparatory busywork. As soon as real money or reputation is on the line feels a loss twice as sharply as an equivalent gain and plans accordingly.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.67},{"slug":"availability","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.53,"conscientiousness":0.41,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Value investor, pronounced in style: notices the one thing that could go wrong before the nine that could go right; apologizes first in disputes regardless of fault. Buries hard calls under a pile of preparatory busywork. As soon as real money or reputation is on the line feels a loss twice as sharply as an equivalent gain and plans accordingly.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('07697d59-4c3f-4d80-a7d5-fae6f631ad4c', 1, '{"big_five":{"openness":0.37,"conscientiousness":0.64,"extraversion":0.34,"agreeableness":0.67,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.42,"narcissism":0.4,"psychopathy":0.28},"prospect_theory":{"lambda":3.18,"alpha":0.88,"beta":0.81},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.58,"liquidation_anxiety":0.46,"max_leverage_comfort":0.32,"deleveraging_style":"adaptive"},"summary":"A steady index-fund holdout who measures decisions by who they might upset. Wants the second-order consequences mapped before the first move is made. Weighs words carefully before spending them. Under pressure refuses to exit positions until price returns to the previous cycle peak; once the urgency drains out, keeps a losing-trade journal they never re-read.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"authority-bias","strength":0.57},{"slug":"ath-anchoring","strength":0.58}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","accommodating","behavioral"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.37,"conscientiousness":0.64,"extraversion":0.34,"agreeableness":0.67,"neuroticism":0.45}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','accommodating','behavioral']::text[], 'A steady index-fund holdout who measures decisions by who they might upset. Wants the second-order consequences mapped before the first move is made. Weighs words carefully before spending them. Under pressure refuses to exit positions until price returns to the previous cycle peak; once the urgency drains out, keeps a losing-trade journal they never re-read.', 0.85, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6c167593-df0d-4522-a67d-b540779237ea', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.27,"extraversion":0.71,"agreeableness":0.24,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.63,"narcissism":0.7,"psychopathy":0.61},"prospect_theory":{"lambda":1.09,"alpha":0.75,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.54,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"A steady perps degen who reads a single setback as evidence of collapse. Prefers a fast wrong answer to a slow right one. Confuses motion with progress. When there is no clean exit discounts the older pattern in favor of whatever just happened; when the stakes are trivial, sizes every position at exactly 2% risk.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.72},{"slug":"airdrop-entitlement","strength":0.71},{"slug":"rug-trauma-overcorrection","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","temperament"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.73,"conscientiousness":0.27,"extraversion":0.71,"agreeableness":0.24,"neuroticism":0.77}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','temperament']::text[], 'A steady perps degen who reads a single setback as evidence of collapse. Prefers a fast wrong answer to a slow right one. Confuses motion with progress. When there is no clean exit discounts the older pattern in favor of whatever just happened; when the stakes are trivial, sizes every position at exactly 2% risk.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b8b26f0e-34a0-406a-b065-811b9b481cd5', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.46,"extraversion":0.87,"agreeableness":0.72,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.33,"narcissism":0.73,"psychopathy":0.3},"prospect_theory":{"lambda":1.4,"alpha":0.83,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.21,"liquidation_anxiety":0.44,"max_leverage_comfort":0.62,"deleveraging_style":"adaptive"},"summary":"As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced perps degen who dominates the room then wonders why others stayed quiet and reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.8},{"slug":"herd-behavior","strength":0.76}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.46,"extraversion":0.87,"agreeableness":0.72,"neuroticism":0.63}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo']::text[], 'As soon as real money or reputation is on the line, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced perps degen who dominates the room then wonders why others stayed quiet and reframes every problem as an excuse to learn a new system. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week refreshes the order book compulsively during lunch.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('fa02318a-adb4-4cc5-ab07-119245519b81', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.52,"extraversion":0.63,"agreeableness":0.68,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.38,"narcissism":0.5,"psychopathy":0.27},"prospect_theory":{"lambda":1.59,"alpha":0.86,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.5,"max_leverage_comfort":0.47,"deleveraging_style":"adaptive"},"summary":"When the walls close in, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady macro allocator who would rather lose a point than win an argument badly and recharges by being around people, not away from them. Reads a room or a market the way others read a paragraph, and without an audience keeps three monitors for a portfolio that fits on one screen.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"bandwagon","strength":0.57}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","accommodating","risk"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.61,"conscientiousness":0.52,"extraversion":0.63,"agreeableness":0.68,"neuroticism":0.64}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','accommodating','risk']::text[], 'When the walls close in, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady macro allocator who would rather lose a point than win an argument badly and recharges by being around people, not away from them. Reads a room or a market the way others read a paragraph, and without an audience keeps three monitors for a portfolio that fits on one screen.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f046ffc0-cd41-4e1c-95bb-317c65fd3402', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.27,"extraversion":0.57,"agreeableness":0.64,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.39,"narcissism":0.35,"psychopathy":0.35},"prospect_theory":{"lambda":3.39,"alpha":0.83,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.76,"max_leverage_comfort":0.15,"deleveraging_style":"panic"},"summary":"Refuses to abandon failing transactions or dead claims because of high gas fees already burned. A steady algorithmic market-maker: spirals on ambiguity and mistakes the spiral for diligence, confuses motion with progress. Lets the deadline make the decision by default, and when the pressure is off names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.7},{"slug":"sunk-cost","strength":0.57},{"slug":"disposition-effect","strength":0.64},{"slug":"ostrich-effect","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.46,"conscientiousness":0.27,"extraversion":0.57,"agreeableness":0.64,"neuroticism":0.74}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Refuses to abandon failing transactions or dead claims because of high gas fees already burned. A steady algorithmic market-maker: spirals on ambiguity and mistakes the spiral for diligence, confuses motion with progress. Lets the deadline make the decision by default, and when the pressure is off names every strategy after the trade that almost worked.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a78ad9d5-4a9a-4806-bf32-64c57189d233', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.32,"extraversion":0.85,"agreeableness":0.45,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.48,"narcissism":0.69,"psychopathy":0.43},"prospect_theory":{"lambda":1.16,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.23,"liquidation_anxiety":0.44,"max_leverage_comfort":0.54,"deleveraging_style":"adaptive"},"summary":"When the downside gets concrete, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced MEV searcher who dominates the room then wonders why others stayed quiet and treats established procedure as a first draft to be rewritten. Trusts momentum over preparation, and as a rule calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.68,"conscientiousness":0.32,"extraversion":0.85,"agreeableness":0.45,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'When the downside gets concrete, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced MEV searcher who dominates the room then wonders why others stayed quiet and treats established procedure as a first draft to be rewritten. Trusts momentum over preparation, and as a rule calls a 90% drawdown a long-term hold.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a38c5518-d405-4bca-b7ee-6c13874f5ab1', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.24,"extraversion":0.49,"agreeableness":0.67,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.42,"narcissism":0.28,"psychopathy":0.36},"prospect_theory":{"lambda":3.71,"alpha":0.77,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.9,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"A pronounced onchain copy-trader who hedges every commitment against an imagined worst case. Treats not-choosing as a safe choice right up until it is not. Defaults to trust and gives the benefit of the doubt too freely. When cornered feels a winning position as fragile and a losing one as merely paused; in the pattern nobody else tracks, rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.69},{"slug":"diamond-hands-identity","strength":0.67},{"slug":"disposition-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.42,"conscientiousness":0.24,"extraversion":0.49,"agreeableness":0.67,"neuroticism":0.87}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'A pronounced onchain copy-trader who hedges every commitment against an imagined worst case. Treats not-choosing as a safe choice right up until it is not. Defaults to trust and gives the benefit of the doubt too freely. When cornered feels a winning position as fragile and a losing one as merely paused; in the pattern nobody else tracks, rotates the whole book into whatever is pumping this hour.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
