('310c4339-a6c4-4989-8d34-2a3c37277bbf', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.31,"extraversion":0.5,"agreeableness":0.49,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.39,"narcissism":0.33,"psychopathy":0.41},"prospect_theory":{"lambda":1.72,"alpha":0.78,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.52,"max_leverage_comfort":0.42,"deleveraging_style":"adaptive"},"summary":"A steady index-fund holdout who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense refuses to abandon failing transactions or dead claims because of high gas fees already burned; in the version no one reviews, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"framing","strength":0.55},{"slug":"gas-sunk-cost","strength":0.69},{"slug":"ostrich-effect","strength":0.59},{"slug":"disposition-effect","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","risk"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.7,"conscientiousness":0.31,"extraversion":0.5,"agreeableness":0.49,"neuroticism":0.72}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','risk']::text[], 'A steady index-fund holdout who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense refuses to abandon failing transactions or dead claims because of high gas fees already burned; in the version no one reviews, refreshes the order book compulsively during lunch.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('ab6b5b5a-1be0-4b95-aa89-baeb3da78aaf', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.33,"extraversion":0.56,"agreeableness":0.62,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.39,"narcissism":0.32,"psychopathy":0.38},"prospect_theory":{"lambda":3.86,"alpha":0.77,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.42,"liquidation_anxiety":0.86,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Airdrop farmer whose defining move is that they rehearses catastrophes in vivid detail before they happen. Lets the deadline make the decision by default. Reads other people''s discomfort before they voice it. When cornered, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.72},{"slug":"loss-aversion","strength":0.63},{"slug":"gas-sunk-cost","strength":0.66},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.48,"conscientiousness":0.33,"extraversion":0.56,"agreeableness":0.62,"neuroticism":0.87}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'Airdrop farmer whose defining move is that they rehearses catastrophes in vivid detail before they happen. Lets the deadline make the decision by default. Reads other people''s discomfort before they voice it. When cornered, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; treats a green week as proof of skill and a red one as proof of bad luck.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d15c1f32-4c5e-4193-b41b-e88df50d0ec1', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.36,"extraversion":0.88,"agreeableness":0.76,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.37,"narcissism":0.74,"psychopathy":0.33},"prospect_theory":{"lambda":1.48,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.38,"max_leverage_comfort":0.71,"deleveraging_style":"adaptive"},"summary":"When someone is watching the outcome, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced value investor who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and on a slow afternoon names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.83},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.36,"extraversion":0.88,"agreeableness":0.76,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition']::text[], 'When someone is watching the outcome, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced value investor who recharges by being around people, not away from them and reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and on a slow afternoon names every strategy after the trade that almost worked.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6ded19dc-7420-402d-b06e-629a73b4395f', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.64,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.37,"narcissism":0.57,"psychopathy":0.39},"prospect_theory":{"lambda":2.82,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.58,"max_leverage_comfort":0.52,"deleveraging_style":"adaptive"},"summary":"Waits for a permission that never quite arrives. This value investor gets bored of the proven method exactly when it starts working and narrates the plan to whoever is nearby before committing to it. In a pinch assumes the current streak is the new normal — once the urgency drains out, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"herd-behavior","strength":0.63},{"slug":"recency","strength":0.66},{"slug":"bandwagon","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","cognition"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.75,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.64,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','cognition']::text[], 'Waits for a permission that never quite arrives. This value investor gets bored of the proven method exactly when it starts working and narrates the plan to whoever is nearby before committing to it. In a pinch assumes the current streak is the new normal — once the urgency drains out, keeps three monitors for a portfolio that fits on one screen.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5ddead14-11cb-4b27-998c-8de1b47b7759', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.46,"extraversion":0.69,"agreeableness":0.74,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.35,"narcissism":0.58,"psychopathy":0.29},"prospect_theory":{"lambda":3,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.53,"max_leverage_comfort":0.55,"deleveraging_style":"adaptive"},"summary":"When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced crypto day-trader who reframes every problem as an excuse to learn a new system and absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"authority-bias","strength":0.54},{"slug":"recency","strength":0.61},{"slug":"endowment","strength":0.53},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","temperament"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.84,"conscientiousness":0.46,"extraversion":0.69,"agreeableness":0.74,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','temperament']::text[], 'When the stakes rise, abandons a private read the instant the crowd leans the other way. Otherwise, a pronounced crypto day-trader who reframes every problem as an excuse to learn a new system and absorbs conflict to keep the peace, often at their own cost. Outsources conviction to whoever spoke last with authority, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
