('09f963cd-a272-422c-bf58-5f0549410cfc', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.38,"extraversion":0.46,"agreeableness":0.62,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.36,"narcissism":0.24,"psychopathy":0.29},"prospect_theory":{"lambda":3.77,"alpha":0.76,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.4,"liquidation_anxiety":0.88,"max_leverage_comfort":0.06,"deleveraging_style":"panic"},"summary":"The instant the deadline moves up, would rather not know yet, even when knowing sooner would help. Otherwise, a pronounced pairs trader who notices the one thing that could go wrong before the nine that could go right and treats a plan as a suggestion the moment it is made. Defers the decision until circumstances make it for them, and in the version no one reviews apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.76},{"slug":"availability","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","decision-making"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.54,"conscientiousness":0.38,"extraversion":0.46,"agreeableness":0.62,"neuroticism":0.9}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','decision-making']::text[], 'The instant the deadline moves up, would rather not know yet, even when knowing sooner would help. Otherwise, a pronounced pairs trader who notices the one thing that could go wrong before the nine that could go right and treats a plan as a suggestion the moment it is made. Defers the decision until circumstances make it for them, and in the version no one reviews apes the launch before the contract is verified.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f692b21d-aea8-4186-a62c-81973dcff21b', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.4,"extraversion":0.73,"agreeableness":0.74,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.29},"prospect_theory":{"lambda":2.85,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.59,"max_leverage_comfort":0.46,"deleveraging_style":"adaptive"},"summary":"Penny-stock gambler whose defining move is that they reframes every problem as an excuse to learn a new system. Feels the weight of a decision lighten the moment someone else co-signs it. Hedges every commitment against an imagined worst case. When the downside gets concrete, gains confidence in a position in proportion to how many others hold it; checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"recency","strength":0.6},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","risk"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.75,"conscientiousness":0.4,"extraversion":0.73,"agreeableness":0.74,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','risk']::text[], 'Penny-stock gambler whose defining move is that they reframes every problem as an excuse to learn a new system. Feels the weight of a decision lighten the moment someone else co-signs it. Hedges every commitment against an imagined worst case. When the downside gets concrete, gains confidence in a position in proportion to how many others hold it; checks the P&L blotter forty times before lunch.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('68427f75-a350-4483-bf0a-aa1b28798600', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.44,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.41,"narcissism":0.49,"psychopathy":0.32},"prospect_theory":{"lambda":1.76,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.42,"max_leverage_comfort":0.41,"deleveraging_style":"adaptive"},"summary":"A measured discretionary swing trader who thinks out loud and recruits an audience for every decision. Knows the answer before it can explain the question. When the number turns red gains confidence in a position in proportion to how many others hold it; when the stakes are trivial, holds a bag from 2021 out of pure spite.","decision_style":"intuitive","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.53},{"slug":"bandwagon","strength":0.56},{"slug":"fomo","strength":0.49},{"slug":"herd-behavior","strength":0.55}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","cognition"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.59,"conscientiousness":0.44,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.57}'::jsonb, 'ENFP', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','cognition']::text[], 'A measured discretionary swing trader who thinks out loud and recruits an audience for every decision. Knows the answer before it can explain the question. When the number turns red gains confidence in a position in proportion to how many others hold it; when the stakes are trivial, holds a bag from 2021 out of pure spite.', 0.83, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('834e39fd-7abf-40fe-9d4b-1212971e3110', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.25,"extraversion":0.88,"agreeableness":0.42,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.49,"narcissism":0.73,"psychopathy":0.44},"prospect_theory":{"lambda":0.93,"alpha":0.79,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.51,"max_leverage_comfort":0.59,"deleveraging_style":"adaptive"},"summary":"Treats being left out of a move as its own kind of loss. A pronounced MEV searcher: dominates the room then wonders why others stayed quiet, treats a plan as a suggestion the moment it is made. Decides in the time it takes to say the decision out loud, and when the stakes are trivial keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.84},{"slug":"dunning-kruger","strength":0.79}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.86,"conscientiousness":0.25,"extraversion":0.88,"agreeableness":0.42,"neuroticism":0.79}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Treats being left out of a move as its own kind of loss. A pronounced MEV searcher: dominates the room then wonders why others stayed quiet, treats a plan as a suggestion the moment it is made. Decides in the time it takes to say the decision out loud, and when the stakes are trivial keeps a losing-trade journal they never re-read.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('27889017-8957-421f-8fca-6664f810d7cd', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.29,"extraversion":0.73,"agreeableness":0.26,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.6,"narcissism":0.65,"psychopathy":0.61},"prospect_theory":{"lambda":1.27,"alpha":0.74,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.54,"max_leverage_comfort":0.48,"deleveraging_style":"adaptive"},"summary":"A steady MEV searcher who hedges every commitment against an imagined worst case. Commits before the doubt has time to organize itself. Negotiates every relationship a little, even the close ones. The moment it stops being hypothetical cannot watch a rally from the sidelines for long; in the small things, screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.69},{"slug":"fomo","strength":0.72},{"slug":"airdrop-entitlement","strength":0.71}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","anxious","risk"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.71,"conscientiousness":0.29,"extraversion":0.73,"agreeableness":0.26,"neuroticism":0.82}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','anxious','risk']::text[], 'A steady MEV searcher who hedges every commitment against an imagined worst case. Commits before the doubt has time to organize itself. Negotiates every relationship a little, even the close ones. The moment it stops being hypothetical cannot watch a rally from the sidelines for long; in the small things, screenshots the winners and never the losers.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
