('91f7faa0-d7c1-464c-a246-2e2b9a43c67c', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.87,"extraversion":0.37,"agreeableness":0.53,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.57,"narcissism":0.41,"psychopathy":0.32},"prospect_theory":{"lambda":1.99,"alpha":0.9,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.8,"liquidation_anxiety":0.24,"max_leverage_comfort":0.41,"deleveraging_style":"disciplined"},"summary":"Treats speed and recklessness as the same thing. This liquidation-bot operator maintains flawless records nobody asked for and weighs words carefully before spending them. The moment it stops being hypothetical treats past peak valuation as guaranteed future recovery — across an ordinary week, apes the launch before the contract is verified.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.65},{"slug":"overconfidence","strength":0.57},{"slug":"anchoring","strength":0.59}],"tags":["trading","deliberative","robinhood","retail-trading","swing-trader","risk-managed","disciplined","temperament"],"archetype":"rh-disciplined-swing"}'::jsonb, '{"openness":0.56,"conscientiousness":0.87,"extraversion":0.37,"agreeableness":0.53,"neuroticism":0.39}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','swing-trader','risk-managed','disciplined','temperament']::text[], 'Treats speed and recklessness as the same thing. This liquidation-bot operator maintains flawless records nobody asked for and weighs words carefully before spending them. The moment it stops being hypothetical treats past peak valuation as guaranteed future recovery — across an ordinary week, apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
