('5361ce4f-4e88-428b-8bcf-270999233324', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.65,"extraversion":0.46,"agreeableness":0.52,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.46,"narcissism":0.43,"psychopathy":0.35},"prospect_theory":{"lambda":3.07,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.59,"liquidation_anxiety":0.47,"max_leverage_comfort":0.29,"deleveraging_style":"adaptive"},"summary":"A measured dividend-yield chaser who over-prepares to the point of diminishing returns. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Moves on from a mistake faster than the people around them do. Once the exit narrows to one door rewrites its own uncertainty out of the story after the fact; in the parts nobody grades, exits winners at the first green candle.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"optimism","strength":0.49},{"slug":"overconfidence","strength":0.5},{"slug":"anchoring","strength":0.48},{"slug":"hindsight","strength":0.57}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","cognition"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.55,"conscientiousness":0.65,"extraversion":0.46,"agreeableness":0.52,"neuroticism":0.35}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','cognition']::text[], 'A measured dividend-yield chaser who over-prepares to the point of diminishing returns. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Moves on from a mistake faster than the people around them do. Once the exit narrows to one door rewrites its own uncertainty out of the story after the fact; in the parts nobody grades, exits winners at the first green candle.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('830ae8d6-eec3-43f9-a2d7-d2b2c51e5924', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.72,"extraversion":0.48,"agreeableness":0.71,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.5,"narcissism":0.41,"psychopathy":0.41},"prospect_theory":{"lambda":3,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.64,"liquidation_anxiety":0.43,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"Overvalues whatever they already hold simply because it is theirs. A steady liquidation-bot operator: cannot relax until the checklist is visibly complete, reads other people''s discomfort before they voice it. Keeps deliberating past the point where more information would change anything, and when the stakes are trivial averages down on a name three times in a week.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"ath-anchoring","strength":0.53},{"slug":"authority-bias","strength":0.51}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","decision-making"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.47,"conscientiousness":0.72,"extraversion":0.48,"agreeableness":0.71,"neuroticism":0.35}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','decision-making']::text[], 'Overvalues whatever they already hold simply because it is theirs. A steady liquidation-bot operator: cannot relax until the checklist is visibly complete, reads other people''s discomfort before they voice it. Keeps deliberating past the point where more information would change anything, and when the stakes are trivial averages down on a name three times in a week.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('61db9bad-33ba-4f46-b844-f554cee43764', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.38,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.32,"narcissism":0.63,"psychopathy":0.29},"prospect_theory":{"lambda":1.49,"alpha":0.87,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.52,"max_leverage_comfort":0.5,"deleveraging_style":"adaptive"},"summary":"When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady MEV searcher who dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right, and in the unglamorous middle of things talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","risk"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.75,"conscientiousness":0.38,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.68}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','risk']::text[], 'When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady MEV searcher who dominates the room then wonders why others stayed quiet and chases novel frameworks and abandons them once the novelty fades. Needs the room''s approval more than it needs to be right, and in the unglamorous middle of things talks in win rate and never mentions size.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('742bf99a-e72b-4aa9-bf75-b59984d62d00', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.39,"extraversion":0.68,"agreeableness":0.53,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.42,"narcissism":0.54,"psychopathy":0.31},"prospect_theory":{"lambda":3.06,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.6,"max_leverage_comfort":0.4,"deleveraging_style":"adaptive"},"summary":"Once the exit narrows to one door, discounts the older pattern in favor of whatever just happened. Otherwise, a steady futures spreader who reads outside the field for ideas the field itself would reject and draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and across the quiet stretches refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"dunning-kruger","strength":0.62},{"slug":"bandwagon","strength":0.52},{"slug":"recency","strength":0.66}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","risk"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.74,"conscientiousness":0.39,"extraversion":0.68,"agreeableness":0.53,"neuroticism":0.58}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','risk']::text[], 'Once the exit narrows to one door, discounts the older pattern in favor of whatever just happened. Otherwise, a steady futures spreader who reads outside the field for ideas the field itself would reject and draws energy from the crowd and wilts when working alone. Trusts the group''s confidence more than its own, and across the quiet stretches refreshes the order book compulsively during lunch.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('3001f0ce-4015-4fad-938e-24acf25268a8', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.68,"extraversion":0.44,"agreeableness":0.62,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.44,"narcissism":0.38,"psychopathy":0.35},"prospect_theory":{"lambda":3.04,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.53,"liquidation_anxiety":0.39,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"A steady quant researcher who builds in buffer time and then fills the buffer with more work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Absorbs conflict to keep the peace, often at their own cost. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about; when no one is watching, keeps three monitors for a portfolio that fits on one screen.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"optimism","strength":0.48},{"slug":"hindsight","strength":0.46},{"slug":"authority-bias","strength":0.48},{"slug":"ath-anchoring","strength":0.48}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","behavioral"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.48,"conscientiousness":0.68,"extraversion":0.44,"agreeableness":0.62,"neuroticism":0.38}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','behavioral']::text[], 'A steady quant researcher who builds in buffer time and then fills the buffer with more work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Absorbs conflict to keep the peace, often at their own cost. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about; when no one is watching, keeps three monitors for a portfolio that fits on one screen.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
