('48806b46-c713-4379-a065-0dc981b53394', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.31,"extraversion":0.92,"agreeableness":0.27,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.61,"narcissism":0.85,"psychopathy":0.57},"prospect_theory":{"lambda":0.94,"alpha":0.82,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.49,"max_leverage_comfort":0.53,"deleveraging_style":"adaptive"},"summary":"A pronounced retail momentum chaser who draws energy from the crowd and wilts when working alone. Commits on impulse and lives loudly with the consequences. Says the blunt thing and enjoys the flinch. As soon as real money or reputation is on the line treats being left out of a move as its own kind of loss; day to day, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"recency","strength":0.65},{"slug":"herd-behavior","strength":0.67},{"slug":"fomo","strength":0.84}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.78,"conscientiousness":0.31,"extraversion":0.92,"agreeableness":0.27,"neuroticism":0.75}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'A pronounced retail momentum chaser who draws energy from the crowd and wilts when working alone. Commits on impulse and lives loudly with the consequences. Says the blunt thing and enjoys the flinch. As soon as real money or reputation is on the line treats being left out of a move as its own kind of loss; day to day, backtests for months but front-runs the model on impulse.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('db34f16b-c1de-4b78-8849-fa98ec152bac', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.24,"extraversion":0.88,"agreeableness":0.31,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.57,"narcissism":0.81,"psychopathy":0.57},"prospect_theory":{"lambda":0.84,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.5,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"In a pinch, treats being left out of a move as its own kind of loss. Otherwise, a pronounced dividend-yield chaser who treats a quiet room as a problem to be solved and is reliably surprised by deadlines that were never hidden. Acts on the midnight epiphany and emails it at 1am, and without an audience exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.71},{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.76}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.81,"conscientiousness":0.24,"extraversion":0.88,"agreeableness":0.31,"neuroticism":0.77}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'In a pinch, treats being left out of a move as its own kind of loss. Otherwise, a pronounced dividend-yield chaser who treats a quiet room as a problem to be solved and is reliably surprised by deadlines that were never hidden. Acts on the midnight epiphany and emails it at 1am, and without an audience exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6f670a21-fa45-4f57-be10-a35757f2b583', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.84,"extraversion":0.41,"agreeableness":0.55,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.52,"narcissism":0.41,"psychopathy":0.34},"prospect_theory":{"lambda":2.44,"alpha":0.94,"beta":0.81},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.71,"liquidation_anxiety":0.28,"max_leverage_comfort":0.32,"deleveraging_style":"disciplined"},"summary":"Delta-neutral market maker whose defining move is that they front-loads the work and double-checks it twice. Keeps deliberating past the point where more information would change anything. The instant it becomes irreversible, refuses to exit positions until price returns to the previous cycle peak; screenshots the winners and never the losers.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"hindsight","strength":0.57},{"slug":"overconfidence","strength":0.45},{"slug":"ath-anchoring","strength":0.63},{"slug":"optimism","strength":0.53}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","temperament"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.49,"conscientiousness":0.84,"extraversion":0.41,"agreeableness":0.55,"neuroticism":0.42}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','temperament']::text[], 'Delta-neutral market maker whose defining move is that they front-loads the work and double-checks it twice. Keeps deliberating past the point where more information would change anything. The instant it becomes irreversible, refuses to exit positions until price returns to the previous cycle peak; screenshots the winners and never the losers.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b37c103a-4d1a-4a07-b3d8-21eb3bf66def', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.3,"extraversion":0.74,"agreeableness":0.79,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.36,"narcissism":0.55,"psychopathy":0.4},"prospect_theory":{"lambda":2.79,"alpha":0.83,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.65,"max_leverage_comfort":0.4,"deleveraging_style":"adaptive"},"summary":"Abandons a private read the instant the crowd leans the other way. A steady macro allocator: collects half-finished manifestos and unconventional methods, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and when the stakes are trivial apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.75},{"slug":"bandwagon","strength":0.68},{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.71}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","cognition"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.8,"conscientiousness":0.3,"extraversion":0.74,"agreeableness":0.79,"neuroticism":0.69}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','cognition']::text[], 'Abandons a private read the instant the crowd leans the other way. A steady macro allocator: collects half-finished manifestos and unconventional methods, absorbs conflict to keep the peace, often at their own cost. Trusts the group''s confidence more than its own, and when the stakes are trivial apes the launch before the contract is verified.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4a5c720e-5ab5-42dc-894a-1862cd959017', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.69,"extraversion":0.46,"agreeableness":0.65,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.46,"narcissism":0.38,"psychopathy":0.3},"prospect_theory":{"lambda":2.75,"alpha":0.9,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.6,"liquidation_anxiety":0.48,"max_leverage_comfort":0.36,"deleveraging_style":"disciplined"},"summary":"Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady algorithmic market-maker who over-prepares to the point of diminishing returns and would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.55},{"slug":"ath-anchoring","strength":0.55},{"slug":"endowment","strength":0.54}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.69,"extraversion":0.46,"agreeableness":0.65,"neuroticism":0.55}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady algorithmic market-maker who over-prepares to the point of diminishing returns and would rather lose a point than win an argument badly. Circles back to ask what someone else would do even after deciding, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('415b1fd9-e883-48ea-a36d-cf2fed83ac49', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.37,"extraversion":0.48,"agreeableness":0.63,"neuroticism":0.91},"dark_triad":{"machiavellianism":0.39,"narcissism":0.2,"psychopathy":0.3},"prospect_theory":{"lambda":3.64,"alpha":0.72,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.89,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Would rather not know yet, even when knowing sooner would help. A pronounced MEV searcher: notices the one thing that could go wrong before the nine that could go right, defaults to trust and gives the benefit of the doubt too freely. Finds one more piece of information to gather before acting, and when the pressure is off apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.79},{"slug":"loss-aversion","strength":0.67},{"slug":"rug-trauma-overcorrection","strength":0.68},{"slug":"diamond-hands-identity","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","temperament"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.51,"conscientiousness":0.37,"extraversion":0.48,"agreeableness":0.63,"neuroticism":0.91}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','temperament']::text[], 'Would rather not know yet, even when knowing sooner would help. A pronounced MEV searcher: notices the one thing that could go wrong before the nine that could go right, defaults to trust and gives the benefit of the doubt too freely. Finds one more piece of information to gather before acting, and when the pressure is off apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('39073642-6f0a-4705-a163-c7c6d8e92b7e', 1, '{"big_five":{"openness":0.39,"conscientiousness":0.67,"extraversion":0.45,"agreeableness":0.66,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.48,"narcissism":0.38,"psychopathy":0.35},"prospect_theory":{"lambda":2.98,"alpha":0.93,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.6,"liquidation_anxiety":0.41,"max_leverage_comfort":0.34,"deleveraging_style":"disciplined"},"summary":"Onchain copy-trader, steady in style: treats a missed deadline as a personal failure regardless of cause; defaults to trust and gives the benefit of the doubt too freely. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Once things get tense holds their estimates with a certainty the track record does not support.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"optimism","strength":0.5},{"slug":"anchoring","strength":0.51},{"slug":"ath-anchoring","strength":0.55},{"slug":"overconfidence","strength":0.57}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","temperament"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.39,"conscientiousness":0.67,"extraversion":0.45,"agreeableness":0.66,"neuroticism":0.34}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','temperament']::text[], 'Onchain copy-trader, steady in style: treats a missed deadline as a personal failure regardless of cause; defaults to trust and gives the benefit of the doubt too freely. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Once things get tense holds their estimates with a certainty the track record does not support.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('3c0c1731-7125-4c05-bcf5-96a5b3bbb79f', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.3,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.42,"narcissism":0.35,"psychopathy":0.34},"prospect_theory":{"lambda":3.57,"alpha":0.78,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.82,"max_leverage_comfort":0.16,"deleveraging_style":"panic"},"summary":"Lets the deadline make the decision by default. This airdrop farmer rehearses catastrophes in vivid detail before they happen and does the interesting 80% and abandons the tedious 20%. The moment risk appears sells the winners early and clings to the losers for far too long — on an ordinary week, confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"recency","strength":0.64},{"slug":"gas-sunk-cost","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.59,"conscientiousness":0.3,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.81}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Lets the deadline make the decision by default. This airdrop farmer rehearses catastrophes in vivid detail before they happen and does the interesting 80% and abandons the tedious 20%. The moment risk appears sells the winners early and clings to the losers for far too long — on an ordinary week, confuses a bull market for a trading edge.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('91b9283e-2480-411b-9c9b-f4e4e683dc4a', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.55,"extraversion":0.64,"agreeableness":0.46,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.47,"narcissism":0.52,"psychopathy":0.3},"prospect_theory":{"lambda":1.68,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.39,"max_leverage_comfort":0.47,"deleveraging_style":"adaptive"},"summary":"A measured index-fund holdout who recharges by being around people, not away from them. Knows the answer before it can explain the question. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; in the parts nobody grades, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.51},{"slug":"optimism","strength":0.53},{"slug":"bandwagon","strength":0.57}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","risk"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.55,"extraversion":0.64,"agreeableness":0.46,"neuroticism":0.5}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','risk']::text[], 'A measured index-fund holdout who recharges by being around people, not away from them. Knows the answer before it can explain the question. The moment it stops being hypothetical gains confidence in a position in proportion to how many others hold it; in the parts nobody grades, apes the launch before the contract is verified.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('2c47251e-33bd-4420-9011-f5185e09879a', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.57,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.37,"narcissism":0.33,"psychopathy":0.32},"prospect_theory":{"lambda":3.46,"alpha":0.81,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.81,"max_leverage_comfort":0.18,"deleveraging_style":"panic"},"summary":"When there is no clean exit, treats non-refundable network fees as active position cost basis. Otherwise, a steady airdrop farmer who spirals on ambiguity and mistakes the spiral for diligence and starts strong and lets follow-through evaporate. Keeps every door open long after most of them should be closed, and day to day sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.66},{"slug":"disposition-effect","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.57,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'When there is no clean exit, treats non-refundable network fees as active position cost basis. Otherwise, a steady airdrop farmer who spirals on ambiguity and mistakes the spiral for diligence and starts strong and lets follow-through evaporate. Keeps every door open long after most of them should be closed, and day to day sizes every position at exactly 2% risk.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('fb48980e-5e3f-4ac7-80a9-7d17130294ae', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.28,"extraversion":0.91,"agreeableness":0.32,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.6,"narcissism":0.82,"psychopathy":0.54},"prospect_theory":{"lambda":0.79,"alpha":0.79,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.44,"max_leverage_comfort":0.73,"deleveraging_style":"adaptive"},"summary":"Futures spreader, pronounced in style: thinks out loud and recruits an audience for every decision; confuses motion with progress. Acts on the midnight epiphany and emails it at 1am. When cornered mistakes a little fluency for real mastery.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.76},{"slug":"dunning-kruger","strength":0.8}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.84,"conscientiousness":0.28,"extraversion":0.91,"agreeableness":0.32,"neuroticism":0.68}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Futures spreader, pronounced in style: thinks out loud and recruits an audience for every decision; confuses motion with progress. Acts on the midnight epiphany and emails it at 1am. When cornered mistakes a little fluency for real mastery.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('cd9cee59-d2d2-476e-98a8-f69841c22eb7', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.35,"extraversion":0.58,"agreeableness":0.44,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.49,"narcissism":0.43,"psychopathy":0.37},"prospect_theory":{"lambda":1.65,"alpha":0.76,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.58,"max_leverage_comfort":0.42,"deleveraging_style":"adaptive"},"summary":"Commodities speculator whose defining move is that they reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting. Is reliably surprised by deadlines that were never hidden. The moment risk appears, delays checking the number it most needs to check; names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.62},{"slug":"gas-sunk-cost","strength":0.58},{"slug":"ostrich-effect","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","decision-making"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.66,"conscientiousness":0.35,"extraversion":0.58,"agreeableness":0.44,"neuroticism":0.75}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','decision-making']::text[], 'Commodities speculator whose defining move is that they reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting. Is reliably surprised by deadlines that were never hidden. The moment risk appears, delays checking the number it most needs to check; names every strategy after the trade that almost worked.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('ccc1ecb8-123f-4a12-8d08-6e1035b4613e', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.68,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.34},"prospect_theory":{"lambda":1.02,"alpha":0.81,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.29,"liquidation_anxiety":0.42,"max_leverage_comfort":0.5,"deleveraging_style":"adaptive"},"summary":"In a pinch, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced quant researcher who draws energy from the crowd and wilts when working alone and reframes every problem as an excuse to learn a new system. Decides in the time it takes to say the decision out loud, and across the quiet stretches keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.75},{"slug":"bandwagon","strength":0.66}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.64,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.68,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'In a pinch, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced quant researcher who draws energy from the crowd and wilts when working alone and reframes every problem as an excuse to learn a new system. Decides in the time it takes to say the decision out loud, and across the quiet stretches keeps a losing-trade journal they never re-read.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
