('fe46f7d4-6dfc-48ad-ac2e-22881200a50c', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.24,"extraversion":0.79,"agreeableness":0.32,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.53,"narcissism":0.71,"psychopathy":0.55},"prospect_theory":{"lambda":0.77,"alpha":0.81,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.45,"max_leverage_comfort":0.71,"deleveraging_style":"adaptive"},"summary":"A steady quant researcher who collects half-finished manifestos and unconventional methods. Trusts momentum over preparation. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up is most certain precisely where their competence is thinnest; in the version no one reviews, exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"dunning-kruger","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","open-minded"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.83,"conscientiousness":0.24,"extraversion":0.79,"agreeableness":0.32,"neuroticism":0.69}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','open-minded']::text[], 'A steady quant researcher who collects half-finished manifestos and unconventional methods. Trusts momentum over preparation. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up is most certain precisely where their competence is thinnest; in the version no one reviews, exits winners at the first green candle.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('ea1ef59c-b7b6-44b8-8ab7-72f5f182d4e0', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.55,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.42,"narcissism":0.64,"psychopathy":0.37},"prospect_theory":{"lambda":0.93,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.45,"max_leverage_comfort":0.65,"deleveraging_style":"adaptive"},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady commodities speculator: gets bored of the proven method exactly when it starts working, needs repeated reassurance that a decision was the right one. Commits before the doubt has time to organize itself, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.79,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.55,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady commodities speculator: gets bored of the proven method exactly when it starts working, needs repeated reassurance that a decision was the right one. Commits before the doubt has time to organize itself, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
