('d25edde5-979f-4463-b84f-298a10049b28', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.86,"extraversion":0.43,"agreeableness":0.61,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.58,"narcissism":0.39,"psychopathy":0.32},"prospect_theory":{"lambda":2.21,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.32,"max_leverage_comfort":0.47,"deleveraging_style":"disciplined"},"summary":"The moment risk appears, is surprised in the moment and certain in the retelling. Otherwise, a pronounced commodities speculator who front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. Treats a rushed decision as a defect regardless of outcome, and across an ordinary week apes the launch before the contract is verified.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"hindsight","strength":0.54},{"slug":"anchoring","strength":0.51},{"slug":"recency","strength":0.47}],"tags":["trading","deliberative","robinhood","retail-trading","swing-trader","risk-managed","disciplined","cognition"],"archetype":"rh-disciplined-swing"}'::jsonb, '{"openness":0.65,"conscientiousness":0.86,"extraversion":0.43,"agreeableness":0.61,"neuroticism":0.43}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','swing-trader','risk-managed','disciplined','cognition']::text[], 'The moment risk appears, is surprised in the moment and certain in the retelling. Otherwise, a pronounced commodities speculator who front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. Treats a rushed decision as a defect regardless of outcome, and across an ordinary week apes the launch before the contract is verified.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('83605d3a-43dc-42f5-acb8-19516ed605d1', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.33,"extraversion":0.65,"agreeableness":0.43,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.48,"narcissism":0.45,"psychopathy":0.39},"prospect_theory":{"lambda":3.67,"alpha":0.81,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.37,"liquidation_anxiety":0.82,"max_leverage_comfort":0.06,"deleveraging_style":"panic"},"summary":"Liquidation-bot operator whose defining move is that they needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Is reliably surprised by deadlines that were never hidden. In a pinch, doubles down on stagnant liquidity pools to justify the initial deployment gas; exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"rug-trauma-overcorrection","strength":0.63},{"slug":"gas-sunk-cost","strength":0.71},{"slug":"disposition-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.33,"extraversion":0.65,"agreeableness":0.43,"neuroticism":0.84}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Liquidation-bot operator whose defining move is that they needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Is reliably surprised by deadlines that were never hidden. In a pinch, doubles down on stagnant liquidity pools to justify the initial deployment gas; exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('51022f87-61c2-4c49-aa64-6e9c538f7b40', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.37,"extraversion":0.85,"agreeableness":0.35,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.52,"narcissism":0.73,"psychopathy":0.43},"prospect_theory":{"lambda":0.74,"alpha":0.78,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.48,"max_leverage_comfort":0.66,"deleveraging_style":"adaptive"},"summary":"Treats hesitation as the bigger risk. This algorithmic market-maker dominates the room then wonders why others stayed quiet and starts strong and lets follow-through evaporate. When the stakes rise treats being left out of a move as its own kind of loss — across the quiet stretches, talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.61},{"slug":"recency","strength":0.71},{"slug":"fomo","strength":0.78}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.84,"conscientiousness":0.37,"extraversion":0.85,"agreeableness":0.35,"neuroticism":0.7}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Treats hesitation as the bigger risk. This algorithmic market-maker dominates the room then wonders why others stayed quiet and starts strong and lets follow-through evaporate. When the stakes rise treats being left out of a move as its own kind of loss — across the quiet stretches, talks in win rate and never mentions size.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d6439f30-2433-49af-b034-621ba9544a48', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.26,"extraversion":0.73,"agreeableness":0.24,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.66,"narcissism":0.67,"psychopathy":0.57},"prospect_theory":{"lambda":1.11,"alpha":0.76,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.59,"max_leverage_comfort":0.61,"deleveraging_style":"adaptive"},"summary":"DeFi yield farmer whose defining move is that they reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, sees malicious intent and exploit risk in every standard smart contract update; apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.8},{"slug":"fomo","strength":0.69},{"slug":"airdrop-entitlement","strength":0.71},{"slug":"recency","strength":0.73}],"tags":["trading","spontaneous","robinhood","retail-trading","revenge-trading","tilt","open-minded","cognition"],"archetype":"rh-revenge-trader"}'::jsonb, '{"openness":0.83,"conscientiousness":0.26,"extraversion":0.73,"agreeableness":0.24,"neuroticism":0.82}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','revenge-trading','tilt','open-minded','cognition']::text[], 'DeFi yield farmer whose defining move is that they reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am. Narrates the plan to whoever is nearby before committing to it. As soon as real money or reputation is on the line, sees malicious intent and exploit risk in every standard smart contract update; apes the launch before the contract is verified.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('cb8c046f-a67f-4200-b9d6-c1f4ba8774fd', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.26,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.65,"narcissism":0.88,"psychopathy":0.55},"prospect_theory":{"lambda":0.87,"alpha":0.82,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.32,"max_leverage_comfort":0.72,"deleveraging_style":"adaptive"},"summary":"In a pinch, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and treats a plan as a suggestion the moment it is made. Prefers a fast wrong answer to a slow right one, and without an audience backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"fomo","strength":0.73},{"slug":"herd-behavior","strength":0.63}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.81,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.26,"neuroticism":0.54}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'In a pinch, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and treats a plan as a suggestion the moment it is made. Prefers a fast wrong answer to a slow right one, and without an audience backtests for months but front-runs the model on impulse.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('542ce05d-5547-4599-b7d5-44b569144072', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.91,"extraversion":0.51,"agreeableness":0.6,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.54,"narcissism":0.39,"psychopathy":0.43},"prospect_theory":{"lambda":2.12,"alpha":0.95,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.84,"liquidation_anxiety":0.28,"max_leverage_comfort":0.34,"deleveraging_style":"disciplined"},"summary":"A pronounced meme-coin rotator who treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Treats setbacks as data rather than verdicts. When the walls close in assumes the bad statistic applies to other people; in the small things, checks the P&L blotter forty times before lunch.","decision_style":"deliberative","mbti_label":"ENFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"overconfidence","strength":0.62},{"slug":"optimism","strength":0.64}],"tags":["trading","deliberative","robinhood","retail-trading","swing-trader","risk-managed","disciplined","decision-making"],"archetype":"rh-disciplined-swing"}'::jsonb, '{"openness":0.5,"conscientiousness":0.91,"extraversion":0.51,"agreeableness":0.6,"neuroticism":0.28}'::jsonb, 'ENFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','swing-trader','risk-managed','disciplined','decision-making']::text[], 'A pronounced meme-coin rotator who treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Treats setbacks as data rather than verdicts. When the walls close in assumes the bad statistic applies to other people; in the small things, checks the P&L blotter forty times before lunch.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b7e55c6c-b864-462b-94e1-9b7858b5b881', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.28,"extraversion":0.39,"agreeableness":0.68,"neuroticism":0.94},"dark_triad":{"machiavellianism":0.4,"narcissism":0.21,"psychopathy":0.39},"prospect_theory":{"lambda":3.64,"alpha":0.76,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.45,"liquidation_anxiety":0.95,"max_leverage_comfort":0.06,"deleveraging_style":"panic"},"summary":"Bonding-curve sniper, pronounced in style: carries yesterday''s stress into today''s unrelated decision; improvises past every deadline and calls it flexibility. Finds one more piece of information to gather before acting. The moment it stops being hypothetical delays checking the number it most needs to check.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.74},{"slug":"ostrich-effect","strength":0.76}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.28,"extraversion":0.39,"agreeableness":0.68,"neuroticism":0.94}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'Bonding-curve sniper, pronounced in style: carries yesterday''s stress into today''s unrelated decision; improvises past every deadline and calls it flexibility. Finds one more piece of information to gather before acting. The moment it stops being hypothetical delays checking the number it most needs to check.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('1f1a24e8-d829-481c-a6bb-1644eb79cab5', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.71,"extraversion":0.42,"agreeableness":0.61,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.47,"narcissism":0.41,"psychopathy":0.34},"prospect_theory":{"lambda":2.41,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.58,"liquidation_anxiety":0.32,"max_leverage_comfort":0.44,"deleveraging_style":"disciplined"},"summary":"When the walls close in, overvalues whatever they already hold simply because it is theirs. Otherwise, a steady delta-neutral market maker who plans in exhaustive detail and resents any deviation. Revisits a settled decision if a single new fact appears, and in the pattern nobody else tracks keeps three monitors for a portfolio that fits on one screen.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"anchoring","strength":0.52},{"slug":"ath-anchoring","strength":0.53},{"slug":"endowment","strength":0.54}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","cognition"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.54,"conscientiousness":0.71,"extraversion":0.42,"agreeableness":0.61,"neuroticism":0.43}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','cognition']::text[], 'When the walls close in, overvalues whatever they already hold simply because it is theirs. Otherwise, a steady delta-neutral market maker who plans in exhaustive detail and resents any deviation. Revisits a settled decision if a single new fact appears, and in the pattern nobody else tracks keeps three monitors for a portfolio that fits on one screen.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
