('31663c2a-7b41-4cfc-83ee-b697c28d5809', 1, '{"big_five":{"openness":0.45,"conscientiousness":0.31,"extraversion":0.68,"agreeableness":0.62,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.38,"narcissism":0.49,"psychopathy":0.39},"prospect_theory":{"lambda":3.41,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.67,"max_leverage_comfort":0.12,"deleveraging_style":"adaptive"},"summary":"Is most certain precisely where their competence is thinnest. A steady perps degen: starts strong and lets follow-through evaporate, notices the one thing that could go wrong before the nine that could go right. Buries hard calls under a pile of preparatory busywork, and without an audience names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"dunning-kruger","strength":0.7},{"slug":"gas-sunk-cost","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","improviser"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.45,"conscientiousness":0.31,"extraversion":0.68,"agreeableness":0.62,"neuroticism":0.69}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','improviser']::text[], 'Is most certain precisely where their competence is thinnest. A steady perps degen: starts strong and lets follow-through evaporate, notices the one thing that could go wrong before the nine that could go right. Buries hard calls under a pile of preparatory busywork, and without an audience names every strategy after the trade that almost worked.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d8e2d7be-f15c-44b8-91eb-0fc2006ffba9', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.52,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.42,"narcissism":0.49,"psychopathy":0.31},"prospect_theory":{"lambda":1.64,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.4,"liquidation_anxiety":0.43,"max_leverage_comfort":0.48,"deleveraging_style":"adaptive"},"summary":"When the number turns red, jumps into whatever everyone else already seems to be winning at. Otherwise, a measured options seller who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Treats overthinking as its own kind of error, and in the unglamorous middle of things screenshots the winners and never the losers.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"herd-behavior","strength":0.58}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","cognition"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.62,"conscientiousness":0.56,"extraversion":0.64,"agreeableness":0.52,"neuroticism":0.59}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','cognition']::text[], 'When the number turns red, jumps into whatever everyone else already seems to be winning at. Otherwise, a measured options seller who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Treats overthinking as its own kind of error, and in the unglamorous middle of things screenshots the winners and never the losers.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('de4eb3cf-7bb6-4f66-ae08-5d7ce2bd78bd', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.77,"extraversion":0.34,"agreeableness":0.56,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.49,"narcissism":0.43,"psychopathy":0.36},"prospect_theory":{"lambda":2.24,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.67,"liquidation_anxiety":0.28,"max_leverage_comfort":0.42,"deleveraging_style":"disciplined"},"summary":"Delta-neutral market maker, steady in style: cannot relax until the checklist is visibly complete; guards their energy and rations social exposure. Keeps deliberating past the point where more information would change anything. Once the exit narrows to one door prices every token against its all-time high, viewing current levels as an automatic discount.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"optimism","strength":0.49},{"slug":"anchoring","strength":0.51},{"slug":"ath-anchoring","strength":0.54},{"slug":"overconfidence","strength":0.49}],"tags":["trading","deliberative","robinhood","retail-trading","swing-trader","risk-managed","disciplined","behavioral"],"archetype":"rh-disciplined-swing"}'::jsonb, '{"openness":0.61,"conscientiousness":0.77,"extraversion":0.34,"agreeableness":0.56,"neuroticism":0.39}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','swing-trader','risk-managed','disciplined','behavioral']::text[], 'Delta-neutral market maker, steady in style: cannot relax until the checklist is visibly complete; guards their energy and rations social exposure. Keeps deliberating past the point where more information would change anything. Once the exit narrows to one door prices every token against its all-time high, viewing current levels as an automatic discount.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4ee94523-9033-4d8e-baf0-f18e4e241dfe', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.72,"extraversion":0.36,"agreeableness":0.61,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.52,"narcissism":0.39,"psychopathy":0.34},"prospect_theory":{"lambda":3.18,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.67,"liquidation_anxiety":0.45,"max_leverage_comfort":0.33,"deleveraging_style":"disciplined"},"summary":"When the downside gets concrete, refuses to exit positions until price returns to the previous cycle peak. Otherwise, a steady commodities speculator who front-loads the work and double-checks it twice and processes internally and surfaces conclusions fully formed. Keeps deliberating past the point where more information would change anything, and left to their own devices backtests for months but front-runs the model on impulse.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"authority-bias","strength":0.47},{"slug":"ath-anchoring","strength":0.56},{"slug":"hindsight","strength":0.49},{"slug":"endowment","strength":0.51}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","decision-making"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.49,"conscientiousness":0.72,"extraversion":0.36,"agreeableness":0.61,"neuroticism":0.41}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','decision-making']::text[], 'When the downside gets concrete, refuses to exit positions until price returns to the previous cycle peak. Otherwise, a steady commodities speculator who front-loads the work and double-checks it twice and processes internally and surfaces conclusions fully formed. Keeps deliberating past the point where more information would change anything, and left to their own devices backtests for months but front-runs the model on impulse.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('55663d85-8101-4e63-9d6c-4b1c0bf61c1e', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.81,"extraversion":0.39,"agreeableness":0.6,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.54,"narcissism":0.41,"psychopathy":0.42},"prospect_theory":{"lambda":2.66,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.67,"liquidation_anxiety":0.38,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"A steady liquidation-bot operator who plans in exhaustive detail and resents any deviation. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Sleeps fine the night before the big call. Under a deadline refuses to exit positions until price returns to the previous cycle peak; when the pressure is off, calls a 90% drawdown a long-term hold.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"ath-anchoring","strength":0.63}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","risk"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.48,"conscientiousness":0.81,"extraversion":0.39,"agreeableness":0.6,"neuroticism":0.27}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','risk']::text[], 'A steady liquidation-bot operator who plans in exhaustive detail and resents any deviation. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. Sleeps fine the night before the big call. Under a deadline refuses to exit positions until price returns to the previous cycle peak; when the pressure is off, calls a 90% drawdown a long-term hold.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a6654d58-3dba-438f-892c-12099717a3b6', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.53,"extraversion":0.42,"agreeableness":0.69,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.42,"narcissism":0.26,"psychopathy":0.28},"prospect_theory":{"lambda":3.96,"alpha":0.79,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.38,"liquidation_anxiety":0.83,"max_leverage_comfort":0.07,"deleveraging_style":"panic"},"summary":"Treats selling any portion of a position as a personal betrayal. A pronounced commodities speculator: carries yesterday''s stress into today''s unrelated decision, defaults to trust and gives the benefit of the doubt too freely. Finds one more piece of information to gather before acting, and in the parts nobody grades keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"INFJ","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.66},{"slug":"availability","strength":0.64},{"slug":"ostrich-effect","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","cognition"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.55,"conscientiousness":0.53,"extraversion":0.42,"agreeableness":0.69,"neuroticism":0.84}'::jsonb, 'INFJ', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','cognition']::text[], 'Treats selling any portion of a position as a personal betrayal. A pronounced commodities speculator: carries yesterday''s stress into today''s unrelated decision, defaults to trust and gives the benefit of the doubt too freely. Finds one more piece of information to gather before acting, and in the parts nobody grades keeps a losing-trade journal they never re-read.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('fda21398-2b22-424f-a78c-dcc9203e3374', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.74,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.39,"narcissism":0.39,"psychopathy":0.28},"prospect_theory":{"lambda":3.31,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.73,"max_leverage_comfort":0.22,"deleveraging_style":"panic"},"summary":"Under pressure, extrapolates the last data point into a permanent trend. Otherwise, a steady discretionary swing trader who absorbs conflict to keep the peace, often at their own cost and notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting, and once the urgency drains out sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"endowment","strength":0.6}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","accommodating"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.66,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.74,"neuroticism":0.73}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','accommodating']::text[], 'Under pressure, extrapolates the last data point into a permanent trend. Otherwise, a steady discretionary swing trader who absorbs conflict to keep the peace, often at their own cost and notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting, and once the urgency drains out sets stop-losses then cancels them at the open.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7dfc9ead-7713-4931-8479-2c4ee6e8c16f', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.24,"extraversion":0.82,"agreeableness":0.4,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.51,"narcissism":0.7,"psychopathy":0.49},"prospect_theory":{"lambda":0.73,"alpha":0.81,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.46,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Discretionary swing trader whose defining move is that they gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. Thinks out loud and recruits an audience for every decision. When the number turns red, looks away from bad news in the hope it resolves unwitnessed; sizes every position at exactly 2% risk.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.73},{"slug":"ostrich-effect","strength":0.75},{"slug":"dunning-kruger","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","open-minded"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.85,"conscientiousness":0.24,"extraversion":0.82,"agreeableness":0.4,"neuroticism":0.77}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','open-minded']::text[], 'Discretionary swing trader whose defining move is that they gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. Thinks out loud and recruits an audience for every decision. When the number turns red, looks away from bad news in the hope it resolves unwitnessed; sizes every position at exactly 2% risk.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('2da5e948-8dc2-43e3-8f5e-6054f7070e5e', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.73,"extraversion":0.43,"agreeableness":0.61,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.46,"narcissism":0.4,"psychopathy":0.33},"prospect_theory":{"lambda":3.06,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.66,"liquidation_anxiety":0.41,"max_leverage_comfort":0.26,"deleveraging_style":"disciplined"},"summary":"A steady commodities speculator who builds in buffer time and then fills the buffer with more work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. As soon as real money or reputation is on the line remembers every surprise as something they saw coming all along; on a slow afternoon, screenshots the winners and never the losers.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"hindsight","strength":0.6},{"slug":"overconfidence","strength":0.57},{"slug":"ath-anchoring","strength":0.52}],"tags":["trading","deliberative","robinhood","retail-trading","buy-and-hold","status-quo","disciplined","risk"],"archetype":"rh-conservative-hodler"}'::jsonb, '{"openness":0.48,"conscientiousness":0.73,"extraversion":0.43,"agreeableness":0.61,"neuroticism":0.39}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','buy-and-hold','status-quo','disciplined','risk']::text[], 'A steady commodities speculator who builds in buffer time and then fills the buffer with more work. Weighs every angle exhaustively and is uneasy the moment ambiguity remains. As soon as real money or reputation is on the line remembers every surprise as something they saw coming all along; on a slow afternoon, screenshots the winners and never the losers.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('506916c0-0e92-42e5-a699-da698055aa26', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.53,"extraversion":0.65,"agreeableness":0.51,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.41,"narcissism":0.48,"psychopathy":0.27},"prospect_theory":{"lambda":1.68,"alpha":0.84,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.48,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"Discretionary swing trader whose defining move is that they treats a quiet room as a problem to be solved. Knows the answer before it can explain the question. When the downside gets concrete, cannot watch a rally from the sidelines for long; keeps three monitors for a portfolio that fits on one screen.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.49},{"slug":"recency","strength":0.49},{"slug":"bandwagon","strength":0.57},{"slug":"fomo","strength":0.59}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","risk"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.59,"conscientiousness":0.53,"extraversion":0.65,"agreeableness":0.51,"neuroticism":0.6}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','risk']::text[], 'Discretionary swing trader whose defining move is that they treats a quiet room as a problem to be solved. Knows the answer before it can explain the question. When the downside gets concrete, cannot watch a rally from the sidelines for long; keeps three monitors for a portfolio that fits on one screen.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('456dd90c-06df-4e43-8fd1-72729ba5f063', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.26,"extraversion":0.66,"agreeableness":0.49,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.41},"prospect_theory":{"lambda":3.73,"alpha":0.77,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.85,"max_leverage_comfort":0.11,"deleveraging_style":"panic"},"summary":"The instant it becomes irreversible, sells the winners early and clings to the losers for far too long. Otherwise, a pronounced macro allocator who rehearses catastrophes in vivid detail before they happen and chases novel frameworks and abandons them once the novelty fades. Keeps every door open long after most of them should be closed, and without an audience sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.7},{"slug":"gas-sunk-cost","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.26,"extraversion":0.66,"agreeableness":0.49,"neuroticism":0.87}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'The instant it becomes irreversible, sells the winners early and clings to the losers for far too long. Otherwise, a pronounced macro allocator who rehearses catastrophes in vivid detail before they happen and chases novel frameworks and abandons them once the novelty fades. Keeps every door open long after most of them should be closed, and without an audience sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a09c06b0-c828-45b1-93b9-7a4812ba4ca6', 1, '{"big_five":{"openness":0.43,"conscientiousness":0.45,"extraversion":0.48,"agreeableness":0.55,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.43,"narcissism":0.28,"psychopathy":0.33},"prospect_theory":{"lambda":3.65,"alpha":0.75,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.83,"max_leverage_comfort":0.05,"deleveraging_style":"panic"},"summary":"Zero-DTE options gambler whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. When there is no clean exit, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ISFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.72},{"slug":"loss-aversion","strength":0.62},{"slug":"availability","strength":0.62},{"slug":"ostrich-effect","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","loss-averse","fomo","anxious","cognition"],"archetype":"rh-panic-seller"}'::jsonb, '{"openness":0.43,"conscientiousness":0.45,"extraversion":0.48,"agreeableness":0.55,"neuroticism":0.84}'::jsonb, 'ISFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','loss-averse','fomo','anxious','cognition']::text[], 'Zero-DTE options gambler whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. When there is no clean exit, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction; holds a bag from 2021 out of pure spite.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6cd2fce-f921-47b6-b7f0-98adf7ff927f', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.38,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.34,"narcissism":0.66,"psychopathy":0.32},"prospect_theory":{"lambda":1.44,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.36,"max_leverage_comfort":0.64,"deleveraging_style":"adaptive"},"summary":"When the walls close in, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady options seller who draws energy from the crowd and wilts when working alone and would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"dunning-kruger","strength":0.63},{"slug":"bandwagon","strength":0.73}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","cognition"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.77,"conscientiousness":0.38,"extraversion":0.8,"agreeableness":0.73,"neuroticism":0.51}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','cognition']::text[], 'When the walls close in, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady options seller who draws energy from the crowd and wilts when working alone and would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things averages down on a name three times in a week.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
