('3f1b3b84-0b59-4530-94b7-ce32867fb439', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.26,"extraversion":0.92,"agreeableness":0.4,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.53,"narcissism":0.76,"psychopathy":0.51},"prospect_theory":{"lambda":1.06,"alpha":0.81,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.21,"liquidation_anxiety":0.44,"max_leverage_comfort":0.67,"deleveraging_style":"adaptive"},"summary":"Volatility arbitrageur, pronounced in style: draws energy from the crowd and wilts when working alone; reads outside the field for ideas the field itself would reject. Decides in the time it takes to say the decision out loud. The moment it stops being hypothetical treats being left out of a move as its own kind of loss.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.76},{"slug":"dunning-kruger","strength":0.81},{"slug":"fomo","strength":0.84},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","spontaneous","robinhood","retail-trading","options-trader","zero-dte","fomo","outgoing"],"archetype":"rh-0dte-options-gambler"}'::jsonb, '{"openness":0.85,"conscientiousness":0.26,"extraversion":0.92,"agreeableness":0.4,"neuroticism":0.7}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','options-trader','zero-dte','fomo','outgoing']::text[], 'Volatility arbitrageur, pronounced in style: draws energy from the crowd and wilts when working alone; reads outside the field for ideas the field itself would reject. Decides in the time it takes to say the decision out loud. The moment it stops being hypothetical treats being left out of a move as its own kind of loss.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('41065922-a4c8-4ee2-bdcb-7743f0ef664c', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.46,"extraversion":0.73,"agreeableness":0.54,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.4,"narcissism":0.5,"psychopathy":0.28},"prospect_theory":{"lambda":3.61,"alpha":0.77,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.82,"max_leverage_comfort":0.2,"deleveraging_style":"panic"},"summary":"The moment it stops being hypothetical, would rather not know yet, even when knowing sooner would help. Otherwise, a steady bonding-curve sniper who needs repeated reassurance that a decision was the right one and thinks out loud and recruits an audience for every decision. Buries hard calls under a pile of preparatory busywork, and in the routine of it trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"fomo","strength":0.68},{"slug":"ostrich-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.64,"conscientiousness":0.46,"extraversion":0.73,"agreeableness":0.54,"neuroticism":0.82}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse']::text[], 'The moment it stops being hypothetical, would rather not know yet, even when knowing sooner would help. Otherwise, a steady bonding-curve sniper who needs repeated reassurance that a decision was the right one and thinks out loud and recruits an audience for every decision. Buries hard calls under a pile of preparatory busywork, and in the routine of it trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('40d246dc-4ca3-4b73-bf9d-2e59dafdf65a', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.68,"extraversion":0.56,"agreeableness":0.72,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.43,"narcissism":0.41,"psychopathy":0.31},"prospect_theory":{"lambda":3.01,"alpha":0.92,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.57,"liquidation_anxiety":0.47,"max_leverage_comfort":0.32,"deleveraging_style":"disciplined"},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This DeFi yield farmer takes on other people''s problems as if they were their own and treats a missed deadline as a personal failure regardless of cause. As soon as real money or reputation is on the line defers to the most senior voice even against their own evidence — left to their own devices, holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"endowment","strength":0.56},{"slug":"authority-bias","strength":0.6},{"slug":"herd-behavior","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.46,"conscientiousness":0.68,"extraversion":0.56,"agreeableness":0.72,"neuroticism":0.51}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This DeFi yield farmer takes on other people''s problems as if they were their own and treats a missed deadline as a personal failure regardless of cause. As soon as real money or reputation is on the line defers to the most senior voice even against their own evidence — left to their own devices, holds a bag from 2021 out of pure spite.', 0.93, 'approved', '092841db-d88c-438b-