('6a55697b-7cf0-4e03-a135-516c93a7a04d', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.42,"extraversion":0.94,"agreeableness":0.6,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.41,"narcissism":0.71,"psychopathy":0.32},"prospect_theory":{"lambda":1.26,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.23,"liquidation_anxiety":0.54,"max_leverage_comfort":0.47,"deleveraging_style":"adaptive"},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced dividend-yield chaser: thinks out loud and recruits an audience for every decision, spirals on ambiguity and mistakes the spiral for diligence. Decides in the time it takes to say the decision out loud, and on an ordinary week exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"herd-behavior","strength":0.77},{"slug":"bandwagon","strength":0.75}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.65,"conscientiousness":0.42,"extraversion":0.94,"agreeableness":0.6,"neuroticism":0.71}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced dividend-yield chaser: thinks out loud and recruits an audience for every decision, spirals on ambiguity and mistakes the spiral for diligence. Decides in the time it takes to say the decision out loud, and on an ordinary week exits winners at the first green candle.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
