('18406788-01ff-46f1-9808-3a120b4de354', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.36,"extraversion":0.55,"agreeableness":0.53,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.37,"narcissism":0.34,"psychopathy":0.35},"prospect_theory":{"lambda":3.31,"alpha":0.75,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.7,"max_leverage_comfort":0.13,"deleveraging_style":"adaptive"},"summary":"When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady futures spreader who notices the one thing that could go wrong before the nine that could go right and treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and on an ordinary week sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.7},{"slug":"disposition-effect","strength":0.67},{"slug":"diamond-hands-identity","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.49,"conscientiousness":0.36,"extraversion":0.55,"agreeableness":0.53,"neuroticism":0.77}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady futures spreader who notices the one thing that could go wrong before the nine that could go right and treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and on an ordinary week sets stop-losses then cancels them at the open.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('bb205975-86b1-40bb-959b-b4934bad1f31', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.5,"extraversion":0.55,"agreeableness":0.56,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.4,"narcissism":0.37,"psychopathy":0.29},"prospect_theory":{"lambda":1.63,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.46,"max_leverage_comfort":0.39,"deleveraging_style":"adaptive"},"summary":"Overvalues whatever they already hold simply because it is theirs. A measured delta-neutral market maker: carries yesterday''s stress into today''s unrelated decision. Trusts a felt sense of pattern over any spreadsheet, and in the unglamorous middle of things refreshes the order book compulsively during lunch.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.52},{"slug":"fomo","strength":0.49},{"slug":"loss-aversion","strength":0.52},{"slug":"endowment","strength":0.56}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","anxious","ipip-neo"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.5,"extraversion":0.55,"agreeableness":0.56,"neuroticism":0.57}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','anxious','ipip-neo']::text[], 'Overvalues whatever they already hold simply because it is theirs. A measured delta-neutral market maker: carries yesterday''s stress into today''s unrelated decision. Trusts a felt sense of pattern over any spreadsheet, and in the unglamorous middle of things refreshes the order book compulsively during lunch.', 0.83, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('1bfab7c5-6ae2-4e34-9073-2e4f54954ade', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.35,"extraversion":0.75,"agreeableness":0.68,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.35},"prospect_theory":{"lambda":3.05,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.58,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Trusts the group''s confidence more than its own. This MEV searcher reframes every problem as an excuse to learn a new system and narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up extrapolates the last data point into a permanent trend — in the parts nobody grades, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.6},{"slug":"recency","strength":0.69},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","dependent","robinhood","retail-trading","meme-stock","endowment-effect","open-minded","decision-making"],"archetype":"rh-meme-stock-hodler"}'::jsonb, '{"openness":0.83,"conscientiousness":0.35,"extraversion":0.75,"agreeableness":0.68,"neuroticism":0.57}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','meme-stock','endowment-effect','open-minded','decision-making']::text[], 'Trusts the group''s confidence more than its own. This MEV searcher reframes every problem as an excuse to learn a new system and narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up extrapolates the last data point into a permanent trend — in the parts nobody grades, rotates the whole book into whatever is pumping this hour.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
