('5b5b6b3d-8b2d-456c-bf19-8cf87cb01d18', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.41,"narcissism":0.67,"psychopathy":0.33},"prospect_theory":{"lambda":1.05,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.24,"liquidation_anxiety":0.43,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady bonding-curve sniper: treats established procedure as a first draft to be rewritten, recharges by being around people, not away from them. Prefers a fast wrong answer to a slow right one, and when no one is watching refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.74},{"slug":"dunning-kruger","strength":0.63},{"slug":"herd-behavior","strength":0.75},{"slug":"recency","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.81,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.64}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady bonding-curve sniper: treats established procedure as a first draft to be rewritten, recharges by being around people, not away from them. Prefers a fast wrong answer to a slow right one, and when no one is watching refreshes the order book compulsively during lunch.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('4b3d5f98-ffd2-403d-9ef3-4152540146ed', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.54,"extraversion":0.7,"agreeableness":0.57,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.39,"narcissism":0.54,"psychopathy":0.25},"prospect_theory":{"lambda":1.74,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.41,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Moves first and rationalizes second, usually convincingly. When the stakes rise, cannot watch a rally from the sidelines for long; sets alerts for a coin they already checked a minute ago.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"dunning-kruger","strength":0.52},{"slug":"fomo","strength":0.63},{"slug":"herd-behavior","strength":0.61},{"slug":"bandwagon","strength":0.57}],"tags":["trading","intuitive","robinhood","retail-trading","dip-buyer","anchoring","outgoing","cognition"],"archetype":"rh-dip-buyer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.54,"extraversion":0.7,"agreeableness":0.57,"neuroticism":0.51}'::jsonb, 'ENFJ', 'intuitive', ARRAY['trading','intuitive','robinhood','retail-trading','dip-buyer','anchoring','outgoing','cognition']::text[], 'Crypto day-trader whose defining move is that they treats a quiet room as a problem to be solved. Moves first and rationalizes second, usually convincingly. When the stakes rise, cannot watch a rally from the sidelines for long; sets alerts for a coin they already checked a minute ago.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f3ccac11-52d4-48d2-b525-a6cf4b609b52', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.27,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.34,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.24,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.22,"liquidation_anxiety":0.43,"max_leverage_comfort":0.64,"deleveraging_style":"adaptive"},"summary":"A pronounced bonding-curve sniper who draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. Takes on other people''s problems as if they were their own. When the downside gets concrete abandons a private read the instant the crowd leans the other way; once the urgency drains out, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.67},{"slug":"herd-behavior","strength":0.8}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.81,"conscientiousness":0.27,"extraversion":0.85,"agreeableness":0.74,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making']::text[], 'A pronounced bonding-curve sniper who draws energy from the crowd and wilts when working alone. Outsources conviction to whoever spoke last with authority. Takes on other people''s problems as if they were their own. When the downside gets concrete abandons a private read the instant the crowd leans the other way; once the urgency drains out, averages down on a name three times in a week.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('352b1b91-e24f-4588-acd5-c3a28474f2d2', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.38,"extraversion":0.91,"agreeableness":0.86,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.37,"narcissism":0.74,"psychopathy":0.34},"prospect_theory":{"lambda":1.26,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.33,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Adopts a conviction mainly because the room already has. A pronounced algorithmic market-maker: fills silence reflexively, even when nobody asked it to, reframes every problem as an excuse to learn a new system. Waits for a permission that never quite arrives, and across an ordinary week exits winners at the first green candle.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"herd-behavior","strength":0.79},{"slug":"bandwagon","strength":0.81}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","ipip-neo"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.38,"extraversion":0.91,"agreeableness":0.86,"neuroticism":0.56}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','ipip-neo']::text[], 'Adopts a conviction mainly because the room already has. A pronounced algorithmic market-maker: fills silence reflexively, even when nobody asked it to, reframes every problem as an excuse to learn a new system. Waits for a permission that never quite arrives, and across an ordinary week exits winners at the first green candle.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
