('3cf0b509-d143-4a2f-93ce-fa730be239db', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.61,"extraversion":0.38,"agreeableness":0.69,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.45,"narcissism":0.38,"psychopathy":0.26},"prospect_theory":{"lambda":2.75,"alpha":0.82,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.51,"liquidation_anxiety":0.49,"max_leverage_comfort":0.25,"deleveraging_style":"adaptive"},"summary":"The instant the deadline moves up, defers to the most senior voice even against their own evidence. Otherwise, a steady prop-desk scalper who measures decisions by who they might upset and weighs words carefully before spending them. Seeks a second, third, and fourth opinion before committing to anything, and in the routine of it exits winners at the first green candle.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.54},{"slug":"authority-bias","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.52,"conscientiousness":0.61,"extraversion":0.38,"agreeableness":0.69,"neuroticism":0.61}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect']::text[], 'The instant the deadline moves up, defers to the most senior voice even against their own evidence. Otherwise, a steady prop-desk scalper who measures decisions by who they might upset and weighs words carefully before spending them. Seeks a second, third, and fourth opinion before committing to anything, and in the routine of it exits winners at the first green candle.', 0.88, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('252193d6-abbe-4288-920e-c6c318efd5d2', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.44,"extraversion":0.88,"agreeableness":0.77,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.37,"narcissism":0.72,"psychopathy":0.28},"prospect_theory":{"lambda":1.25,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.42,"max_leverage_comfort":0.65,"deleveraging_style":"adaptive"},"summary":"As soon as real money or reputation is on the line, adopts a conviction mainly because the room already has. Otherwise, a pronounced MEV searcher who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything, and as a rule apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.75},{"slug":"fomo","strength":0.73},{"slug":"dunning-kruger","strength":0.69}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.76,"conscientiousness":0.44,"extraversion":0.88,"agreeableness":0.77,"neuroticism":0.61}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making']::text[], 'As soon as real money or reputation is on the line, adopts a conviction mainly because the room already has. Otherwise, a pronounced MEV searcher who recharges by being around people, not away from them and would rather invent a worse tool than use someone else''s good one. Seeks a second, third, and fourth opinion before committing to anything, and as a rule apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('583be835-ce98-4059-b26a-5cb0319789f4', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.36,"extraversion":0.68,"agreeableness":0.47,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.45,"narcissism":0.51,"psychopathy":0.4},"prospect_theory":{"lambda":1.82,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.55,"max_leverage_comfort":0.51,"deleveraging_style":"adaptive"},"summary":"Under pressure, mistakes a little fluency for real mastery. Otherwise, a steady delta-neutral market maker who chases novel frameworks and abandons them once the novelty fades and is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and as a rule rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.61},{"slug":"ostrich-effect","strength":0.56},{"slug":"fomo","strength":0.58},{"slug":"gas-sunk-cost","strength":0.58}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","open-minded","risk"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.72,"conscientiousness":0.36,"extraversion":0.68,"agreeableness":0.47,"neuroticism":0.66}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','open-minded','risk']::text[], 'Under pressure, mistakes a little fluency for real mastery. Otherwise, a steady delta-neutral market maker who chases novel frameworks and abandons them once the novelty fades and is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and as a rule rotates the whole book into whatever is pumping this hour.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e759ab75-ab3f-4d2a-98eb-212458d11400', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.42,"extraversion":0.6,"agreeableness":0.45,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.49,"narcissism":0.45,"psychopathy":0.38},"prospect_theory":{"lambda":1.73,"alpha":0.83,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.6,"max_leverage_comfort":0.37,"deleveraging_style":"adaptive"},"summary":"Under pressure, exits winning positions at the first minor delay or quiet period from devs. Otherwise, a steady perps degen who carries yesterday''s stress into today''s unrelated decision and gets bored of the proven method exactly when it starts working. Treats not-choosing as a safe choice right up until it is not, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"rug-trauma-overcorrection","strength":0.65},{"slug":"fomo","strength":0.58},{"slug":"ostrich-effect","strength":0.56}],"tags":["trading","avoidant","robinhood","retail-trading","overtrading","burnout","anxious","cognition"],"archetype":"rh-247-fatigue-trader"}'::jsonb, '{"openness":0.65,"conscientiousness":0.42,"extraversion":0.6,"agreeableness":0.45,"neuroticism":0.72}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','overtrading','burnout','anxious','cognition']::text[], 'Under pressure, exits winning positions at the first minor delay or quiet period from devs. Otherwise, a steady perps degen who carries yesterday''s stress into today''s unrelated decision and gets bored of the proven method exactly when it starts working. Treats not-choosing as a safe choice right up until it is not, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e59221dc-e78c-42d2-a93a-0b9fe410e450', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.78,"extraversion":0.4,"agreeableness":0.62,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.53,"narcissism":0.35,"psychopathy":0.37},"prospect_theory":{"lambda":2.47,"alpha":0.97,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.72,"liquidation_anxiety":0.35,"max_leverage_comfort":0.35,"deleveraging_style":"disciplined"},"summary":"A steady quant researcher who over-prepares to the point of diminishing returns. Slow-walks the decision through every contingency before moving. Measures decisions by who they might upset. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; in the pattern nobody else tracks, refreshes the order book compulsively during lunch.","decision_style":"deliberative","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.49},{"slug":"bandwagon","strength":0.57},{"slug":"hindsight","strength":0.52},{"slug":"anchoring","strength":0.54}],"tags":["trading","deliberative","robinhood","retail-trading","dca","fractional-shares","disciplined","decision-making"],"archetype":"rh-fractional-dca"}'::jsonb, '{"openness":0.54,"conscientiousness":0.78,"extraversion":0.4,"agreeableness":0.62,"neuroticism":0.41}'::jsonb, 'INFJ', 'deliberative', ARRAY['trading','deliberative','robinhood','retail-trading','dca','fractional-shares','disciplined','decision-making']::text[], 'A steady quant researcher who over-prepares to the point of diminishing returns. Slow-walks the decision through every contingency before moving. Measures decisions by who they might upset. The instant the deadline moves up finds it easier to believe something once it stops being a minority view; in the pattern nobody else tracks, refreshes the order book compulsively during lunch.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
