('0bc388ae-8758-4761-8ebe-bfc4a1213706', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.31,"extraversion":0.6,"agreeableness":0.65,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.35,"narcissism":0.38,"psychopathy":0.33},"prospect_theory":{"lambda":3.56,"alpha":0.81,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.81,"max_leverage_comfort":0.06,"deleveraging_style":"panic"},"summary":"Lets the deadline make the decision by default. This liquidation-bot operator rehearses catastrophes in vivid detail before they happen and treats a plan as a suggestion the moment it is made. The moment it stops being hypothetical looks away from bad news in the hope it resolves unwitnessed — left to their own devices, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.66},{"slug":"ostrich-effect","strength":0.67},{"slug":"availability","strength":0.63},{"slug":"disposition-effect","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.58,"conscientiousness":0.31,"extraversion":0.6,"agreeableness":0.65,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious']::text[], 'Lets the deadline make the decision by default. This liquidation-bot operator rehearses catastrophes in vivid detail before they happen and treats a plan as a suggestion the moment it is made. The moment it stops being hypothetical looks away from bad news in the hope it resolves unwitnessed — left to their own devices, refreshes the order book compulsively during lunch.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
