('1e5b4cdd-68db-4441-b9ad-87cc62a8e592', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.39,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.39,"narcissism":0.72,"psychopathy":0.29},"prospect_theory":{"lambda":1.54,"alpha":0.84,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.47,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Finds it easier to believe something once it stops being a minority view. A pronounced retail momentum chaser: thinks out loud and recruits an audience for every decision, hedges every commitment against an imagined worst case. Seeks a second, third, and fourth opinion before committing to anything, and without an audience screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"bandwagon","strength":0.77},{"slug":"fomo","strength":0.7}],"tags":["trading","dependent","robinhood","retail-trading","social-trader","fomo","outgoing","decision-making"],"archetype":"rh-sentiment-follower"}'::jsonb, '{"openness":0.84,"conscientiousness":0.39,"extraversion":0.86,"agreeableness":0.7,"neuroticism":0.66}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','social-trader','fomo','outgoing','decision-making']::text[], 'Finds it easier to believe something once it stops being a minority view. A pronounced retail momentum chaser: thinks out loud and recruits an audience for every decision, hedges every commitment against an imagined worst case. Seeks a second, third, and fourth opinion before committing to anything, and without an audience screenshots the winners and never the losers.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
