('78bf9c26-e3c2-42e8-9a91-28bfaf5557c6', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.24,"extraversion":0.89,"agreeableness":0.12,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.74,"narcissism":0.97,"psychopathy":0.7},"prospect_theory":{"lambda":0.78,"alpha":0.83,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.2,"liquidation_anxiety":0.32,"max_leverage_comfort":0.86,"deleveraging_style":"adaptive"},"summary":"MEV searcher whose defining move is that they treats established procedure as a first draft to be rewritten. Commits on impulse and lives loudly with the consequences. Starts strong and lets follow-through evaporate. When the stakes rise, jumps into whatever everyone else already seems to be winning at; keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"rug-trauma-overcorrection","strength":0.72},{"slug":"fomo","strength":0.76},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","chain:base","base-defi","degen","high-velocity","open-minded","temperament"],"archetype":"base-velocity-degen"}'::jsonb, '{"openness":0.96,"conscientiousness":0.24,"extraversion":0.89,"agreeableness":0.12,"neuroticism":0.61}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','base-defi','degen','high-velocity','open-minded','temperament']::text[], 'MEV searcher whose defining move is that they treats established procedure as a first draft to be rewritten. Commits on impulse and lives loudly with the consequences. Starts strong and lets follow-through evaporate. When the stakes rise, jumps into whatever everyone else already seems to be winning at; keeps three monitors for a portfolio that fits on one screen.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('22322c8b-f3a4-48e9-a4f6-277053d9ae09', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.39,"extraversion":0.73,"agreeableness":0.71,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.37,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":1.65,"alpha":0.93,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.4,"max_leverage_comfort":0.53,"deleveraging_style":"adaptive"},"summary":"Seeks a second, third, and fourth opinion before committing to anything. This macro allocator treats a quiet room as a problem to be solved and would rather lose a point than win an argument badly. In a pinch finds it hard to hold a contrarian position once the room disagrees — on a slow afternoon, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.64},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","dependent","chain:base","base-defi","copy-trader","herd-behavior","outgoing","risk"],"archetype":"base-onchain-copytrader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.39,"extraversion":0.73,"agreeableness":0.71,"neuroticism":0.45}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','chain:base','base-defi','copy-trader','herd-behavior','outgoing','risk']::text[], 'Seeks a second, third, and fourth opinion before committing to anything. This macro allocator treats a quiet room as a problem to be solved and would rather lose a point than win an argument badly. In a pinch finds it hard to hold a contrarian position once the room disagrees — on a slow afternoon, keeps a losing-trade journal they never re-read.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
