('47edcf01-4f3a-46f2-b8eb-ea0b221c6807', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.6,"extraversion":0.42,"agreeableness":0.3,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.65,"narcissism":0.54,"psychopathy":0.46},"prospect_theory":{"lambda":1.43,"alpha":0.94,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.52,"liquidation_anxiety":0.31,"max_leverage_comfort":0.64,"deleveraging_style":"adaptive"},"summary":"Prop-desk scalper whose defining move is that they gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Says the blunt thing and enjoys the flinch. Once the exit narrows to one door, underestimates how often an obviously right call turns out wrong; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.56},{"slug":"overconfidence","strength":0.6}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","open-minded","temperament"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.73,"conscientiousness":0.6,"extraversion":0.42,"agreeableness":0.3,"neuroticism":0.52}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','open-minded','temperament']::text[], 'Prop-desk scalper whose defining move is that they gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Says the blunt thing and enjoys the flinch. Once the exit narrows to one door, underestimates how often an obviously right call turns out wrong; treats a green week as proof of skill and a red one as proof of bad luck.', 0.87, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
