('3eb09188-2806-4416-9f3a-6c7a2ca49a0b', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.46,"extraversion":0.68,"agreeableness":0.29,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.62,"narcissism":0.74,"psychopathy":0.52},"prospect_theory":{"lambda":1.35,"alpha":0.9,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.29,"max_leverage_comfort":0.8,"deleveraging_style":"adaptive"},"summary":"Index-fund holdout whose defining move is that they would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Says the blunt thing and enjoys the flinch. Under a deadline, assumes the current streak is the new normal; talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"overconfidence","strength":0.54},{"slug":"recency","strength":0.62}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.97,"conscientiousness":0.46,"extraversion":0.68,"agreeableness":0.29,"neuroticism":0.43}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Index-fund holdout whose defining move is that they would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Says the blunt thing and enjoys the flinch. Under a deadline, assumes the current streak is the new normal; talks in win rate and never mentions size.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
