('d4500fb6-a307-4cd0-93e1-5b6d478be878', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.64,"extraversion":0.42,"agreeableness":0.22,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.72,"narcissism":0.57,"psychopathy":0.63},"prospect_theory":{"lambda":1.25,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.52,"liquidation_anxiety":0.31,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Futures spreader whose defining move is that they treats consensus-seeking as a waste of time. Treats a decision without a paper trail as a decision not yet made. Treats established procedure as a first draft to be rewritten. When the downside gets concrete, is more certain than the hit rate justifies; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.72},{"slug":"hindsight","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.62},{"slug":"optimism","strength":0.53}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","assertive","ipip-neo"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.67,"conscientiousness":0.64,"extraversion":0.42,"agreeableness":0.22,"neuroticism":0.34}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','assertive','ipip-neo']::text[], 'Futures spreader whose defining move is that they treats consensus-seeking as a waste of time. Treats a decision without a paper trail as a decision not yet made. Treats established procedure as a first draft to be rewritten. When the downside gets concrete, is more certain than the hit rate justifies; keeps a losing-trade journal they never re-read.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
