('1d2bab25-cddd-4c7f-8cf3-bc62b1329ec1', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.41,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.42,"narcissism":0.53,"psychopathy":0.29},"prospect_theory":{"lambda":1.43,"alpha":0.87,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.31,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"When the downside gets concrete, treats being left out of a move as its own kind of loss. Otherwise, a steady dividend-yield chaser who fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and across an ordinary week confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.58},{"slug":"fomo","strength":0.59},{"slug":"herd-behavior","strength":0.59},{"slug":"sunk-cost","strength":0.53}],"tags":["trading","dependent","chain:base","base-defi","copy-trader","herd-behavior","outgoing","decision-making"],"archetype":"base-onchain-copytrader"}'::jsonb, '{"openness":0.51,"conscientiousness":0.41,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.5}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','chain:base','base-defi','copy-trader','herd-behavior','outgoing','decision-making']::text[], 'When the downside gets concrete, treats being left out of a move as its own kind of loss. Otherwise, a steady dividend-yield chaser who fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and across an ordinary week confuses a bull market for a trading edge.', 0.84, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
