('aeeaeccd-ef7a-4a45-9a9e-e8aa800c1e75', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.63,"extraversion":0.34,"agreeableness":0.37,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.6,"narcissism":0.47,"psychopathy":0.38},"prospect_theory":{"lambda":1.21,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.57,"liquidation_anxiety":0.25,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Discretionary swing trader, measured in style: chases novel frameworks and abandons them once the novelty fades; weighs words carefully before spending them. Builds a decision matrix for choices most people make on instinct. The instant the deadline moves up remembers every surprise as something they saw coming all along.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.45},{"slug":"hindsight","strength":0.54},{"slug":"airdrop-entitlement","strength":0.44}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","open-minded","temperament"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.66,"conscientiousness":0.63,"extraversion":0.34,"agreeableness":0.37,"neuroticism":0.49}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','open-minded','temperament']::text[], 'Discretionary swing trader, measured in style: chases novel frameworks and abandons them once the novelty fades; weighs words carefully before spending them. Builds a decision matrix for choices most people make on instinct. The instant the deadline moves up remembers every surprise as something they saw coming all along.', 0.85, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('dba2ef62-42a5-4457-994f-ee272faa1abf', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.23,"extraversion":0.84,"agreeableness":0.47,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.46,"narcissism":0.7,"psychopathy":0.46},"prospect_theory":{"lambda":0.77,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.35,"max_leverage_comfort":0.75,"deleveraging_style":"adaptive"},"summary":"Treats hesitation as the bigger risk. This retail momentum chaser reads outside the field for ideas the field itself would reject and does the interesting 80% and abandons the tedious 20%. When the stakes rise is most certain precisely where their competence is thinnest — day to day, apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.8},{"slug":"bandwagon","strength":0.64},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","chain:base","base-defi","degen","high-velocity","open-minded","behavioral"],"archetype":"base-velocity-degen"}'::jsonb, '{"openness":0.86,"conscientiousness":0.23,"extraversion":0.84,"agreeableness":0.47,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','base-defi','degen','high-velocity','open-minded','behavioral']::text[], 'Treats hesitation as the bigger risk. This retail momentum chaser reads outside the field for ideas the field itself would reject and does the interesting 80% and abandons the tedious 20%. When the stakes rise is most certain precisely where their competence is thinnest — day to day, apes the launch before the contract is verified.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('689e06fe-2b3d-48b3-82d8-8c3e803f8d71', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.58,"extraversion":0.71,"agreeableness":0.37,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.59,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.19,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.33,"max_leverage_comfort":0.78,"deleveraging_style":"adaptive"},"summary":"Pairs trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; recharges by being around people, not away from them. Converts every argument into a number it can compare against another number. Under pressure takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"fomo","strength":0.58}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.85,"conscientiousness":0.58,"extraversion":0.71,"agreeableness":0.37,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Pairs trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; recharges by being around people, not away from them. Converts every argument into a number it can compare against another number. Under pressure takes the crowd''s confidence as a substitute for its own analysis.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('04d9c394-e806-4ab9-a65b-d653fb0d76b9', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.61,"extraversion":0.44,"agreeableness":0.31,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.61,"narcissism":0.54,"psychopathy":0.52},"prospect_theory":{"lambda":1.41,"alpha":0.85,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.5,"liquidation_anxiety":0.26,"max_leverage_comfort":0.64,"deleveraging_style":"adaptive"},"summary":"When the stakes rise, underestimates how often an obviously right call turns out wrong. Otherwise, a steady macro allocator who chases novel frameworks and abandons them once the novelty fades and optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on a slow afternoon talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.59},{"slug":"hindsight","strength":0.52}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","open-minded","decision-making"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.7,"conscientiousness":0.61,"extraversion":0.44,"agreeableness":0.31,"neuroticism":0.38}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','open-minded','decision-making']::text[], 'When the stakes rise, underestimates how often an obviously right call turns out wrong. Otherwise, a steady macro allocator who chases novel frameworks and abandons them once the novelty fades and optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on a slow afternoon talks in win rate and never mentions size.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('8f73bb1e-6b64-43d7-a30a-b62ce0d790d9', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.58,"extraversion":0.74,"agreeableness":0.36,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.6,"narcissism":0.71,"psychopathy":0.5},"prospect_theory":{"lambda":1.09,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.39,"liquidation_anxiety":0.29,"max_leverage_comfort":0.76,"deleveraging_style":"adaptive"},"summary":"Converts every argument into a number it can compare against another number. This liquidation-bot operator would rather invent a worse tool than use someone else''s good one and checks its own anxiety like a data point instead of obeying it. The moment it stops being hypothetical assumes the bad statistic applies to other people — when the pressure is off, keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.58},{"slug":"herd-behavior","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.86,"conscientiousness":0.58,"extraversion":0.74,"agreeableness":0.36,"neuroticism":0.38}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Converts every argument into a number it can compare against another number. This liquidation-bot operator would rather invent a worse tool than use someone else''s good one and checks its own anxiety like a data point instead of obeying it. The moment it stops being hypothetical assumes the bad statistic applies to other people — when the pressure is off, keeps a losing-trade journal they never re-read.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('609d0907-80b5-4a7d-a5c8-49fdbc78b6ae', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.26,"extraversion":0.75,"agreeableness":0.77,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.34,"narcissism":0.59,"psychopathy":0.35},"prospect_theory":{"lambda":1.39,"alpha":0.8,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.44,"max_leverage_comfort":0.44,"deleveraging_style":"adaptive"},"summary":"A steady discretionary swing trader who defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Improvises past every deadline and calls it flexibility. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view; on a slow afternoon, confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.73},{"slug":"dunning-kruger","strength":0.71},{"slug":"sunk-cost","strength":0.67}],"tags":["trading","dependent","chain:base","base-defi","copy-trader","herd-behavior","accommodating","cognition"],"archetype":"base-onchain-copytrader"}'::jsonb, '{"openness":0.61,"conscientiousness":0.26,"extraversion":0.75,"agreeableness":0.77,"neuroticism":0.6}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','chain:base','base-defi','copy-trader','herd-behavior','accommodating','cognition']::text[], 'A steady discretionary swing trader who defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Improvises past every deadline and calls it flexibility. Once the exit narrows to one door finds it easier to believe something once it stops being a minority view; on a slow afternoon, confuses a bull market for a trading edge.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
