('5bf563c3-a6d8-4153-83df-3cf3629ea9b5', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.33,"extraversion":0.74,"agreeableness":0.76,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.39,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":1.49,"alpha":0.85,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.31,"liquidation_anxiety":0.37,"max_leverage_comfort":0.45,"deleveraging_style":"adaptive"},"summary":"Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady perps degen who defaults to trust and gives the benefit of the doubt too freely and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and in the version no one reviews confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.6},{"slug":"fomo","strength":0.67},{"slug":"herd-behavior","strength":0.67},{"slug":"bandwagon","strength":0.75}],"tags":["trading","dependent","chain:base","base-defi","copy-trader","herd-behavior","accommodating","cognition"],"archetype":"base-onchain-copytrader"}'::jsonb, '{"openness":0.58,"conscientiousness":0.33,"extraversion":0.74,"agreeableness":0.76,"neuroticism":0.55}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','chain:base','base-defi','copy-trader','herd-behavior','accommodating','cognition']::text[], 'Under pressure, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady perps degen who defaults to trust and gives the benefit of the doubt too freely and draws energy from the crowd and wilts when working alone. Seeks a second, third, and fourth opinion before committing to anything, and in the version no one reviews confuses a bull market for a trading edge.', 0.89, 'approved', '092841db-d88c-438b-ab16-502