('a53d5339-ae7a-4aca-afd9-d9d6b046571e', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.17,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.72,"narcissism":0.83,"psychopathy":0.58},"prospect_theory":{"lambda":0.78,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.34,"liquidation_anxiety":0.33,"max_leverage_comfort":0.8,"deleveraging_style":"adaptive"},"summary":"A pronounced bonding-curve sniper who gets bored of the proven method exactly when it starts working. Reads a room or a market the way others read a paragraph. Recharges by being around people, not away from them. When there is no clean exit underestimates how often an obviously right call turns out wrong; in the small things, trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.66},{"slug":"fomo","strength":0.63},{"slug":"airdrop-entitlement","strength":0.61},{"slug":"recency","strength":0.58}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.17,"neuroticism":0.52}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'A pronounced bonding-curve sniper who gets bored of the proven method exactly when it starts working. Reads a room or a market the way others read a paragraph. Recharges by being around people, not away from them. When there is no clean exit underestimates how often an obviously right call turns out wrong; in the small things, trusts the chart more than the fundamentals and won''t say why.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
