('642f47d5-7457-470d-9460-c2ec1d83f0b8', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.61,"extraversion":0.7,"agreeableness":0.27,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.67,"narcissism":0.72,"psychopathy":0.54},"prospect_theory":{"lambda":1.22,"alpha":0.94,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.27,"max_leverage_comfort":0.74,"deleveraging_style":"adaptive"},"summary":"Dividend-yield chaser whose defining move is that they reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct. Says the blunt thing and enjoys the flinch. In a pinch, cannot watch a rally from the sidelines for long; names every strategy after the trade that almost worked.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.54},{"slug":"fomo","strength":0.62},{"slug":"recency","strength":0.54},{"slug":"overconfidence","strength":0.6}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.83,"conscientiousness":0.61,"extraversion":0.7,"agreeableness":0.27,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Dividend-yield chaser whose defining move is that they reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct. Says the blunt thing and enjoys the flinch. In a pinch, cannot watch a rally from the sidelines for long; names every strategy after the trade that almost worked.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('c64805c1-a145-4661-b833-744eed17c2e7', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.43,"extraversion":0.91,"agreeableness":0.37,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.51,"narcissism":0.85,"psychopathy":0.38},"prospect_theory":{"lambda":0.93,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.34,"max_leverage_comfort":0.81,"deleveraging_style":"adaptive"},"summary":"As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced options seller who chases novel frameworks and abandons them once the novelty fades and negotiates every relationship a little, even the close ones. Decides on a gut read in seconds and reverse-engineers the reasons later, and as a rule sizes every position at exactly 2% risk.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"bandwagon","strength":0.63},{"slug":"herd-behavior","strength":0.74}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.43,"extraversion":0.91,"agreeableness":0.37,"neuroticism":0.51}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced options seller who chases novel frameworks and abandons them once the novelty fades and negotiates every relationship a little, even the close ones. Decides on a gut read in seconds and reverse-engineers the reasons later, and as a rule sizes every position at exactly 2% risk.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
