('c074f67b-ed78-486b-ad74-aafb9454517c', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.68,"extraversion":0.35,"agreeableness":0.33,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.68,"narcissism":0.54,"psychopathy":0.48},"prospect_theory":{"lambda":1.42,"alpha":0.86,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.61,"liquidation_anxiety":0.26,"max_leverage_comfort":0.56,"deleveraging_style":"disciplined"},"summary":"A steady algorithmic market-maker who treats a missed deadline as a personal failure regardless of cause. Ranks the options twice, once on paper and once out loud, and trusts the paper. Gets bored of the proven method exactly when it starts working. When the stakes rise expects retroactive token rewards for routine protocol usage and reacts with outrage when excluded; when the stakes are trivial, talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.54},{"slug":"airdrop-entitlement","strength":0.55},{"slug":"rug-trauma-overcorrection","strength":0.46},{"slug":"ath-anchoring","strength":0.53}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","disciplined","cognition"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.66,"conscientiousness":0.68,"extraversion":0.35,"agreeableness":0.33,"neuroticism":0.42}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','disciplined','cognition']::text[], 'A steady algorithmic market-maker who treats a missed deadline as a personal failure regardless of cause. Ranks the options twice, once on paper and once out loud, and trusts the paper. Gets bored of the proven method exactly when it starts working. When the stakes rise expects retroactive token rewards for routine protocol usage and reacts with outrage when excluded; wh