('b5e7d930-0b5d-4052-9a2f-94df70b93756', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.25,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.62,"narcissism":0.82,"psychopathy":0.54},"prospect_theory":{"lambda":0.68,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.24,"max_leverage_comfort":0.83,"deleveraging_style":"adaptive"},"summary":"Lets pattern-matching from past cases stand in for fresh analysis. This onchain copy-trader gets bored of the proven method exactly when it starts working and optimizes for winning over being liked. As soon as real money or reputation is on the line discounts the older pattern in favor of whatever just happened — when no one is watching, confuses a bull market for a trading edge.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.68},{"slug":"fomo","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.4,"extraversion":0.78,"agreeableness":0.25,"neuroticism":0.52}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded']::text[], 'Lets pattern-matching from past cases stand in for fresh analysis. This onchain copy-trader gets bored of the proven method exactly when it starts working and optimizes for winning over being liked. As soon as real money or reputation is on the line discounts the older pattern in favor of whatever just happened — when no one is watching, confuses a bull market for a trading edge.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('8a98f211-e5e6-4657-b2b9-c3830e0dbdc6', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.38,"extraversion":0.59,"agreeableness":0.66,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.37,"narcissism":0.49,"psychopathy":0.31},"prospect_theory":{"lambda":1.56,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.36,"liquidation_anxiety":0.4,"max_leverage_comfort":0.59,"deleveraging_style":"adaptive"},"summary":"A measured discretionary swing trader who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Improvises past every deadline and calls it flexibility. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; in the small things, refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.61},{"slug":"bandwagon","strength":0.56},{"slug":"sunk-cost","strength":0.57}],"tags":["trading","dependent","chain:base","base-defi","copy-trader","herd-behavior","accommodating","cognition"],"archetype":"base-onchain-copytrader"}'::jsonb, '{"openness":0.63,"conscientiousness":0.38,"extraversion":0.59,"agreeableness":0.66,"neuroticism":0.48}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','chain:base','base-defi','copy-trader','herd-behavior','accommodating','cognition']::text[], 'A measured discretionary swing trader who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything. Improvises past every deadline and calls it flexibility. The instant it becomes irreversible finds it hard to hold a contrarian position once the room disagrees; in the small things, refreshes the order book compulsively during lunch.', 0.86, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('60d74f81-39d0-4c9b-b216-f00576f10d20', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.38,"extraversion":0.77,"agreeableness":0.39,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.49,"narcissism":0.77,"psychopathy":0.46},"prospect_theory":{"lambda":1.26,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.31,"max_leverage_comfort":0.81,"deleveraging_style":"adaptive"},"summary":"Assumes the bad statistic applies to other people. A pronounced index-fund holdout: gets bored of the proven method exactly when it starts working, starts strong and lets follow-through evaporate. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and day to day averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"optimism","strength":0.66},{"slug":"herd-behavior","strength":0.61},{"slug":"fomo","strength":0.65}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.38,"extraversion":0.77,"agreeableness":0.39,"neuroticism":0.42}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded']::text[], 'Assumes the bad statistic applies to other people. A pronounced index-fund holdout: gets bored of the proven method exactly when it starts working, starts strong and lets follow-through evaporate. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and day to day averages down on a name three times in a week.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
