('43e6c400-4fc4-4c11-bef0-72ce02a54b5b', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.15,"extraversion":0.96,"agreeableness":0.4,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.47,"narcissism":0.76,"psychopathy":0.51},"prospect_theory":{"lambda":0.79,"alpha":0.81,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.25,"liquidation_anxiety":0.52,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"When the walls close in, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced airdrop farmer who thinks out loud and recruits an audience for every decision and notices the one thing that could go wrong before the nine that could go right. Prefers a fast wrong answer to a slow right one, and when the pressure is off screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.67},{"slug":"fomo","strength":0.8},{"slug":"dunning-kruger","strength":0.8},{"slug":"herd-behavior","strength":0.72}],"tags":["trading","spontaneous","chain:base","base-defi","degen","high-velocity","outgoing","temperament"],"archetype":"base-velocity-degen"}'::jsonb, '{"openness":0.82,"conscientiousness":0.15,"extraversion":0.96,"agreeableness":0.4,"neuroticism":0.76}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','base-defi','degen','high-velocity','outgoing','temperament']::text[], 'When the walls close in, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced airdrop farmer who thinks out loud and recruits an audience for every decision and notices the one thing that could go wrong before the nine that could go right. Prefers a fast wrong answer to a slow right one, and when the pressure is off screenshots the winners and never the losers.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('9b4bfacd-2621-47a7-86da-6786536c87e6', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.29,"extraversion":0.89,"agreeableness":0.26,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.62,"narcissism":0.88,"psychopathy":0.61},"prospect_theory":{"lambda":0.82,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.27,"liquidation_anxiety":0.43,"max_leverage_comfort":0.74,"deleveraging_style":"adaptive"},"summary":"A pronounced pairs trader who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Draws energy from the crowd and wilts when working alone. Under a deadline treats being left out of a move as its own kind of loss; in the pattern nobody else tracks, apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.29,"extraversion":0.89,"agreeableness":0.26,"neuroticism":0.65}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded']::text[], 'A pronounced pairs trader who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Draws energy from the crowd and wilts when working alone. Under a deadline treats being left out of a move as its own kind of loss; in the pattern nobody else tracks, apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f3d595f3-817b-450d-a4d9-89ec2c7567d3', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.55,"extraversion":0.47,"agreeableness":0.3,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.58,"narcissism":0.57,"psychopathy":0.52},"prospect_theory":{"lambda":1.41,"alpha":0.9,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.49,"liquidation_anxiety":0.36,"max_leverage_comfort":0.69,"deleveraging_style":"adaptive"},"summary":"Wants the base rate before the anecdote. This commodities speculator reframes every problem as an excuse to learn a new system and assumes self-interest in others because it is usually there in themselves. When the safe option quietly expires assumes the current streak is the new normal — when the stakes are trivial, keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.53},{"slug":"recency","strength":0.59}],"tags":["trading","analytical","chain:base","base-defi","airdrop-farmer","sybil-adjacent","open-minded","ipip-neo"],"archetype":"base-airdrop-farmer"}'::jsonb, '{"openness":0.8,"conscientiousness":0.55,"extraversion":0.47,"agreeableness":0.3,"neuroticism":0.44}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:base','base-defi','airdrop-farmer','sybil-adjacent','open-minded','ipip-neo']::text[], 'Wants the base rate before the anecdote. This commodities speculator reframes every problem as an excuse to learn a new system and assumes self-interest in others because it is usually there in themselves. When the safe option quietly expires assumes the current streak is the new normal — when the stakes are trivial, keeps a losing-trade journal they never re-read.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
