('da1302c5-d044-400d-974b-36b5c9f80173', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.3,"extraversion":0.7,"agreeableness":0.37,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.53,"narcissism":0.68,"psychopathy":0.49},"prospect_theory":{"lambda":1,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.37,"liquidation_anxiety":0.41,"max_leverage_comfort":0.68,"deleveraging_style":"adaptive"},"summary":"Lets pattern-matching from past cases stand in for fresh analysis. This discretionary swing trader chases novel frameworks and abandons them once the novelty fades and treats warmth as leverage and cooperation as weakness. When the downside gets concrete discounts the older pattern in favor of whatever just happened — without an audience, refreshes the order book compulsively during lunch.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.68},{"slug":"fomo","strength":0.57}],"tags":["trading","intuitive","chain:base","base-defi","meme-coin","rotator","open-minded","ipip-neo"],"archetype":"base-memecoin-rotator"}'::jsonb, '{"openness":0.82,"conscientiousness":0.3,"extraversion":0.7,"agreeableness":0.37,"neuroticism":0.6}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','base-defi','meme-coin','rotator','open-minded','ipip-neo']::text[], 'Lets pattern-matching from past cases stand in for fresh analysis. This discretionary swing trader chases novel frameworks and abandons them once the novelty fades and treats warmth as leverage and cooperation as weakness. When the downside gets concrete discounts the older pattern in favor of whatever just happened — without an audience, refreshes the order book compulsively during lunch.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
