('fa25f99f-01aa-4a1d-b56a-cb1c59c7f943', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.93,"extraversion":0.28,"agreeableness":0.44,"neuroticism":0.19},"dark_triad":{"machiavellianism":0.66,"narcissism":0.51,"psychopathy":0.48},"prospect_theory":{"lambda":2.77,"alpha":0.97,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.85,"liquidation_anxiety":0.27,"max_leverage_comfort":0.53,"deleveraging_style":"disciplined"},"summary":"Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Converts every argument into a number it can compare against another number. Says the least in the room and notices the most. When there is no clean exit, holds their estimates with a certainty the track record does not support; checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.69},{"slug":"hindsight","strength":0.62},{"slug":"optimism","strength":0.67}],"tags":["trading","analytical","crypto-whale","market-maker","institutional","delta-neutral","disciplined","decision-making"],"archetype":"whale-market-maker"}'::jsonb, '{"openness":0.79,"conscientiousness":0.93,"extraversion":0.28,"agreeableness":0.44,"neuroticism":0.19}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','market-maker','institutional','delta-neutral','disciplined','decision-making']::text[], 'Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Converts every argument into a number it can compare against another number. Says the least in the room and notices the most. When there is no clean exit, holds their estimates with a certainty the track record does not support; checks the P&L blotter forty times before lunch.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
