('d936f86d-a86a-4ccb-a6fd-2ec9aedc3d27', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.86,"extraversion":0.29,"agreeableness":0.42,"neuroticism":0.08},"dark_triad":{"machiavellianism":0.68,"narcissism":0.49,"psychopathy":0.57},"prospect_theory":{"lambda":2.7,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.78,"liquidation_anxiety":0.29,"max_leverage_comfort":0.56,"deleveraging_style":"disciplined"},"summary":"A pronounced crypto day-trader who sleeps fine the night before the big call. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Reads outside the field for ideas the field itself would reject. When there is no clean exit underestimates how often an obviously right call turns out wrong; when the pressure is off, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"overconfidence","strength":0.77},{"slug":"optimism","strength":0.7},{"slug":"anchoring","strength":0.5}],"tags":["trading","analytical","crypto-whale","market-maker","institutional","delta-neutral","even-keeled","cognition"],"archetype":"whale-market-maker"}'::jsonb, '{"openness":0.73,"conscientiousness":0.86,"extraversion":0.29,"agreeableness":0.42,"neuroticism":0.08}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','market-maker','institutional','delta-neutral','even-keeled','cognition']::text[], 'A pronounced crypto day-trader who sleeps fine the night before the big call. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Reads outside the field for ideas the field itself would reject. When there is no clean exit underestimates how often an obviously right call turns out wrong; when the pressure is off, trusts the chart more than the fundamentals and won''t say why.', 0.98, 'a