('2475f55d-bb5a-4655-8e14-ef46359e2d2f', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.86,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.82,"narcissism":0.6,"psychopathy":0.51},"prospect_theory":{"lambda":2.37,"alpha":0.93,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.72,"liquidation_anxiety":0.29,"max_leverage_comfort":0.7,"deleveraging_style":"disciplined"},"summary":"Remembers every surprise as something they saw coming all along. A pronounced MEV searcher: treats established procedure as a first draft to be rewritten, treats a crisis as an interesting problem rather than a threat. Builds a decision matrix for choices most people make on instinct, and when the stakes are trivial treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.64},{"slug":"hindsight","strength":0.68},{"slug":"ath-anchoring","strength":0.61},{"slug":"optimism","strength":0.52}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","decision-making"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.91,"conscientiousness":0.86,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','decision-making']::text[], 'Remembers every surprise as something they saw coming all along. A pronounced MEV searcher: treats established procedure as a first draft to be rewritten, treats a crisis as an interesting problem rather than a threat. Builds a decision matrix for choices most people make on instinct, and when the stakes are trivial treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', '092841db-d