('e9438dfc-cda2-44d8-b7d9-a318ec3f9c4e', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.97,"extraversion":0.29,"agreeableness":0.44,"neuroticism":0.18},"dark_triad":{"machiavellianism":0.65,"narcissism":0.43,"psychopathy":0.53},"prospect_theory":{"lambda":2.52,"alpha":0.99,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.82,"liquidation_anxiety":0.24,"max_leverage_comfort":0.43,"deleveraging_style":"disciplined"},"summary":"Demands the data before the discussion and the discussion before the call. This DeFi yield farmer plans in exhaustive detail and resents any deviation and sleeps fine the night before the big call. The moment it stops being hypothetical underestimates how often an obviously right call turns out wrong — without an audience, exits winners at the first green candle.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.69},{"slug":"optimism","strength":0.63}],"tags":["trading","analytical","crypto-whale","market-maker","institutional","delta-neutral","disciplined","decision-making"],"archetype":"whale-market-maker"}'::jsonb, '{"openness":0.57,"conscientiousness":0.97,"extraversion":0.29,"agreeableness":0.44,"neuroticism":0.18}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','market-maker','institutional','delta-neutral','disciplined','decision-making']::text[], 'Demands the data before the discussion and the discussion before the call. This DeFi yield farmer plans in exhaustive detail and resents any deviation and sleeps fine the night before the big call. The moment it stops being hypothetical underestimates how often an obviously right call turns out wrong — without an audience, exits winners at the first green candle.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('c8a992aa-3852-4401-b7d2-7a5c65ba6cfa', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.97,"extraversion":0.3,"agreeableness":0.28,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.8,"narcissism":0.59,"psychopathy":0.55},"prospect_theory":{"lambda":2.32,"alpha":0.99,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.91,"liquidation_anxiety":0.28,"max_leverage_comfort":0.59,"deleveraging_style":"disciplined"},"summary":"Macro allocator whose defining move is that they builds in buffer time and then fills the buffer with more work. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. When there is no clean exit, treats past peak valuation as guaranteed future recovery; apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.66},{"slug":"hindsight","strength":0.66},{"slug":"ath-anchoring","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.97,"extraversion":0.3,"agreeableness":0.28,"neuroticism":0.32}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament']::text[], 'Macro allocator whose defining move is that they builds in buffer time and then fills the buffer with more work. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. When there is no clean exit, treats past peak valuation as guaranteed future recovery; apes the launch before the contract is verified.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
