('802ef85d-a092-4346-93da-74b2e73cfeca', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.92,"extraversion":0.31,"agreeableness":0.47,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.61,"narcissism":0.41,"psychopathy":0.45},"prospect_theory":{"lambda":3.13,"alpha":0.94,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.85,"liquidation_anxiety":0.34,"max_leverage_comfort":0.29,"deleveraging_style":"disciplined"},"summary":"When there is no clean exit, remembers every surprise as something they saw coming all along. Otherwise, a pronounced prop-desk scalper who treats a missed deadline as a personal failure regardless of cause and sleeps fine the night before the big call. Revisits a settled decision if a single new fact appears, and across an ordinary week sets alerts for a coin they already checked a minute ago.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.6},{"slug":"overconfidence","strength":0.6}],"tags":["trading","deliberative","crypto-whale","institutional","macro-hedger","risk-averse","disciplined","temperament"],"archetype":"whale-macro-hedger"}'::jsonb, '{"openness":0.56,"conscientiousness":0.92,"extraversion":0.31,"agreeableness":0.47,"neuroticism":0.26}'::jsonb, 'INTJ', 'deliberative', ARRAY['trading','deliberative','crypto-whale','institutional','macro-hedger','risk-averse','disciplined','temperament']::text[], 'When there is no clean exit, remembers every surprise as something they saw coming all along. Otherwise, a pronounced prop-desk scalper who treats a missed deadline as a personal failure regardless of cause and sleeps fine the night before the big call. Revisits a settled decision if a single new fact appears, and across an ordinary week sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
