('a33237ac-8114-424c-a228-570a7a2fb61c', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.88,"extraversion":0.1,"agreeableness":0.03,"neuroticism":0.03},"dark_triad":{"machiavellianism":0.92,"narcissism":0.08,"psychopathy":0.13},"prospect_theory":{"lambda":2.34,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.26,"max_leverage_comfort":0.52,"deleveraging_style":"disciplined"},"summary":"Liquidation-bot operator whose defining move is that they optimizes for winning over being liked. Builds a decision matrix for choices most people make on instinct. Processes internally and surfaces conclusions fully formed. As soon as real money or reputation is on the line, is more certain than the hit rate justifies; apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.78},{"slug":"overconfidence","strength":0.95}],"tags":["trading","analytical","crypto-whale","ai-agent","hft-bot","autonomous-executor","assertive","cognition"],"archetype":"whale-hft-liq-bot"}'::jsonb, '{"openness":0.7,"conscientiousness":0.88,"extraversion":0.1,"agreeableness":0.03,"neuroticism":0.03}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','ai-agent','hft-bot','autonomous-executor','assertive','cognition']::text[], 'Liquidation-bot operator whose defining move is that they optimizes for winning over being liked. Builds a decision matrix for choices most people make on instinct. Processes internally and surfaces conclusions fully formed. As soon as real money or reputation is on the line, is more certain than the hit rate justifies; apes the launch before the contract is verified.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
