('18fd80b6-ccf3-416e-9ec5-8d52db40a9a0', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.91,"extraversion":0.48,"agreeableness":0.38,"neuroticism":0.22},"dark_triad":{"machiavellianism":0.81,"narcissism":0.54,"psychopathy":0.52},"prospect_theory":{"lambda":2.15,"alpha":0.97,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.78,"liquidation_anxiety":0.3,"max_leverage_comfort":0.61,"deleveraging_style":"disciplined"},"summary":"A pronounced bonding-curve sniper who builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct. Sleeps fine the night before the big call. The instant it becomes irreversible underestimates how often an obviously right call turns out wrong; on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.72},{"slug":"hindsight","strength":0.69}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.91,"extraversion":0.48,"agreeableness":0.38,"neuroticism":0.22}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo']::text[], 'A pronounced bonding-curve sniper who builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct. Sleeps fine the night before the big call. The instant it becomes irreversible underestimates how often an obviously right call turns out wrong; on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('74702237-8433-4184-8acb-8a8407e7c5b0', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.71,"extraversion":0.58,"agreeableness":0.23,"neuroticism":0.2},"dark_triad":{"machiavellianism":0.91,"narcissism":0.68,"psychopathy":0.48},"prospect_theory":{"lambda":1.41,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.62,"liquidation_anxiety":0.24,"max_leverage_comfort":0.81,"deleveraging_style":"disciplined"},"summary":"Perps degen, pronounced in style: chases novel frameworks and abandons them once the novelty fades; treats a crisis as an interesting problem rather than a threat. Weighs options against explicit criteria and distrusts anything they cannot tabulate. As soon as real money or reputation is on the line underestimates how often an obviously right call turns out wrong.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"optimism","strength":0.62},{"slug":"overconfidence","strength":0.78}],"tags":["trading","analytical","crypto-whale","mev-searcher","mempool-extractor","quant-trader","open-minded","behavioral"],"archetype":"whale-mev-searcher"}'::jsonb, '{"openness":0.88,"conscientiousness":0.71,"extraversion":0.58,"agreeableness":0.23,"neuroticism":0.2}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','mev-searcher','mempool-extractor','quant-trader','open-minded','behavioral']::text[], 'Perps degen, pronounced in style: chases novel frameworks and abandons them once the novelty fades; treats a crisis as an interesting problem rather than a threat. Weighs options against explicit criteria and distrusts anything they cannot tabulate. As soon as real money or reputation is on the line underestimates how often an obviously right call turns out wrong.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
