('e3a9bb44-9f54-4f2c-af12-6303c105b1a9', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.74,"extraversion":0.64,"agreeableness":0.21,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.91,"narcissism":0.78,"psychopathy":0.51},"prospect_theory":{"lambda":1.52,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.55,"liquidation_anxiety":0.26,"max_leverage_comfort":0.86,"deleveraging_style":"disciplined"},"summary":"Holds their estimates with a certainty the track record does not support. A pronounced prop-desk scalper: reframes every problem as an excuse to learn a new system, draws energy from the crowd and wilts when working alone. Builds a decision matrix for choices most people make on instinct, and as a rule keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.67},{"slug":"overconfidence","strength":0.74},{"slug":"hindsight","strength":0.62}],"tags":["trading","analytical","crypto-whale","mev-searcher","mempool-extractor","quant-trader","open-minded","temperament"],"archetype":"whale-mev-searcher"}'::jsonb, '{"openness":0.96,"conscientiousness":0.74,"extraversion":0.64,"agreeableness":0.21,"neuroticism":0.26}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','mev-searcher','mempool-extractor','quant-trader','open-minded','temperament']::text[], 'Holds their estimates with a certainty the track record does not support. A pronounced prop-desk scalper: reframes every problem as an excuse to learn a new system, draws energy from the crowd and wilts when working alone. Builds a decision matrix for choices most people make on instinct, and as a rule keeps a losing-trade journal they never re-read.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
