('4cf27dd9-4d82-4055-bfb2-eb149a8f2dd9', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.85,"extraversion":0.55,"agreeableness":0.36,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.66,"narcissism":0.5,"psychopathy":0.54},"prospect_theory":{"lambda":1.8,"alpha":0.96,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.77,"liquidation_anxiety":0.28,"max_leverage_comfort":0.44,"deleveraging_style":"disciplined"},"summary":"A pronounced founder raising a round who maintains flawless records nobody asked for. Demands the data before the discussion and the discussion before the call. Stays flat when the numbers go red. Under pressure is more certain than the hit rate justifies; when the pressure is off, writes the walk-away number down before the call starts.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.57},{"slug":"overconfidence","strength":0.61},{"slug":"ath-anchoring","strength":0.57}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","cognition"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.57,"conscientiousness":0.85,"extraversion":0.55,"agreeableness":0.36,"neuroticism":0.27}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','cognition']::text[], 'A pronounced founder raising a round who maintains flawless records nobody asked for. Demands the data before the discussion and the discussion before the call. Stays flat when the numbers go red. Under pressure is more certain than the hit rate justifies; when the pressure is off, writes the walk-away number down before the call starts.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
