('c95dae0f-8975-40a9-b4f1-fe23b8321a1c', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.96,"extraversion":0.42,"agreeableness":0.29,"neuroticism":0.17},"dark_triad":{"machiavellianism":0.83,"narcissism":0.6,"psychopathy":0.69},"prospect_theory":{"lambda":1.9,"alpha":0.95,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.83,"liquidation_anxiety":0.21,"max_leverage_comfort":0.63,"deleveraging_style":"disciplined"},"summary":"A pronounced founder raising a round who plans in exhaustive detail and resents any deviation. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Moves on from a mistake faster than the people around them do. When the number turns red underestimates how often an obviously right call turns out wrong; across the quiet stretches, memorizes the counterparty BATNA in advance.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.78},{"slug":"optimism","strength":0.61}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","autonomous-agent","disciplined","risk"],"archetype":"a2a-negotiation-agent"}'::jsonb, '{"openness":0.78,"conscientiousness":0.96,"extraversion":0.42,"agreeableness":0.29,"neuroticism":0.17}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','autonomous-agent','disciplined','risk']::text[], 'A pronounced founder raising a round who plans in exhaustive detail and resents any deviation. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Moves on from a mistake faster than the people around them do. When the number turns red underestimates how often an obviously right call turns out wrong; across the quiet stretches, memorizes the counterparty BATNA in advance.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
