('38662620-41ea-4a26-952c-e67b131a479f', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.78,"extraversion":0.5,"agreeableness":0.32,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.68,"narcissism":0.57,"psychopathy":0.55},"prospect_theory":{"lambda":1.74,"alpha":0.96,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.65,"liquidation_anxiety":0.26,"max_leverage_comfort":0.6,"deleveraging_style":"disciplined"},"summary":"When the number turns red, is more certain than the hit rate justifies. Otherwise, a steady franchise dealmaker who cannot relax until the checklist is visibly complete and chases novel frameworks and abandons them once the novelty fades. Converts every argument into a number it can compare against another number, and on a slow afternoon memorizes the counterparty BATNA in advance.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"anchoring","strength":0.52},{"slug":"overconfidence","strength":0.65},{"slug":"ath-anchoring","strength":0.6},{"slug":"hindsight","strength":0.63}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","decision-making"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.71,"conscientiousness":0.78,"extraversion":0.5,"agreeableness":0.32,"neuroticism":0.28}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','decision-making']::text[], 'When the number turns red, is more certain than the hit rate justifies. Otherwise, a steady franchise dealmaker who cannot relax until the checklist is visibly complete and chases novel frameworks and abandons them once the novelty fades. Converts every argument into a number it can compare against another number, and on a slow afternoon memorizes the counterparty BATNA in advance.', 0.91, 'approved', '092841db-d88c-438b-ab16-502e8