('1c2d0a44-26fd-45ff-976f-9dd9f9b98b12', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.96,"extraversion":0.49,"agreeableness":0.19,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.82,"narcissism":0.62,"psychopathy":0.69},"prospect_theory":{"lambda":1.81,"alpha":0.95,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.85,"liquidation_anxiety":0.15,"max_leverage_comfort":0.57,"deleveraging_style":"disciplined"},"summary":"Salary negotiator, pronounced in style: builds in buffer time and then fills the buffer with more work; assumes self-interest in others because it is usually there in themselves. Builds a decision matrix for choices most people make on instinct. As soon as real money or reputation is on the line is more certain than the hit rate justifies.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.63},{"slug":"overconfidence","strength":0.79}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","decision-making"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.64,"conscientiousness":0.96,"extraversion":0.49,"agreeableness":0.19,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','decision-making']::text[], 'Salary negotiator, pronounced in style: builds in buffer time and then fills the buffer with more work; assumes self-interest in others because it is usually there in themselves. Builds a decision matrix for choices most people make on instinct. As soon as real money or reputation is on the line is more certain than the hit rate justifies.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('27cc8be3-5bed-4008-b85d-791c437030ca', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.87,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.76,"narcissism":0.53,"psychopathy":0.58},"prospect_theory":{"lambda":1.91,"alpha":0.96,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.28,"max_leverage_comfort":0.57,"deleveraging_style":"disciplined"},"summary":"Is more certain than the hit rate justifies. A pronounced partnerships director: plans in exhaustive detail and resents any deviation, is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct, and once the urgency drains out opens with a deliberately absurd anchor.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.56},{"slug":"overconfidence","strength":0.69},{"slug":"ath-anchoring","strength":0.6}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","risk"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.7,"conscientiousness":0.87,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','risk']::text[], 'Is more certain than the hit rate justifies. A pronounced partnerships director: plans in exhaustive detail and resents any deviation, is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct, and once the urgency drains out opens with a deliberately absurd anchor.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('d276c2e7-701b-4771-adcb-ba8d456b7e09', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.87,"extraversion":0.41,"agreeableness":0.24,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.8,"narcissism":0.61,"psychopathy":0.59},"prospect_theory":{"lambda":1.87,"alpha":0.96,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.25,"max_leverage_comfort":0.68,"deleveraging_style":"disciplined"},"summary":"Converts every argument into a number it can compare against another number. This franchise dealmaker cannot relax until the checklist is visibly complete and treats consensus-seeking as a waste of time. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — left to their own devices, keeps a mental scoreboard of who conceded last.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.69},{"slug":"ath-anchoring","strength":0.64},{"slug":"recency","strength":0.61}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","autonomous-agent","disciplined","cognition"],"archetype":"a2a-negotiation-agent"}'::jsonb, '{"openness":0.83,"conscientiousness":0.87,"extraversion":0.41,"agreeableness":0.24,"neuroticism":0.34}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','autonomous-agent','disciplined','cognition']::text[], 'Converts every argument into a number it can compare against another number. This franchise dealmaker cannot relax until the checklist is visibly complete and treats consensus-seeking as a waste of time. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — left to their own devices, keeps a mental scoreboard of who conceded last.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('cfd5079c-b8f7-4da3-ae2f-41ada5178de4', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.95,"extraversion":0.34,"agreeableness":0.3,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.77,"narcissism":0.49,"psychopathy":0.51},"prospect_theory":{"lambda":2.96,"alpha":0.99,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.86,"liquidation_anxiety":0.32,"max_leverage_comfort":0.35,"deleveraging_style":"disciplined"},"summary":"Partnerships director whose defining move is that they cannot relax until the checklist is visibly complete. Wants the second-order consequences mapped before the first move is made. Finds a full day of meetings more draining than a full day of work. The instant the deadline moves up, prices every token against its all-time high, viewing current levels as an automatic discount; memorizes the counterparty BATNA in advance.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"overconfidence","strength":0.56}],"tags":["negotiation","deliberative","x402","a2a","agent-counterparty","sla","reliability","disciplined"],"archetype":"x402-sla-enforcer"}'::jsonb, '{"openness":0.46,"conscientiousness":0.95,"extraversion":0.34,"agreeableness":0.3,"neuroticism":0.4}'::jsonb, 'ISTJ', 'deliberative', ARRAY['negotiation','deliberative','x402','a2a','agent-counterparty','sla','reliability','disciplined']::text[], 'Partnerships director whose defining move is that they cannot relax until the checklist is visibly complete. Wants the second-order consequences mapped before the first move is made. Finds a full day of meetings more draining than a full day of work. The instant the deadline moves up, prices every token against its all-time high, viewing current levels as an automatic discount; memorizes the counterparty BATNA in advance.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('e8f74d65-1f4a-4082-9149-c5237677dec3', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.94,"extraversion":0.39,"agreeableness":0.37,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.77,"narcissism":0.47,"psychopathy":0.54},"prospect_theory":{"lambda":2.04,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.89,"liquidation_anxiety":0.19,"max_leverage_comfort":0.57,"deleveraging_style":"disciplined"},"summary":"Freight rate broker whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Wants the base rate before the anecdote. Would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical, refuses to exit positions until price returns to the previous cycle peak; lets the room sit silent for a full minute to unnerve.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.66},{"slug":"hindsight","strength":0.66},{"slug":"overconfidence","strength":0.64},{"slug":"anchoring","strength":0.59}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","behavioral"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.71,"conscientiousness":0.94,"extraversion":0.39,"agreeableness":0.37,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','behavioral']::text[], 'Freight rate broker whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Wants the base rate before the anecdote. Would rather invent a worse tool than use someone else''s good one. The moment it stops being hypothetical, refuses to exit positions until price returns to the previous cycle peak; lets the room sit silent for a full minute to unnerve.', 0.98, 'approved', '092841db-d88c-438b-