('39e2ace1-286f-4dc7-94ec-afd2733c13ac', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.89,"extraversion":0.47,"agreeableness":0.33,"neuroticism":0.15},"dark_triad":{"machiavellianism":0.79,"narcissism":0.56,"psychopathy":0.67},"prospect_theory":{"lambda":2.01,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.8,"liquidation_anxiety":0.29,"max_leverage_comfort":0.55,"deleveraging_style":"disciplined"},"summary":"In a pinch, refuses to exit positions until price returns to the previous cycle peak. Otherwise, a pronounced salary negotiator who front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the parts nobody grades writes the walk-away number down before the call starts.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.63},{"slug":"optimism","strength":0.64}],"tags":["negotiation","analytical","x402","a2a","agent-counterparty","volume-discount","disciplined","ipip-neo"],"archetype":"x402-volume-negotiator"}'::jsonb, '{"openness":0.69,"conscientiousness":0.89,"extraversion":0.47,"agreeableness":0.33,"neuroticism":0.15}'::jsonb, 'INTJ', 'analytical', ARRAY['negotiation','analytical','x402','a2a','agent-counterparty','volume-discount','disciplined','ipip-neo']::text[], 'In a pinch, refuses to exit positions until price returns to the previous cycle peak. Otherwise, a pronounced salary negotiator who front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the parts nobody grades writes the walk-away number down before the call starts.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e4