('c3c031ce-918d-4f3d-80a0-add592977a20', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.86,"extraversion":0.5,"agreeableness":0.26,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.8,"narcissism":0.55,"psychopathy":0.69},"prospect_theory":{"lambda":1.92,"alpha":0.95,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.22,"max_leverage_comfort":0.56,"deleveraging_style":"disciplined"},"summary":"Founder raising a round whose defining move is that they builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct. Says the blunt thing and enjoys the flinch. Under pressure, underestimates how often an obviously right call turns out wrong; memorizes the counterparty BATNA in advance.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.8},{"slug":"ath-anchoring","strength":0.57},{"slug":"anchoring","strength":0.5},{"slug":"optimism","strength":0.57}],"tags":["negotiation","analytical","x402","agent-counterparty","price-negotiation","anchoring","disciplined","temperament"],"archetype":"x402-price-haggler"}'::jsonb, '{"openness":0.7,"conscientiousness":0.86,"extraversion":0.5,"agreeableness":0.26,"neuroticism":0.21}'::jsonb, 'ENTJ', 'analytical', ARRAY['negotiation','analytical','x402','agent-counterparty','price-negotiation','anchoring','disciplined','temperament']::text[], 'Founder raising a round whose defining move is that they builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct. Says the blunt thing and enjoys the flinch. Under pressure, underestimates how often an obviously right call turns out wrong; memorizes the counterparty BATNA in advance.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
