('91741f79-cbd1-4bd3-8b98-1afb0358963f', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.28,"extraversion":0.63,"agreeableness":0.42,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.53,"narcissism":0.5,"psychopathy":0.41},"prospect_theory":{"lambda":0.96,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.49,"max_leverage_comfort":0.63,"deleveraging_style":"adaptive"},"summary":"Airdrop farmer whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Knows the answer before it can explain the question. Dominates the room then wonders why others stayed quiet. When cornered, doubles down on stagnant liquidity pools to justify the initial deployment gas; refreshes the order book compulsively during lunch.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"ostrich-effect","strength":0.62},{"slug":"gas-sunk-cost","strength":0.67}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","behavioral"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.28,"extraversion":0.63,"agreeableness":0.42,"neuroticism":0.72}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','behavioral']::text[], 'Airdrop farmer whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Knows the answer before it can explain the question. Dominates the room then wonders why others stayed quiet. When cornered, doubles down on stagnant liquidity pools to justify the initial deployment gas; refreshes the order book compulsively during lunch.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
