('690aa0ef-13bc-4c3f-9d9f-20815730fc3c', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.06,"extraversion":0.88,"agreeableness":0.4,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.48,"narcissism":0.71,"psychopathy":0.54},"prospect_theory":{"lambda":0.55,"alpha":0.8,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.51,"max_leverage_comfort":0.67,"deleveraging_style":"adaptive"},"summary":"When the walls close in, is most certain precisely where their competence is thinnest. Otherwise, a pronounced MEV searcher who treats a plan as a suggestion the moment it is made and would rather invent a worse tool than use someone else''s good one. Prefers a fast wrong answer to a slow right one, and day to day treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.91},{"slug":"recency","strength":0.8},{"slug":"gas-sunk-cost","strength":0.82}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","improviser","risk"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.88,"conscientiousness":0.06,"extraversion":0.88,"agreeableness":0.4,"neuroticism":0.77}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','improviser','risk']::text[], 'When the walls close in, is most certain precisely where their competence is thinnest. Otherwise, a pronounced MEV searcher who treats a plan as a suggestion the moment it is made and would rather invent a worse tool than use someone else''s good one. Prefers a fast wrong answer to a slow right one, and day to day treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
