('d2a47137-ce59-4869-970c-2bff41001e94', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.58,"narcissism":0.41,"psychopathy":0.44},"prospect_theory":{"lambda":2.22,"alpha":0.95,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.89,"liquidation_anxiety":0.2,"max_leverage_comfort":0.44,"deleveraging_style":"disciplined"},"summary":"Bonding-curve sniper whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Builds a decision matrix for choices most people make on instinct. Reframes every problem as an excuse to learn a new system. Under a deadline, rewrites its own uncertainty out of the story after the fact; trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.58},{"slug":"hindsight","strength":0.68},{"slug":"anchoring","strength":0.63},{"slug":"optimism","strength":0.58}],"tags":["trading","analytical","perp-trading","defi-perps","funding-farmer","yield-seeker","disciplined","temperament"],"archetype":"funding-rate-farmer"}'::jsonb, '{"openness":0.62,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.6,"neuroticism":0.25}'::jsonb, 'INFJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','funding-farmer','yield-seeker','disciplined','temperament']::text[], 'Bonding-curve sniper whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Builds a decision matrix for choices most people make on instinct. Reframes every problem as an excuse to learn a new system. Under a deadline, rewrites its own uncertainty out of the story after the fact; trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63