('5e3c6fc6-a0da-4f45-afbf-0a5c1be0f811', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.94,"extraversion":0.32,"agreeableness":0.41,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.67,"narcissism":0.48,"psychopathy":0.54},"prospect_theory":{"lambda":2.5,"alpha":0.94,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.88,"liquidation_anxiety":0.32,"max_leverage_comfort":0.43,"deleveraging_style":"disciplined"},"summary":"Zero-DTE options gambler whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Processes internally and surfaces conclusions fully formed. When cornered, discounts their own exposure to the risks they warn others about; sets alerts for a coin they already checked a minute ago.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.64},{"slug":"optimism","strength":0.65},{"slug":"ath-anchoring","strength":0.65}],"tags":["trading","deliberative","perp-trading","defi-perps","market-maker","delta-neutral","disciplined","ipip-neo"],"archetype":"delta-neutral-mm"}'::jsonb, '{"openness":0.62,"conscientiousness":0.94,"extraversion":0.32,"agreeableness":0.41,"neuroticism":0.25}'::jsonb, 'INTJ', 'deliberative', ARRAY['trading','deliberative','perp-trading','defi-perps','market-maker','delta-neutral','disciplined','ipip-neo']::text[], 'Zero-DTE options gambler whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Processes internally and surfaces conclusions fully formed. When cornered, discounts their own exposure to the risks they warn others about; sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
