('14a8ec59-028b-45ea-87cf-b8986d3ece4a', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.41,"extraversion":0.71,"agreeableness":0.36,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.56,"narcissism":0.64,"psychopathy":0.41},"prospect_theory":{"lambda":0.94,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.43,"max_leverage_comfort":0.74,"deleveraging_style":"adaptive"},"summary":"In a pinch, extrapolates the last data point into a permanent trend. Otherwise, a steady discretionary swing trader who collects half-finished manifestos and unconventional methods and thinks out loud and recruits an audience for every decision. Lets pattern-matching from past cases stand in for fresh analysis, and on an ordinary week sizes every position at exactly 2% risk.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.57},{"slug":"recency","strength":0.61},{"slug":"fomo","strength":0.6}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","ipip-neo"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.83,"conscientiousness":0.41,"extraversion":0.71,"agreeableness":0.36,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','ipip-neo']::text[], 'In a pinch, extrapolates the last data point into a permanent trend. Otherwise, a steady discretionary swing trader who collects half-finished manifestos and unconventional methods and thinks out loud and recruits an audience for every decision. Lets pattern-matching from past cases stand in for fresh analysis, and on an ordinary week sizes every position at exactly 2% risk.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
