('6b43c1da-37d2-4f48-8fb1-17c1a7cc375f', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.89,"extraversion":0.45,"agreeableness":0.43,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.69,"narcissism":0.46,"psychopathy":0.38},"prospect_theory":{"lambda":2.21,"alpha":0.95,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.78,"liquidation_anxiety":0.28,"max_leverage_comfort":0.54,"deleveraging_style":"disciplined"},"summary":"Wants the base rate before the anecdote. This quant researcher front-loads the work and double-checks it twice and sleeps fine the night before the big call. When the downside gets concrete refuses to exit positions until price returns to the previous cycle peak — on an ordinary week, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.54},{"slug":"ath-anchoring","strength":0.55},{"slug":"anchoring","strength":0.54}],"tags":["trading","analytical","perp-trading","defi-perps","funding-farmer","yield-seeker","disciplined","behavioral"],"archetype":"funding-rate-farmer"}'::jsonb, '{"openness":0.67,"conscientiousness":0.89,"extraversion":0.45,"agreeableness":0.43,"neuroticism":0.38}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','funding-farmer','yield-seeker','disciplined','behavioral']::text[], 'Wants the base rate before the anecdote. This quant researcher front-loads the work and double-checks it twice and sleeps fine the night before the big call. When the downside gets concrete refuses to exit positions until price returns to the previous cycle peak — on an ordinary week, apes the launch before the contract is verified.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('fb636e1a-3420-42b3-9792-5d4718291666', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.43,"extraversion":0.6,"agreeableness":0.23,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.68,"narcissism":0.68,"psychopathy":0.51},"prospect_theory":{"lambda":0.97,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.41,"liquidation_anxiety":0.42,"max_leverage_comfort":0.71,"deleveraging_style":"adaptive"},"summary":"Delta-neutral market maker whose defining move is that they collects half-finished manifestos and unconventional methods. Reads a room or a market the way others read a paragraph. Rehearses catastrophes in vivid detail before they happen. The instant it becomes irreversible, assumes the current streak is the new normal; backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.72},{"slug":"airdrop-entitlement","strength":0.62}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","decision-making"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.43,"extraversion":0.6,"agreeableness":0.23,"neuroticism":0.68}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','decision-making']::text[], 'Delta-neutral market maker whose defining move is that they collects half-finished manifestos and unconventional methods. Reads a room or a market the way others read a paragraph. Rehearses catastrophes in vivid detail before they happen. The instant it becomes irreversible, assumes the current streak is the new normal; backtests for months but front-runs the model on impulse.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
