('7e458b1f-0a2e-4c98-9438-539c0545e1e0', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.88,"extraversion":0.3,"agreeableness":0.21,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.88,"narcissism":0.66,"psychopathy":0.6},"prospect_theory":{"lambda":1.83,"alpha":0.9,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.82,"liquidation_anxiety":0.22,"max_leverage_comfort":0.66,"deleveraging_style":"disciplined"},"summary":"A pronounced DeFi yield farmer who cannot relax until the checklist is visibly complete. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Guards their energy and rations social exposure. When the safe option quietly expires remembers every surprise as something they saw coming all along; day to day, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.61},{"slug":"recency","strength":0.57},{"slug":"ath-anchoring","strength":0.65},{"slug":"hindsight","strength":0.73}],"tags":["trading","analytical","perp-trading","defi-perps","liquidation-hunter","predatory-trading","disciplined","risk"],"archetype":"liquidation-hunter"}'::jsonb, '{"openness":0.84,"conscientiousness":0.88,"extraversion":0.3,"agreeableness":0.21,"neuroticism":0.34}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','liquidation-hunter','predatory-trading','disciplined','risk']::text[], 'A pronounced DeFi yield farmer who cannot relax until the checklist is visibly complete. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Guards their energy and rations social exposure. When the safe option quietly expires remembers every surprise as something they saw coming all along; day to day, apes the launch before the contract is verified.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c6