('b0e4e14a-835e-4d2c-86db-af013c1de7be', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.16,"extraversion":0.95,"agreeableness":0.4,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.49,"narcissism":0.76,"psychopathy":0.5},"prospect_theory":{"lambda":0.5,"alpha":0.77,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.2,"liquidation_anxiety":0.46,"max_leverage_comfort":0.65,"deleveraging_style":"adaptive"},"summary":"Once things get tense, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced prop-desk scalper who fills silence reflexively, even when nobody asked it to and treats a plan as a suggestion the moment it is made. Decides in the time it takes to say the decision out loud, and in the unglamorous middle of things refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.7},{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.78}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","outgoing","ipip-neo"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.85,"conscientiousness":0.16,"extraversion":0.95,"agreeableness":0.4,"neuroticism":0.79}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','outgoing','ipip-neo']::text[], 'Once things get tense, jumps into whatever everyone else already seems to be winning at. Otherwise, a pronounced prop-desk scalper who fills silence reflexively, even when nobody asked it to and treats a plan as a suggestion the moment it is made. Decides in the time it takes to say the decision out loud, and in the unglamorous middle of things refreshes the order book compulsively during lunch.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
