('37ca1252-8bef-4c8c-976b-98a6423b9854', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.89,"extraversion":0.29,"agreeableness":0.27,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.84,"narcissism":0.52,"psychopathy":0.6},"prospect_theory":{"lambda":1.74,"alpha":0.92,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.24,"max_leverage_comfort":0.53,"deleveraging_style":"disciplined"},"summary":"A pronounced airdrop farmer who front-loads the work and double-checks it twice. Ranks the options twice, once on paper and once out loud, and trusts the paper. Says the least in the room and notices the most. Once things get tense remembers every surprise as something they saw coming all along; in the parts nobody grades, sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.67},{"slug":"ath-anchoring","strength":0.6},{"slug":"optimism","strength":0.57}],"tags":["trading","analytical","perp-trading","defi-perps","liquidation-hunter","predatory-trading","disciplined","risk"],"archetype":"liquidation-hunter"}'::jsonb, '{"openness":0.61,"conscientiousness":0.89,"extraversion":0.29,"agreeableness":0.27,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','liquidation-hunter','predatory-trading','disciplined','risk']::text[], 'A pronounced airdrop farmer who front-loads the work and double-checks it twice. Ranks the options twice, once on paper and once out loud, and trusts the paper. Says the least in the room and notices the most. Once things get tense remembers every surprise as something they saw coming all along; in the parts nobody grades, sets stop-losses then cancels them at the open.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
