('d6d7a408-8690-4fc3-a14d-e3eddaec0bce', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.29,"extraversion":0.7,"agreeableness":0.32,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.6,"narcissism":0.73,"psychopathy":0.5},"prospect_theory":{"lambda":0.96,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.35,"max_leverage_comfort":0.76,"deleveraging_style":"adaptive"},"summary":"Delta-neutral market maker whose defining move is that they reads outside the field for ideas the field itself would reject. Decides on a gut read in seconds and reverse-engineers the reasons later. Assumes self-interest in others because it is usually there in themselves. When the downside gets concrete, cannot see the gap in its own knowledge from inside the gap; checks the P&L blotter forty times before lunch.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"fomo","strength":0.54},{"slug":"recency","strength":0.67},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","behavioral"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.29,"extraversion":0.7,"agreeableness":0.32,"neuroticism":0.56}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','behavioral']::text[], 'Delta-neutral market maker whose defining move is that they reads outside the field for ideas the field itself would reject. Decides on a gut read in seconds and reverse-engineers the reasons later. Assumes self-interest in others because it is usually there in themselves. When the downside gets concrete, cannot see the gap in its own knowledge from inside the gap; checks the P&L blotter forty times before lunch.', 0.95, 'approved', '092841db-d88c-