('0b22e816-a269-442a-b1aa-afa6bbfbd2e0', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.04,"extraversion":0.92,"agreeableness":0.31,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.58,"narcissism":0.76,"psychopathy":0.61},"prospect_theory":{"lambda":0.53,"alpha":0.73,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.26,"liquidation_anxiety":0.55,"max_leverage_comfort":0.61,"deleveraging_style":"adaptive"},"summary":"Once the exit narrows to one door, doubles down on stagnant liquidity pools to justify the initial deployment gas. Otherwise, a pronounced quant researcher who treats a plan as a suggestion the moment it is made and reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am, and in the pattern nobody else tracks backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.84},{"slug":"gas-sunk-cost","strength":0.89},{"slug":"ostrich-effect","strength":0.82},{"slug":"recency","strength":0.8}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","improviser","ipip-neo"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.88,"conscientiousness":0.04,"extraversion":0.92,"agreeableness":0.31,"neuroticism":0.88}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','improviser','ipip-neo']::text[], 'Once the exit narrows to one door, doubles down on stagnant liquidity pools to justify the initial deployment gas. Otherwise, a pronounced quant researcher who treats a plan as a suggestion the moment it is made and reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am, and in the pattern nobody else tracks backtests for months but front-runs the model on impulse.', 0.98, 'approved', '0928