('67fb4ed9-91b0-47d9-9a76-1f81e13f74c2', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.84,"extraversion":0.34,"agreeableness":0.14,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.87,"narcissism":0.69,"psychopathy":0.62},"prospect_theory":{"lambda":1.89,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.7,"liquidation_anxiety":0.22,"max_leverage_comfort":0.72,"deleveraging_style":"disciplined"},"summary":"When cornered, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced perps degen who gets bored of the proven method exactly when it starts working and sleeps fine the night before the big call. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the pattern nobody else tracks refreshes the order book compulsively during lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"overconfidence","strength":0.72},{"slug":"airdrop-entitlement","strength":0.65},{"slug":"hindsight","strength":0.64}],"tags":["trading","analytical","perp-trading","defi-perps","liquidation-hunter","predatory-trading","open-minded","cognition"],"archetype":"liquidation-hunter"}'::jsonb, '{"openness":0.91,"conscientiousness":0.84,"extraversion":0.34,"agreeableness":0.14,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','liquidation-hunter','predatory-trading','open-minded','cognition']::text[], 'When cornered, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced perps degen who gets bored of the proven method exactly when it starts working and sleeps fine the night before the big call. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the pattern nobody else tracks refreshes the order book compulsively