('54800be8-375c-4514-9bab-4f475d733464', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.97,"extraversion":0.55,"agreeableness":0.6,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.57,"narcissism":0.44,"psychopathy":0.42},"prospect_theory":{"lambda":2.25,"alpha":0.97,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.82,"liquidation_anxiety":0.24,"max_leverage_comfort":0.56,"deleveraging_style":"disciplined"},"summary":"Builds a decision matrix for choices most people make on instinct. This futures spreader front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. The instant the deadline moves up refuses to exit positions until price returns to the previous cycle peak — in the routine of it, sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"ENFJ","suggested_biases":[{"slug":"anchoring","strength":0.54},{"slug":"ath-anchoring","strength":0.59}],"tags":["trading","analytical","perp-trading","defi-perps","funding-farmer","yield-seeker","disciplined","risk"],"archetype":"funding-rate-farmer"}'::jsonb, '{"openness":0.69,"conscientiousness":0.97,"extraversion":0.55,"agreeableness":0.6,"neuroticism":0.33}'::jsonb, 'ENFJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','funding-farmer','yield-seeker','disciplined','risk']::text[], 'Builds a decision matrix for choices most people make on instinct. This futures spreader front-loads the work and double-checks it twice and reframes every problem as an excuse to learn a new system. The instant the deadline moves up refuses to exit positions until price returns to the previous cycle peak — in the routine of it, sets stop-losses then cancels them at the open.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6a19609-6226-4497-8f79-1d658724c8f9', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.73,"extraversion":0.62,"agreeableness":0.41,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.63,"narcissism":0.57,"psychopathy":0.4},"prospect_theory":{"lambda":2.26,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.55,"liquidation_anxiety":0.36,"max_leverage_comfort":0.49,"deleveraging_style":"disciplined"},"summary":"A steady airdrop farmer who treats a missed deadline as a personal failure regardless of cause. Converts every argument into a number it can compare against another number. Thinks out loud and recruits an audience for every decision. When the number turns red expects to be the exception to a risk it can otherwise describe accurately; when the pressure is off, averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.48},{"slug":"hindsight","strength":0.6},{"slug":"optimism","strength":0.63},{"slug":"ath-anchoring","strength":0.48}],"tags":["trading","analytical","perp-trading","defi-perps","funding-farmer","yield-seeker","disciplined","behavioral"],"archetype":"funding-rate-farmer"}'::jsonb, '{"openness":0.62,"conscientiousness":0.73,"extraversion":0.62,"agreeableness":0.41,"neuroticism":0.36}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','funding-farmer','yield-seeker','disciplined','behavioral']::text[], 'A steady airdrop farmer who treats a missed deadline as a personal failure regardless of cause. Converts every argument into a number it can compare against another number. Thinks out loud and recruits an audience for every decision. When the number turns red expects to be the exception to a risk it can otherwise describe accurately; when the pressure is off, averages down on a name three times in a week.', 0.93, 'approved', '092841d