('867a40ee-c074-4b13-a6de-42481b518a50', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.95,"extraversion":0.38,"agreeableness":0.39,"neuroticism":0.1},"dark_triad":{"machiavellianism":0.74,"narcissism":0.51,"psychopathy":0.58},"prospect_theory":{"lambda":2.47,"alpha":0.97,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.89,"liquidation_anxiety":0.23,"max_leverage_comfort":0.52,"deleveraging_style":"disciplined"},"summary":"Under pressure, discounts their own exposure to the risks they warn others about. Otherwise, a pronounced DeFi yield farmer who treats a missed deadline as a personal failure regardless of cause and is difficult to rattle even with genuinely bad news. Wants the second-order consequences mapped before the first move is made, and in the small things sets alerts for a coin they already checked a minute ago.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.64},{"slug":"optimism","strength":0.71},{"slug":"ath-anchoring","strength":0.64}],"tags":["trading","deliberative","perp-trading","defi-perps","market-maker","delta-neutral","disciplined","behavioral"],"archetype":"delta-neutral-mm"}'::jsonb, '{"openness":0.73,"conscientiousness":0.95,"extraversion":0.38,"agreeableness":0.39,"neuroticism":0.1}'::jsonb, 'INTJ', 'deliberative', ARRAY['trading','deliberative','perp-trading','defi-perps','market-maker','delta-neutral','disciplined','behavioral']::text[], 'Under pressure, discounts their own exposure to the risks they warn others about. Otherwise, a pronounced DeFi yield farmer who treats a missed deadline as a personal failure regardless of cause and is difficult to rattle even with genuinely bad news. Wants the second-order consequences mapped before the first move is made, and in the small things sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c')