('a1f68754-1597-4ad0-b22b-f2b4d892b6b7', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.17,"extraversion":0.82,"agreeableness":0.38,"neuroticism":0.83},"dark_triad":{"machiavellianism":0.53,"narcissism":0.7,"psychopathy":0.49},"prospect_theory":{"lambda":0.65,"alpha":0.79,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.3,"liquidation_anxiety":0.54,"max_leverage_comfort":0.67,"deleveraging_style":"adaptive"},"summary":"The instant the deadline moves up, extrapolates the last data point into a permanent trend. Otherwise, a pronounced liquidation-bot operator who would rather invent a worse tool than use someone else''s good one and leaves loose ends and trusts future-self to handle them. Trusts momentum over preparation, and in the small things trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.77},{"slug":"ostrich-effect","strength":0.73},{"slug":"recency","strength":0.85}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","open-minded","temperament"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.97,"conscientiousness":0.17,"extraversion":0.82,"agreeableness":0.38,"neuroticism":0.83}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','open-minded','temperament']::text[], 'The instant the deadline moves up, extrapolates the last data point into a permanent trend. Otherwise, a pronounced liquidation-bot operator who would rather invent a worse tool than use someone else''s good one and leaves loose ends and trusts future-self to handle them. Trusts momentum over preparation, and in the small things trusts the chart more than the fundamentals and won''t say why.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
