('08403574-b078-4015-9855-3919f24d4576', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.72,"extraversion":0.33,"agreeableness":0.31,"neuroticism":0.17},"dark_triad":{"machiavellianism":0.82,"narcissism":0.61,"psychopathy":0.62},"prospect_theory":{"lambda":1.92,"alpha":0.88,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.59,"liquidation_anxiety":0.27,"max_leverage_comfort":0.77,"deleveraging_style":"disciplined"},"summary":"When someone is watching the outcome, discounts their own exposure to the risks they warn others about. Otherwise, a pronounced onchain copy-trader who gets bored of the proven method exactly when it starts working and treats warmth as leverage and cooperation as weakness. Wants the base rate before the anecdote, and when the stakes are trivial keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.63},{"slug":"recency","strength":0.6},{"slug":"hindsight","strength":0.56},{"slug":"ath-anchoring","strength":0.55}],"tags":["trading","analytical","perp-trading","defi-perps","liquidation-hunter","predatory-trading","open-minded","decision-making"],"archetype":"liquidation-hunter"}'::jsonb, '{"openness":0.9,"conscientiousness":0.72,"extraversion":0.33,"agreeableness":0.31,"neuroticism":0.17}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','liquidation-hunter','predatory-trading','open-minded','decision-making']::text[], 'When someone is watching the outcome, discounts their own exposure to the risks they warn others about. Otherwise, a pronounced onchain copy-trader who gets bored of the proven method exactly when it starts working and treats warmth as leverage and cooperation as weakness. Wants the base rate before the anecdote, and when the stakes are trivial keeps a losing-trade journal they never re-read.', 0.95, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('1f02c8d9-d940-4fe2-9ab0-c6c3bb5c95ca', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.83,"extraversion":0.42,"agreeableness":0.5,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.56,"narcissism":0.4,"psychopathy":0.41},"prospect_theory":{"lambda":2.37,"alpha":0.97,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.3,"max_leverage_comfort":0.37,"deleveraging_style":"disciplined"},"summary":"Quant researcher whose defining move is that they plans in exhaustive detail and resents any deviation. Ranks the options twice, once on paper and once out loud, and trusts the paper. Moves on from a mistake faster than the people around them do. Under pressure, is surprised in the moment and certain in the retelling; backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"INFJ","suggested_biases":[{"slug":"overconfidence","strength":0.59},{"slug":"hindsight","strength":0.63}],"tags":["trading","analytical","perp-trading","defi-perps","funding-farmer","yield-seeker","disciplined","risk"],"archetype":"funding-rate-farmer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.83,"extraversion":0.42,"agreeableness":0.5,"neuroticism":0.3}'::jsonb, 'INFJ', 'analytical', ARRAY['trading','analytical','perp-trading','defi-perps','funding-farmer','yield-seeker','disciplined','risk']::text[], 'Quant researcher whose defining move is that they plans in exhaustive detail and resents any deviation. Ranks the options twice, once on paper and once out loud, and trusts the paper. Moves on from a mistake faster than the people around them do. Under pressure, is surprised in the moment and certain in the retelling; backtests for months but front-runs the model on impulse.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
