('0d82904d-f1d5-4b38-9bd9-d141ce3fcc3e', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.1,"extraversion":0.8,"agreeableness":0.23,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.65,"narcissism":0.8,"psychopathy":0.68},"prospect_theory":{"lambda":0.62,"alpha":0.78,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.29,"liquidation_anxiety":0.42,"max_leverage_comfort":0.69,"deleveraging_style":"adaptive"},"summary":"Macro allocator, pronounced in style: does the interesting 80% and abandons the tedious 20%; treats warmth as leverage and cooperation as weakness. Treats hesitation as the bigger risk. The instant it becomes irreversible cannot see the gap in its own knowledge from inside the gap.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.72},{"slug":"dunning-kruger","strength":0.86}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","improviser","temperament"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.87,"conscientiousness":0.1,"extraversion":0.8,"agreeableness":0.23,"neuroticism":0.73}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','improviser','temperament']::text[], 'Macro allocator, pronounced in style: does the interesting 80% and abandons the tedious 20%; treats warmth as leverage and cooperation as weakness. Treats hesitation as the bigger risk. The instant it becomes irreversible cannot see the gap in its own knowledge from inside the gap.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('96c97408-83d2-46f2-a12c-b8378c02db4f', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.35,"extraversion":0.67,"agreeableness":0.34,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.58,"narcissism":0.65,"psychopathy":0.45},"prospect_theory":{"lambda":1.23,"alpha":0.81,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.37,"liquidation_anxiety":0.37,"max_leverage_comfort":0.64,"deleveraging_style":"adaptive"},"summary":"Perps degen whose defining move is that they gets bored of the proven method exactly when it starts working. Decides on a gut read in seconds and reverse-engineers the reasons later. Starts strong and lets follow-through evaporate. When cornered, mistakes a little fluency for real mastery; backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.61},{"slug":"dunning-kruger","strength":0.66},{"slug":"recency","strength":0.65}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","temperament"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.82,"conscientiousness":0.35,"extraversion":0.67,"agreeableness":0.34,"neuroticism":0.61}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','temperament']::text[], 'Perps degen whose defining move is that they gets bored of the proven method exactly when it starts working. Decides on a gut read in seconds and reverse-engineers the reasons later. Starts strong and lets follow-through evaporate. When cornered, mistakes a little fluency for real mastery; backtests for months but front-runs the model on impulse.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('2feef1ea-c839-4dcf-99d7-6fad9470c9bc', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.49,"extraversion":0.65,"agreeableness":0.47,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.45,"narcissism":0.54,"psychopathy":0.29},"prospect_theory":{"lambda":1.08,"alpha":0.8,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.44,"max_leverage_comfort":0.55,"deleveraging_style":"adaptive"},"summary":"Options seller, measured in style: gets bored of the proven method exactly when it starts working; narrates the plan to whoever is nearby before committing to it. Moves first and rationalizes second, usually convincingly. When the safe option quietly expires assumes the current streak is the new normal.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"fomo","strength":0.57}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","ipip-neo"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.66,"conscientiousness":0.49,"extraversion":0.65,"agreeableness":0.47,"neuroticism":0.64}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','ipip-neo']::text[], 'Options seller, measured in style: gets bored of the proven method exactly when it starts working; narrates the plan to whoever is nearby before committing to it. Moves first and rationalizes second, usually convincingly. When the safe option quietly expires assumes the current streak is the new normal.', 0.9, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
