('d2d606c7-50d9-4497-9e3f-53ac6b8c4c3e', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.88,"extraversion":0.35,"agreeableness":0.43,"neuroticism":0.2},"dark_triad":{"machiavellianism":0.66,"narcissism":0.45,"psychopathy":0.52},"prospect_theory":{"lambda":2.57,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.33,"max_leverage_comfort":0.45,"deleveraging_style":"disciplined"},"summary":"When the stakes rise, is more certain than the hit rate justifies. Otherwise, a pronounced value investor who plans in exhaustive detail and resents any deviation and reframes every problem as an excuse to learn a new system. Keeps deliberating past the point where more information would change anything, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.","decision_style":"deliberative","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.67},{"slug":"hindsight","strength":0.66},{"slug":"optimism","strength":0.66}],"tags":["trading","deliberative","perp-trading","defi-perps","market-maker","delta-neutral","disciplined","ipip-neo"],"archetype":"delta-neutral-mm"}'::jsonb, '{"openness":0.62,"conscientiousness":0.88,"extraversion":0.35,"agreeableness":0.43,"neuroticism":0.2}'::jsonb, 'INTJ', 'deliberative', ARRAY['trading','deliberative','perp-trading','defi-perps','market-maker','delta-neutral','disciplined','ipip-neo']::text[], 'When the stakes rise, is more certain than the hit rate justifies. Otherwise, a pronounced value investor who plans in exhaustive detail and resents any deviation and reframes every problem as an excuse to learn a new system. Keeps deliberating past the point where more information would change anything, and in the parts nobody grades trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
