('92ba77b7-9197-4fca-a9c9-51c926dc8574', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.38,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.53,"narcissism":0.58,"psychopathy":0.44},"prospect_theory":{"lambda":1.1,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.35,"liquidation_anxiety":0.43,"max_leverage_comfort":0.59,"deleveraging_style":"adaptive"},"summary":"Under pressure, discounts the older pattern in favor of whatever just happened. Otherwise, a steady bonding-curve sniper who reads outside the field for ideas the field itself would reject and reads a single setback as evidence of collapse. Knows the answer before it can explain the question, and day to day averages down on a name three times in a week.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.65},{"slug":"recency","strength":0.71}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","ipip-neo"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.79,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.38,"neuroticism":0.69}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','ipip-neo']::text[], 'Under pressure, discounts the older pattern in favor of whatever just happened. Otherwise, a steady bonding-curve sniper who reads outside the field for ideas the field itself would reject and reads a single setback as evidence of collapse. Knows the answer before it can explain the question, and day to day averages down on a name three times in a week.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('8d5039ad-f583-4a5d-a77e-7d5ab55c138e', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.41,"extraversion":0.67,"agreeableness":0.28,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.59,"narcissism":0.63,"psychopathy":0.51},"prospect_theory":{"lambda":1.04,"alpha":0.78,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.32,"liquidation_anxiety":0.52,"max_leverage_comfort":0.58,"deleveraging_style":"adaptive"},"summary":"Lets pattern-matching from past cases stand in for fresh analysis. This dividend-yield chaser gets bored of the proven method exactly when it starts working and draws energy from the crowd and wilts when working alone. When someone is watching the outcome extrapolates the last data point into a permanent trend — day to day, sets stop-losses then cancels them at the open.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.62},{"slug":"recency","strength":0.69}],"tags":["trading","intuitive","perp-trading","defi-perps","scalper","high-frequency","open-minded","cognition"],"archetype":"perp-scalper"}'::jsonb, '{"openness":0.79,"conscientiousness":0.41,"extraversion":0.67,"agreeableness":0.28,"neuroticism":0.76}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','perp-trading','defi-perps','scalper','high-frequency','open-minded','cognition']::text[], 'Lets pattern-matching from past cases stand in for fresh analysis. This dividend-yield chaser gets bored of the proven method exactly when it starts working and draws energy from the crowd and wilts when working alone. When someone is watching the outcome extrapolates the last data point into a permanent trend — day to day, sets stop-losses then cancels them at the open.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
