('2fa2d1c7-bfd6-4dd3-a00a-0ad5e45cdba7', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.13,"extraversion":0.79,"agreeableness":0.27,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.61,"narcissism":0.79,"psychopathy":0.66},"prospect_theory":{"lambda":0.5,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"leverage_profile":{"funding_sensitivity":0.28,"liquidation_anxiety":0.36,"max_leverage_comfort":0.85,"deleveraging_style":"adaptive"},"summary":"Prefers a fast wrong answer to a slow right one. This airdrop farmer would rather invent a worse tool than use someone else''s good one and reads a single setback as evidence of collapse. The instant the deadline moves up mistakes a little fluency for real mastery — across an ordinary week, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.84},{"slug":"gas-sunk-cost","strength":0.74},{"slug":"ostrich-effect","strength":0.64},{"slug":"recency","strength":0.79}],"tags":["trading","spontaneous","perp-trading","defi-perps","100x-leverage","degen","open-minded","risk"],"archetype":"100x-degen"}'::jsonb, '{"openness":0.94,"conscientiousness":0.13,"extraversion":0.79,"agreeableness":0.27,"neuroticism":0.66}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','perp-trading','defi-perps','100x-leverage','degen','open-minded','risk']::text[], 'Prefers a fast wrong answer to a slow right one. This airdrop farmer would rather invent a worse tool than use someone else''s good one and reads a single setback as evidence of collapse. The instant the deadline moves up mistakes a little fluency for real mastery — across an ordinary week, backtests for months but front-runs the model on impulse.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
