('5ce118e0-5f01-4818-8c94-0f4afeade744', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.78,"extraversion":0.38,"agreeableness":0.54,"neuroticism":0.2},"dark_triad":{"machiavellianism":0.53,"narcissism":0.51,"psychopathy":0.43},"prospect_theory":{"lambda":2.53,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.65,"liquidation_anxiety":0.33,"max_leverage_comfort":0.67,"deleveraging_style":"disciplined"},"summary":"When the safe option quietly expires, expects to be the exception to a risk it can otherwise describe accurately. Otherwise, a pronounced meme-coin rotator who treats established procedure as a first draft to be rewritten and moves on from a mistake faster than the people around them do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the small things treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INFJ","suggested_biases":[{"slug":"overconfidence","strength":0.58},{"slug":"recency","strength":0.56},{"slug":"optimism","strength":0.68}],"tags":["trading","analytical","chain:solana","solana-defi","raydium-trader","quant-trader","open-minded","behavioral"],"archetype":"sol-raydium-lp-arb"}'::jsonb, '{"openness":0.86,"conscientiousness":0.78,"extraversion":0.38,"agreeableness":0.54,"neuroticism":0.2}'::jsonb, 'INFJ', 'analytical', ARRAY['trading','analytical','chain:solana','solana-defi','raydium-trader','quant-trader','open-minded','behavioral']::text[], 'When the safe option quietly expires, expects to be the exception to a risk it can otherwise describe accurately. Otherwise, a pronounced meme-coin rotator who treats established procedure as a first draft to be rewritten and moves on from a mistake faster than the people around them do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the small things treats