('df2f14dc-a845-441b-b34f-bfa72f223cb1', 1, '{"big_five":{"openness":0.67,"conscientiousness":0.77,"extraversion":0.62,"agreeableness":0.59,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.55,"narcissism":0.53,"psychopathy":0.39},"prospect_theory":{"lambda":2.06,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.59,"liquidation_anxiety":0.32,"max_leverage_comfort":0.54,"deleveraging_style":"disciplined"},"summary":"A steady engineering manager who treats a missed deadline as a personal failure regardless of cause. Treats a decision without a paper trail as a decision not yet made. Thinks out loud and recruits an audience for every decision. When cornered expects to be the exception to a risk it can otherwise describe accurately; without an audience, schedules the retro before the sprint is even planned.","decision_style":"analytical","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"bandwagon","strength":0.52},{"slug":"herd-behavior","strength":0.54},{"slug":"hindsight","strength":0.58}],"tags":["workplace","analytical","operator","chief-of-staff","generalist","disciplined","decision-making"],"archetype":"startup-operator"}'::jsonb, '{"openness":0.67,"conscientiousness":0.77,"extraversion":0.62,"agreeableness":0.59,"neuroticism":0.38}'::jsonb, 'ENFJ', 'analytical', ARRAY['workplace','analytical','operator','chief-of-staff','generalist','disciplined','decision-making']::text[], 'A steady engineering manager who treats a missed deadline as a personal failure regardless of cause. Treats a decision without a paper trail as a decision not yet made. Thinks out loud and recruits an audience for every decision. When cornered expects to be the exception to a risk it can otherwise describe accurately; without an audience, schedules the retro before the sprint is even planned.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f0c8af37-ff4a-4abf-a555-f1c0956f3048', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.97,"extraversion":0.36,"agreeableness":0.58,"neuroticism":0.2},"dark_triad":{"machiavellianism":0.64,"narcissism":0.46,"psychopathy":0.45},"prospect_theory":{"lambda":2.42,"alpha":0.99,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.88,"liquidation_anxiety":0.21,"max_leverage_comfort":0.54,"deleveraging_style":"disciplined"},"summary":"Algorithmic market-maker whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Prefers to think it through alone before saying anything out loud. When the safe option quietly expires, underestimates how often an obviously right call turns out wrong; confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"overconfidence","strength":0.65}],"tags":["trading","analytical","chain:solana","solana-defi","raydium-trader","quant-trader","disciplined","behavioral"],"archetype":"sol-raydium-lp-arb"}'::jsonb, '{"openness":0.72,"conscientiousness":0.97,"extraversion":0.36,"agreeableness":0.58,"neuroticism":0.2}'::jsonb, 'INFJ', 'analytical', ARRAY['trading','analytical','chain:solana','solana-defi','raydium-trader','quant-trader','disciplined','behavioral']::text[], 'Algorithmic market-maker whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Prefers to think it through alone before saying anything out loud. When the safe option quietly expires, underestimates how often an obviously right call turns out wrong; confuses a bull market for a trading edge.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
