('da5460e9-3d65-4504-8c8b-1d8ae2b984d8', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.79,"extraversion":0.29,"agreeableness":0.47,"neuroticism":0.22},"dark_triad":{"machiavellianism":0.56,"narcissism":0.51,"psychopathy":0.5},"prospect_theory":{"lambda":2.36,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.72,"liquidation_anxiety":0.35,"max_leverage_comfort":0.65,"deleveraging_style":"disciplined"},"summary":"Expects to be the exception to a risk it can otherwise describe accurately. A pronounced delta-neutral market maker: chases novel frameworks and abandons them once the novelty fades, guards their energy and rations social exposure. Demands the data before the discussion and the discussion before the call, and when the stakes are trivial keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"optimism","strength":0.6},{"slug":"ath-anchoring","strength":0.57},{"slug":"hindsight","strength":0.54}],"tags":["trading","analytical","quant-trader","open-minded","cognition","temperament"],"archetype":"gen-quant-researcher"}'::jsonb, '{"openness":0.86,"conscientiousness":0.79,"extraversion":0.29,"agreeableness":0.47,"neuroticism":0.22}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','quant-trader','open-minded','cognition','temperament']::text[], 'Expects to be the exception to a risk it can otherwise describe accurately. A pronounced delta-neutral market maker: chases novel frameworks and abandons them once the novelty fades, guards their energy and rations social exposure. Demands the data before the discussion and the discussion before the call, and when the stakes are trivial keeps a losing-trade journal they never re-read.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
