('37201646-133b-47be-b2ca-19edeeeb5e4c', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.75,"extraversion":0.6,"agreeableness":0.37,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.89,"narcissism":0.61,"psychopathy":0.53},"prospect_theory":{"lambda":1.57,"alpha":0.94,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.62,"liquidation_anxiety":0.25,"max_leverage_comfort":0.76,"deleveraging_style":"disciplined"},"summary":"When cornered, assumes the bad statistic applies to other people. Otherwise, a pronounced delta-neutral market maker who reads outside the field for ideas the field itself would reject and front-loads the work and double-checks it twice. Builds a decision matrix for choices most people make on instinct, and in the unglamorous middle of things sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.65},{"slug":"overconfidence","strength":0.6},{"slug":"hindsight","strength":0.64},{"slug":"ath-anchoring","strength":0.51}],"tags":["trading","analytical","crypto-whale","mev-searcher","mempool-extractor","quant-trader","open-minded","cognition"],"archetype":"whale-mev-searcher"}'::jsonb, '{"openness":0.89,"conscientiousness":0.75,"extraversion":0.6,"agreeableness":0.37,"neuroticism":0.3}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','mev-searcher','mempool-extractor','quant-trader','open-minded','cognition']::text[], 'When cornered, assumes the bad statistic applies to other people. Otherwise, a pronounced delta-neutral market maker who reads outside the field for ideas the field itself would reject and front-loads the work and double-checks it twice. Builds a decision matrix for choices most people make on instinct, and in the unglamorous middle of things sizes every position at exactly 2% risk.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('5d0f2c88-6daa-46f8-a38f-cd0d14756547', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.9,"extraversion":0.34,"agreeableness":0.43,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.65,"narcissism":0.48,"psychopathy":0.49},"prospect_theory":{"lambda":2.23,"alpha":0.98,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.84,"liquidation_anxiety":0.23,"max_leverage_comfort":0.72,"deleveraging_style":"disciplined"},"summary":"Prices every token against its all-time high, viewing current levels as an automatic discount. A pronounced macro allocator: collects half-finished manifestos and unconventional methods, weighs words carefully before spending them. Converts every argument into a number it can compare against another number, and when the pressure is off rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.56},{"slug":"ath-anchoring","strength":0.62}],"tags":["trading","analytical","quant-trader","open-minded","behavioral"],"archetype":"gen-quant-researcher"}'::jsonb, '{"openness":0.9,"conscientiousness":0.9,"extraversion":0.34,"agreeableness":0.43,"neuroticism":0.3}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','quant-trader','open-minded','behavioral']::text[], 'Prices every token against its all-time high, viewing current levels as an automatic discount. A pronounced macro allocator: collects half-finished manifestos and unconventional methods, weighs words carefully before spending them. Converts every argument into a number it can compare against another number, and when the pressure is off rotates the whole book into whatever is pumping this hour.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
