('e9da8d93-2047-4a6d-8273-800829780380', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.62,"extraversion":0.82,"agreeableness":0.5,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.48,"narcissism":0.69,"psychopathy":0.35},"prospect_theory":{"lambda":1.23,"alpha":0.92,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":2},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.32,"max_leverage_comfort":0.72,"deleveraging_style":"adaptive"},"summary":"Procurement lead whose defining move is that they recharges by being around people, not away from them. Moves first and rationalizes second, usually convincingly. Treats a missed deadline as a personal failure regardless of cause. The instant the deadline moves up, discounts their own exposure to the risks they warn others about; never makes the first concession on principle.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"optimism","strength":0.66}],"tags":["negotiation","intuitive","founder","fundraising","optimism","outgoing","temperament","behavioral"],"archetype":"founder-fundraiser"}'::jsonb, '{"openness":0.81,"conscientiousness":0.62,"extraversion":0.82,"agreeableness":0.5,"neuroticism":0.39}'::jsonb, 'ENFJ', 'intuitive', ARRAY['negotiation','intuitive','founder','fundraising','optimism','outgoing','temperament','behavioral']::text[], 'Procurement lead whose defining move is that they recharges by being around people, not away from them. Moves first and rationalizes second, usually convincingly. Treats a missed deadline as a personal failure regardless of cause. The instant the deadline moves up, discounts their own exposure to the risks they warn others about; never makes the first concession on principle.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b244bccd-aef5-4204-a030-9b8c524ca1fc', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.66,"extraversion":0.67,"agreeableness":0.84,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.38,"narcissism":0.57,"psychopathy":0.3},"prospect_theory":{"lambda":2.32,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.47,"liquidation_anxiety":0.34,"max_leverage_comfort":0.43,"deleveraging_style":"disciplined"},"summary":"Under pressure, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced peer mentor who reads other people''s discomfort before they voice it and collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and left to their own devices can sense a mood shift from the doorway.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.63}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","ipip-neo"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.66,"extraversion":0.67,"agreeableness":0.84,"neuroticism":0.45}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','ipip-neo']::text[], 'Under pressure, finds it easier to believe something once it stops being a minority view. Otherwise, a pronounced peer mentor who reads other people''s discomfort before they voice it and collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and left to their own devices can sense a mood shift from the doorway.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
