('cac1c787-e13f-4105-98d5-55c887d581f4', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.84,"extraversion":0.25,"agreeableness":0.46,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.6,"narcissism":0.38,"psychopathy":0.48},"prospect_theory":{"lambda":2.56,"alpha":0.95,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.75,"liquidation_anxiety":0.31,"max_leverage_comfort":0.36,"deleveraging_style":"disciplined"},"summary":"The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced dividend-yield chaser who treats a missed deadline as a personal failure regardless of cause and checks its own anxiety like a data point instead of obeying it. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and in the small things averages down on a name three times in a week.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.6},{"slug":"overconfidence","strength":0.65}],"tags":["trading","deliberative","value-investor","long-term","disciplined","ipip-neo"],"archetype":"gen-value-holdout"}'::jsonb, '{"openness":0.46,"conscientiousness":0.84,"extraversion":0.25,"agreeableness":0.46,"neuroticism":0.27}'::jsonb, 'ISTJ', 'deliberative', ARRAY['trading','deliberative','value-investor','long-term','disciplined','ipip-neo']::text[], 'The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced dividend-yield chaser who treats a missed deadline as a personal failure regardless of cause and checks its own anxiety like a data point instead of obeying it. Weighs every angle exhaustively and is uneasy the moment ambiguity remains, and in the small things averages down on a name three times in a week.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
