('eb5d1e63-49bd-4a18-b86b-5a98ed8047b3', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.68,"extraversion":0.39,"agreeableness":0.38,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.61,"narcissism":0.56,"psychopathy":0.44},"prospect_theory":{"lambda":1.82,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.57,"liquidation_anxiety":0.32,"max_leverage_comfort":0.69,"deleveraging_style":"disciplined"},"summary":"Discounts the older pattern in favor of whatever just happened. A steady bonding-curve sniper: chases novel frameworks and abandons them once the novelty fades, treats warmth as leverage and cooperation as weakness. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on an ordinary week talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.52},{"slug":"recency","strength":0.61}],"tags":["trading","analytical","volatility-arb","contrarian","open-minded","temperament","ipip-neo"],"archetype":"gen-vol-arb"}'::jsonb, '{"openness":0.81,"conscientiousness":0.68,"extraversion":0.39,"agreeableness":0.38,"neuroticism":0.44}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','volatility-arb','contrarian','open-minded','temperament','ipip-neo']::text[], 'Discounts the older pattern in favor of whatever just happened. A steady bonding-curve sniper: chases novel frameworks and abandons them once the novelty fades, treats warmth as leverage and cooperation as weakness. Ranks the options twice, once on paper and once out loud, and trusts the paper, and on an ordinary week talks in win rate and never mentions size.', 0.94, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
