('8b08be3e-8137-4cba-853b-a565c9ca536a', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.95,"extraversion":0.72,"agreeableness":0.52,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.61,"narcissism":0.58,"psychopathy":0.42},"prospect_theory":{"lambda":2.24,"alpha":0.99,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.74,"liquidation_anxiety":0.28,"max_leverage_comfort":0.38,"deleveraging_style":"disciplined"},"summary":"Compliance officer whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Stays flat when the numbers go red. When someone is watching the outcome, discounts their own exposure to the risks they warn others about; ships on Friday at 4:58pm out of habit.","decision_style":"analytical","mbti_label":"ESFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"anchoring","strength":0.61},{"slug":"optimism","strength":0.65},{"slug":"hindsight","strength":0.64}],"tags":["workplace","analytical","crisis-response","incident-commander","decisive","disciplined","ipip-neo","temperament"],"archetype":"crisis-incident-commander"}'::jsonb, '{"openness":0.49,"conscientiousness":0.95,"extraversion":0.72,"agreeableness":0.52,"neuroticism":0.25}'::jsonb, 'ESFJ', 'analytical', ARRAY['workplace','analytical','crisis-response','incident-commander','decisive','disciplined','ipip-neo','temperament']::text[], 'Compliance officer whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Stays flat when the numbers go red. When someone is watching the outcome, discounts their own exposure to the risks they warn others about; ships on Friday at 4:58pm out of habit.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
