('e65c3c10-4b82-460c-b0ee-5d528e029516', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.83,"extraversion":0.29,"agreeableness":0.47,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.6,"narcissism":0.44,"psychopathy":0.46},"prospect_theory":{"lambda":2.34,"alpha":0.95,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.34,"max_leverage_comfort":0.66,"deleveraging_style":"disciplined"},"summary":"A steady volatility arbitrageur who reads outside the field for ideas the field itself would reject. Wants the base rate before the anecdote. Builds in buffer time and then fills the buffer with more work. The instant the deadline moves up assumes the bad statistic applies to other people; when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.56},{"slug":"optimism","strength":0.59},{"slug":"recency","strength":0.53}],"tags":["trading","analytical","quant-trader","open-minded","ipip-neo"],"archetype":"gen-quant-researcher"}'::jsonb, '{"openness":0.83,"conscientiousness":0.83,"extraversion":0.29,"agreeableness":0.47,"neuroticism":0.27}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','quant-trader','open-minded','ipip-neo']::text[], 'A steady volatility arbitrageur who reads outside the field for ideas the field itself would reject. Wants the base rate before the anecdote. Builds in buffer time and then fills the buffer with more work. The instant the deadline moves up assumes the bad statistic applies to other people; when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
