('eda2dbe8-5a8d-4f49-a404-de8fbff588d4', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.53,"extraversion":0.84,"agreeableness":0.52,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.37},"prospect_theory":{"lambda":1.46,"alpha":0.92,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":2},"leverage_profile":{"funding_sensitivity":0.33,"liquidation_anxiety":0.33,"max_leverage_comfort":0.82,"deleveraging_style":"adaptive"},"summary":"Salary negotiator, pronounced in style: reads outside the field for ideas the field itself would reject; recharges by being around people, not away from them. Treats overthinking as its own kind of error. When someone is watching the outcome takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"herd-behavior","strength":0.63}],"tags":["negotiation","intuitive","founder","fundraising","optimism","open-minded","risk"],"archetype":"founder-fundraiser"}'::jsonb, '{"openness":0.91,"conscientiousness":0.53,"extraversion":0.84,"agreeableness":0.52,"neuroticism":0.35}'::jsonb, 'ENFJ', 'intuitive', ARRAY['negotiation','intuitive','founder','fundraising','optimism','open-minded','risk']::text[], 'Salary negotiator, pronounced in style: reads outside the field for ideas the field itself would reject; recharges by being around people, not away from them. Treats overthinking as its own kind of error. When someone is watching the outcome takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('a96901e4-37ec-4288-a0dc-ca1442203668', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.41,"narcissism":0.6,"psychopathy":0.32},"prospect_theory":{"lambda":2.26,"alpha":0.93,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.37,"liquidation_anxiety":0.4,"max_leverage_comfort":0.43,"deleveraging_style":"adaptive"},"summary":"In a pinch, abandons a private read the instant the crowd leans the other way. Otherwise, a steady neighborhood connector who would rather lose a point than win an argument badly and fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and in the routine of it texts an apology before confirming anyone is upset.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"herd-behavior","strength":0.78},{"slug":"optimism","strength":0.66},{"slug":"bandwagon","strength":0.7}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","behavioral"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.58,"conscientiousness":0.56,"extraversion":0.74,"agreeableness":0.82,"neuroticism":0.38}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','behavioral']::text[], 'In a pinch, abandons a private read the instant the crowd leans the other way. Otherwise, a steady neighborhood connector who would rather lose a point than win an argument badly and fills silence reflexively, even when nobody asked it to. Circles back to ask what someone else would do even after deciding, and in the routine of it texts an apology before confirming anyone is upset.', 0.92, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
