('ccbcbd40-62e8-44bd-b1ce-6e2ee53a9056', 1, '{"big_five":{"openness":0.35,"conscientiousness":0.91,"extraversion":0.33,"agreeableness":0.56,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.61,"narcissism":0.42,"psychopathy":0.3},"prospect_theory":{"lambda":3.02,"alpha":0.97,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.86,"liquidation_anxiety":0.33,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"HR mediator whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Wants the version that already worked last time, not a better one. When cornered, refuses to exit positions until price returns to the previous cycle peak; ships on Friday at 4:58pm out of habit.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"anchoring","strength":0.61},{"slug":"hindsight","strength":0.6},{"slug":"ath-anchoring","strength":0.72}],"tags":["workplace","deliberative","income-planner","conservative","disciplined","behavioral"],"archetype":"gen-dividend-planner"}'::jsonb, '{"openness":0.35,"conscientiousness":0.91,"extraversion":0.33,"agreeableness":0.56,"neuroticism":0.4}'::jsonb, 'ISFJ', 'deliberative', ARRAY['workplace','deliberative','income-planner','conservative','disciplined','behavioral']::text[], 'HR mediator whose defining move is that they treats a missed deadline as a personal failure regardless of cause. Slow-walks the decision through every contingency before moving. Wants the version that already worked last time, not a better one. When cornered, refuses to exit positions until price returns to the previous cycle peak; ships on Friday at 4:58pm out of habit.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('8d37b631-dbe6-4e82-9e9a-8b235facae97', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.64,"extraversion":0.64,"agreeableness":0.92,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.35,"narcissism":0.49,"psychopathy":0.32},"prospect_theory":{"lambda":2.31,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"leverage_profile":{"funding_sensitivity":0.51,"liquidation_anxiety":0.35,"max_leverage_comfort":0.48,"deleveraging_style":"adaptive"},"summary":"Community manager whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires, gains confidence in a position in proportion to how many others hold it; mediates conflicts they secretly started.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.61},{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.72}],"tags":["social","dependent","community","mediator","high-agreeableness","accommodating","temperament"],"archetype":"community-peacemaker"}'::jsonb, '{"openness":0.63,"conscientiousness":0.64,"extraversion":0.64,"agreeableness":0.92,"neuroticism":0.48}'::jsonb, 'ENFJ', 'dependent', ARRAY['social','dependent','community','mediator','high-agreeableness','accommodating','temperament']::text[], 'Community manager whose defining move is that they defaults to trust and gives the benefit of the doubt too freely. Waits for a permission that never quite arrives. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires, gains confidence in a position in proportion to how many others hold it; mediates conflicts they secretly started.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('565406d9-ce4e-48f6-a35a-6bd5803af35c', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.7,"extraversion":0.48,"agreeableness":0.47,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.5,"narcissism":0.47,"psychopathy":0.43},"prospect_theory":{"lambda":1.93,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.6,"liquidation_anxiety":0.33,"max_leverage_comfort":0.55,"deleveraging_style":"disciplined"},"summary":"When there is no clean exit, is more certain than the hit rate justifies. Otherwise, a steady MEV searcher who cannot relax until the checklist is visibly complete and reframes every problem as an excuse to learn a new system. Reads a room or a market the way others read a paragraph, and across an ordinary week sizes every position at exactly 2% risk.","decision_style":"intuitive","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.51},{"slug":"overconfidence","strength":0.55}],"tags":["trading","intuitive","macro-allocator","discretionary","disciplined","decision-making"],"archetype":"gen-macro-allocator"}'::jsonb, '{"openness":0.63,"conscientiousness":0.7,"extraversion":0.48,"agreeableness":0.47,"neuroticism":0.36}'::jsonb, 'INTJ', 'intuitive', ARRAY['trading','intuitive','macro-allocator','discretionary','disciplined','decision-making']::text[], 'When there is no clean exit, is more certain than the hit rate justifies. Otherwise, a steady MEV searcher who cannot relax until the checklist is visibly complete and reframes every problem as an excuse to learn a new system. Reads a room or a market the way others read a paragraph, and across an ordinary week sizes every position at exactly 2% risk.', 0.89, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
