('919432cc-e644-4b58-8f68-960b7cb4bddf', 1, '{"big_five":{"openness":0.43,"conscientiousness":0.94,"extraversion":0.3,"agreeableness":0.45,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.69,"narcissism":0.41,"psychopathy":0.45},"prospect_theory":{"lambda":3.18,"alpha":0.98,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.84,"liquidation_anxiety":0.39,"max_leverage_comfort":0.33,"deleveraging_style":"disciplined"},"summary":"Product lead whose defining move is that they plans in exhaustive detail and resents any deviation. Slow-walks the decision through every contingency before moving. Treats a crisis as an interesting problem rather than a threat. Once things get tense, rewrites its own uncertainty out of the story after the fact; CCs their manager as a control mechanism.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"overconfidence","strength":0.61},{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.69},{"slug":"optimism","strength":0.53}],"tags":["workplace","deliberative","compliance","auditor","risk-averse","disciplined","ipip-neo","behavioral"],"archetype":"compliance-auditor"}'::jsonb, '{"openness":0.43,"conscientiousness":0.94,"extraversion":0.3,"agreeableness":0.45,"neuroticism":0.34}'::jsonb, 'ISTJ', 'deliberative', ARRAY['workplace','deliberative','compliance','auditor','risk-averse','disciplined','ipip-neo','behavioral']::text[], 'Product lead whose defining move is that they plans in exhaustive detail and resents any deviation. Slow-walks the decision through every contingency before moving. Treats a crisis as an interesting problem rather than a threat. Once things get tense, rewrites its own uncertainty out of the story after the fact; CCs their manager as a control mechanism.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('6dfcd62b-b6c1-44d8-b8e4-4cf306c79742', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.83,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.55,"narcissism":0.54,"psychopathy":0.36},"prospect_theory":{"lambda":2.07,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.64,"liquidation_anxiety":0.24,"max_leverage_comfort":0.53,"deleveraging_style":"disciplined"},"summary":"Middle manager whose defining move is that they cannot relax until the checklist is visibly complete. Builds a decision matrix for choices most people make on instinct. Treats a crisis as an interesting problem rather than a threat. When someone is watching the outcome, discounts their own exposure to the risks they warn others about; over-indexes on the last piece of negative feedback received.","decision_style":"analytical","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.66},{"slug":"ath-anchoring","strength":0.54}],"tags":["workplace","analytical","operator","chief-of-staff","generalist","disciplined","behavioral"],"archetype":"startup-operator"}'::jsonb, '{"openness":0.73,"conscientiousness":0.83,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.32}'::jsonb, 'ENFJ', 'analytical', ARRAY['workplace','analytical','operator','chief-of-staff','generalist','disciplined','behavioral']::text[], 'Middle manager whose defining move is that they cannot relax until the checklist is visibly complete. Builds a decision matrix for choices most people make on instinct. Treats a crisis as an interesting problem rather than a threat. When someone is watching the outcome, discounts their own exposure to the risks they warn others about; over-indexes on the last piece of negative feedback received.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
