('2a4444fb-57a0-45f6-a466-7216fb43603e', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.88,"extraversion":0.37,"agreeableness":0.27,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.77,"narcissism":0.59,"psychopathy":0.49},"prospect_theory":{"lambda":2.01,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.8,"liquidation_anxiety":0.2,"max_leverage_comfort":0.69,"deleveraging_style":"disciplined"},"summary":"Measures every later offer against the opening one, not against fair value. A pronounced algorithmic market-maker: treats a missed deadline as a personal failure regardless of cause, would rather be respected than liked, and says so. Ranks the options twice, once on paper and once out loud, and trusts the paper, and when no one is watching rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.58},{"slug":"anchoring","strength":0.6},{"slug":"recency","strength":0.52},{"slug":"ath-anchoring","strength":0.58}],"tags":["trading","analytical","volatility-arb","contrarian","disciplined","risk"],"archetype":"gen-vol-arb"}'::jsonb, '{"openness":0.8,"conscientiousness":0.88,"extraversion":0.37,"agreeableness":0.27,"neuroticism":0.42}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','volatility-arb','contrarian','disciplined','risk']::text[], 'Measures every later offer against the opening one, not against fair value. A pronounced algorithmic market-maker: treats a missed deadline as a personal failure regardless of cause, would rather be respected than liked, and says so. Ranks the options twice, once on paper and once out loud, and trusts the paper, and when no one is watching rotates the whole book into whatever is pumping this hour.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
