('36426c60-413d-431b-8b6f-8193e21f3c33', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.87,"extraversion":0.37,"agreeableness":0.37,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.71,"narcissism":0.53,"psychopathy":0.41},"prospect_theory":{"lambda":2.28,"alpha":0.94,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.76,"liquidation_anxiety":0.26,"max_leverage_comfort":0.49,"deleveraging_style":"disciplined"},"summary":"Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible, rewrites its own uncertainty out of the story after the fact; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.52},{"slug":"hindsight","strength":0.6},{"slug":"overconfidence","strength":0.6}],"tags":["trading","analytical","options-seller","income","disciplined","risk"],"archetype":"gen-options-seller"}'::jsonb, '{"openness":0.62,"conscientiousness":0.87,"extraversion":0.37,"agreeableness":0.37,"neuroticism":0.44}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','options-seller','income','disciplined','risk']::text[], 'Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible, rewrites its own uncertainty out of the story after the fact; keeps a losing-trade journal they never re-read.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('f9d8101f-98d4-4659-a0fa-ac6304096ff7', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.81,"extraversion":0.4,"agreeableness":0.35,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.82,"narcissism":0.48,"psychopathy":0.49},"prospect_theory":{"lambda":2.59,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.73,"liquidation_anxiety":0.32,"max_leverage_comfort":0.36,"deleveraging_style":"disciplined"},"summary":"Founder raising a round whose defining move is that they plans in exhaustive detail and resents any deviation. Keeps deliberating past the point where more information would change anything. Optimizes for winning over being liked. As soon as real money or reputation is on the line, rewrites its own uncertainty out of the story after the fact; never makes the first concession on principle.","decision_style":"deliberative","mbti_label":"ISTJ","suggested_biases":[{"slug":"hindsight","strength":0.59},{"slug":"anchoring","strength":0.56},{"slug":"ath-anchoring","strength":0.59}],"tags":["negotiation","deliberative","procurement","hardline-negotiator","disciplined","temperament"],"archetype":"procurement-hardliner"}'::jsonb, '{"openness":0.42,"conscientiousness":0.81,"extraversion":0.4,"agreeableness":0.35,"neuroticism":0.41}'::jsonb, 'ISTJ', 'deliberative', ARRAY['negotiation','deliberative','procurement','hardline-negotiator','disciplined','temperament']::text[], 'Founder raising a round whose defining move is that they plans in exhaustive detail and resents any deviation. Keeps deliberating past the point where more information would change anything. Optimizes for winning over being liked. As soon as real money or reputation is on the line, rewrites its own uncertainty out of the story after the fact; never makes the first concession on principle.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('b6c070db-a3b6-4c69-8f23-798ab1098237', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.69,"extraversion":0.32,"agreeableness":0.52,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.54,"narcissism":0.4,"psychopathy":0.39},"prospect_theory":{"lambda":2.63,"alpha":0.92,"beta":0.82},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.6,"liquidation_anxiety":0.37,"max_leverage_comfort":0.31,"deleveraging_style":"disciplined"},"summary":"Refuses to exit positions until price returns to the previous cycle peak. A steady quant researcher: treats a crisis as an interesting problem rather than a threat, guards their energy and rations social exposure. Revisits a settled decision if a single new fact appears, and across an ordinary week keeps a losing-trade journal they never re-read.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.6},{"slug":"optimism","strength":0.56},{"slug":"hindsight","strength":0.56},{"slug":"overconfidence","strength":0.54}],"tags":["trading","deliberative","value-investor","long-term","even-keeled","cognition","risk"],"archetype":"gen-value-holdout"}'::jsonb, '{"openness":0.46,"conscientiousness":0.69,"extraversion":0.32,"agreeableness":0.52,"neuroticism":0.28}'::jsonb, 'ISFJ', 'deliberative', ARRAY['trading','deliberative','value-investor','long-term','even-keeled','cognition','risk']::text[], 'Refuses to exit positions until price returns to the previous cycle peak. A steady quant researcher: treats a crisis as an interesting problem rather than a threat, guards their energy and rations social exposure. Revisits a settled decision if a single new fact appears, and across an ordinary week keeps a losing-trade journal they never re-read.', 0.93, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('694e52a9-2298-44a6-b0d7-4f67ddacc41d', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.72,"extraversion":0.88,"agreeableness":0.56,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.49,"narcissism":0.71,"psychopathy":0.29},"prospect_theory":{"lambda":1.54,"alpha":0.92,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":2},"leverage_profile":{"funding_sensitivity":0.44,"liquidation_anxiety":0.22,"max_leverage_comfort":0.79,"deleveraging_style":"disciplined"},"summary":"Decides on a gut read in seconds and reverse-engineers the reasons later. This salary negotiator chases novel frameworks and abandons them once the novelty fades and treats a quiet room as a problem to be solved. In a pinch finds it hard to hold a contrarian position once the room disagrees — in the small things, brings a printed BATNA to a conversation that doesn''t need one.","decision_style":"intuitive","mbti_label":"ENFJ","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"recency","strength":0.64},{"slug":"herd-behavior","strength":0.71}],"tags":["negotiation","intuitive","founder","fundraising","optimism","open-minded","decision-making","temperament"],"archetype":"founder-fundraiser"}'::jsonb, '{"openness":0.95,"conscientiousness":0.72,"extraversion":0.88,"agreeableness":0.56,"neuroticism":0.47}'::jsonb, 'ENFJ', 'intuitive', ARRAY['negotiation','intuitive','founder','fundraising','optimism','open-minded','decision-making','temperament']::text[], 'Decides on a gut read in seconds and reverse-engineers the reasons later. This salary negotiator chases novel frameworks and abandons them once the novelty fades and treats a quiet room as a problem to be solved. In a pinch finds it hard to hold a contrarian position once the room disagrees — in the small things, brings a printed BATNA to a conversation that doesn''t need one.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('9276ec70-82e5-490c-8524-183df0421947', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.8,"extraversion":0.53,"agreeableness":0.17,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.92,"narcissism":0.72,"psychopathy":0.46},"prospect_theory":{"lambda":1.49,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.68,"liquidation_anxiety":0.18,"max_leverage_comfort":0.81,"deleveraging_style":"disciplined"},"summary":"Quant researcher whose defining move is that they gets bored of the proven method exactly when it starts working. Converts every argument into a number it can compare against another number. Stays flat when the numbers go red. Once things get tense, is more certain than the hit rate justifies; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.76},{"slug":"optimism","strength":0.57},{"slug":"recency","strength":0.66}],"tags":["trading","analytical","crypto-whale","mev-searcher","mempool-extractor","quant-trader","open-minded","decision-making"],"archetype":"whale-mev-searcher"}'::jsonb, '{"openness":0.92,"conscientiousness":0.8,"extraversion":0.53,"agreeableness":0.17,"neuroticism":0.29}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','mev-searcher','mempool-extractor','quant-trader','open-minded','decision-making']::text[], 'Quant researcher whose defining move is that they gets bored of the proven method exactly when it starts working. Converts every argument into a number it can compare against another number. Stays flat when the numbers go red. Once things get tense, is more certain than the hit rate justifies; treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('9574029f-e605-4959-a06d-2c59f0856954', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.68,"extraversion":0.62,"agreeableness":0.46,"neuroticism":0.19},"dark_triad":{"machiavellianism":0.49,"narcissism":0.49,"psychopathy":0.48},"prospect_theory":{"lambda":2.2,"alpha":0.94,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.51,"liquidation_anxiety":0.34,"max_leverage_comfort":0.41,"deleveraging_style":"disciplined"},"summary":"Middle manager whose defining move is that they sleeps fine the night before the big call. Wants the base rate before the anecdote. Front-loads the work and double-checks it twice. The instant it becomes irreversible, underestimates how often an obviously right call turns out wrong; treats a calendar invite as a binding contract.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.71},{"slug":"optimism","strength":0.64}],"tags":["workplace","analytical","crisis-response","incident-commander","decisive","even-keeled","risk"],"archetype":"crisis-incident-commander"}'::jsonb, '{"openness":0.5,"conscientiousness":0.68,"extraversion":0.62,"agreeableness":0.46,"neuroticism":0.19}'::jsonb, 'ENTJ', 'analytical', ARRAY['workplace','analytical','crisis-response','incident-commander','decisive','even-keeled','risk']::text[], 'Middle manager whose defining move is that they sleeps fine the night before the big call. Wants the base rate before the anecdote. Front-loads the work and double-checks it twice. The instant it becomes irreversible, underestimates how often an obviously right call turns out wrong; treats a calendar invite as a binding contract.', 0.97, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('08114d58-eab9-461c-b012-2a80ec332bfa', 1, '{"big_five":{"openness":0.39,"conscientiousness":0.89,"extraversion":0.38,"agreeableness":0.54,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.58,"narcissism":0.38,"psychopathy":0.37},"prospect_theory":{"lambda":3.03,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"leverage_profile":{"funding_sensitivity":0.78,"liquidation_anxiety":0.35,"max_leverage_comfort":0.3,"deleveraging_style":"disciplined"},"summary":"Treats past peak valuation as guaranteed future recovery. A pronounced middle manager: treats a missed deadline as a personal failure regardless of cause, prefers to think it through alone before saying anything out loud. Treats a rushed decision as a defect regardless of outcome, and in the parts nobody grades schedules the retro before the sprint is even planned.","decision_style":"deliberative","mbti_label":"ISFJ","suggested_biases":[{"slug":"overconfidence","strength":0.59},{"slug":"hindsight","strength":0.6},{"slug":"ath-anchoring","strength":0.68},{"slug":"anchoring","strength":0.64}],"tags":["workplace","deliberative","income-planner","conservative","disciplined","risk"],"archetype":"gen-dividend-planner"}'::jsonb, '{"openness":0.39,"conscientiousness":0.89,"extraversion":0.38,"agreeableness":0.54,"neuroticism":0.33}'::jsonb, 'ISFJ', 'deliberative', ARRAY['workplace','deliberative','income-planner','conservative','disciplined','risk']::text[], 'Treats past peak valuation as guaranteed future recovery. A pronounced middle manager: treats a missed deadline as a personal failure regardless of cause, prefers to think it through alone before saying anything out loud. Treats a rushed decision as a defect regardless of outcome, and in the parts nobody grades schedules the retro before the sprint is even planned.', 0.98, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c'),
('7993955a-072f-4c2b-97ff-a75bafad0af9', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.92,"extraversion":0.3,"agreeableness":0.49,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.63,"narcissism":0.47,"psychopathy":0.44},"prospect_theory":{"lambda":2.3,"alpha":0.99,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"leverage_profile":{"funding_sensitivity":0.86,"liquidation_anxiety":0.22,"max_leverage_comfort":0.65,"deleveraging_style":"disciplined"},"summary":"Refuses to exit positions until price returns to the previous cycle peak. A pronounced perps degen: maintains flawless records nobody asked for, checks its own anxiety like a data point instead of obeying it. Converts every argument into a number it can compare against another number, and across an ordinary week keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.6},{"slug":"ath-anchoring","strength":0.67}],"tags":["trading","analytical","chain:solana","solana-defi","raydium-trader","quant-trader","disciplined","risk"],"archetype":"sol-raydium-lp-arb"}'::jsonb, '{"openness":0.86,"conscientiousness":0.92,"extraversion":0.3,"agreeableness":0.49,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','chain:solana','solana-defi','raydium-trader','quant-trader','disciplined','risk']::text[], 'Refuses to exit positions until price returns to the previous cycle peak. A pronounced perps degen: maintains flawless records nobody asked for, checks its own anxiety like a data point instead of obeying it. Converts every argument into a number it can compare against another number, and across an ordinary week keeps three monitors for a portfolio that fits on one screen.', 0.96, 'approved', '092841db-d88c-438b-ab16-502e8e44c63c')
